// ============================================
// ACCESSIBLE TABS
// ============================================

interface Tab {
    id: string;
    label: string;
    content: React.ReactNode;
}

interface AccessibleTabsProps {
    tabs: Tab[];
    defaultTab?: string;
    onChange?: (tabId: string) => void;
    className?: string;
}

export const AccessibleTabs: React.FC<AccessibleTabsProps> = ({
    tabs,
    defaultTab,
    onChange,
    className = ''
}) => {
    const [activeTab, setActiveTab] = useState(defaultTab || tabs[0]?.id);
    const tabsRef = useRef<(HTMLButtonElement | null)[]>([]);

    const { onKeyDown } = useKeyboardNavigation({
        onArrowRight: () => {
            const currentIndex = tabs.findIndex(t => t.id === activeTab);
            const nextIndex = (currentIndex + 1) % tabs.length;
            setActiveTab(tabs[nextIndex].id);
            tabsRef.current[nextIndex]?.focus();
        },
        onArrowLeft: () => {
            const currentIndex = tabs.findIndex(t => t.id === activeTab);
            const prevIndex = currentIndex === 0 ? tabs.length - 1 : currentIndex - 1;
            setActiveTab(tabs[prevIndex].id);
            tabsRef.current[prevIndex]?.focus();
        },
        onHome: () => {
            setActiveTab(tabs[0].id);
            tabsRef.current[0]?.focus();
        },
        onEnd: () => {
            setActiveTab(tabs[tabs.length - 1].id);
            tabsRef.current[tabs.length - 1]?.focus();
        },
        preventDefault: true
    });

    useEffect(() => {
        onChange?.(activeTab);
    }, [activeTab, onChange]);

    return (
        <div className={className}>
            {/* Tab list */}
            <div
                role="tablist"
                aria-label="Tab"
                className="flex border-b border-slate-200 dark:border-slate-700"
                onKeyDown={onKeyDown as any}
            >
                {tabs.map((tab, index) => (
                    <button
                        key={tab.id}
                        ref={el => tabsRef.current[index] = el}
                        role="tab"
                        id={`tab-${tab.id}`}
                        aria-selected={activeTab === tab.id}
                        aria-controls={`tabpanel-${tab.id}`}
                        tabIndex={activeTab === tab.id ? 0 : -1}
                        onClick={() => setActiveTab(tab.id)}
                        className={`px-4 py-3 text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-inset focus:ring-indigo-500 ${activeTab === tab.id
                            ? 'text-indigo-600 dark:text-indigo-400 border-b-2 border-indigo-600 dark:border-indigo-400'
                            : 'text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white'
                            }`}
                    >
                        {tab.label}
                    </button>
                ))}
            </div>

            {/* Tab panels */}
            {tabs.map(tab => (
                <div
                    key={tab.id}
                    role="tabpanel"
                    id={`tabpanel-${tab.id}`}
                    aria-labelledby={`tab-${tab.id}`}
                    hidden={activeTab !== tab.id}
                    tabIndex={0}
                    className="py-4 focus:outline-none"
                >
                    {tab.content}
                </div>
            ))}
        </div>
    );
};

