import React, { Component, ErrorInfo, ReactNode } from 'react';
import { logger } from '../services/logger';
import { errorReporter } from '../services/errorHandling';
import { AlertTriangleIcon, RefreshCwIcon, HomeIcon } from './Icons';
import { Button } from './ui/Button';

interface ErrorContext {
  userId?: string;
  component?: string;
  action?: string;
  metadata?: Record<string, any>;
  timestamp: string;
  url: string;
  userAgent: string;
}

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  context?: string;
  onError?: (error: Error, errorInfo: ErrorInfo, context: ErrorContext) => void;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  errorContext: ErrorContext | null;
}

/**
 * Enhanced Error Boundary Component
 * Catches JavaScript errors anywhere in child component tree and displays fallback UI
 * Now with structured logging and error tracking
 */
class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      errorContext: null
    };
  }

  static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Create comprehensive error context
    const errorContext: ErrorContext = {
      userId: this.getUserId(),
      component: this.props.context || 'ErrorBoundary',
      action: 'component_error',
      metadata: {
        componentStack: errorInfo.componentStack,
        props: this.sanitizeProps()
      },
      timestamp: new Date().toISOString(),
      url: window.location.href,
      userAgent: navigator.userAgent
    };

    // Log the error with structured logging
    logger.error(
      `Component Error: ${error.message}`,
      error,
      errorContext.metadata,
      errorContext.component
    );

    // Report to error tracking service
    errorReporter.report(error, errorContext.metadata);

    this.setState({
      errorInfo,
      errorContext
    });

    // Call custom error handler if provided
    if (this.props.onError) {
      this.props.onError(error, errorInfo, errorContext);
    }
  }

  private getUserId(): string | undefined {
    // Try to get user ID from various sources
    try {
      const user = JSON.parse(localStorage.getItem('user') || '{}');
      return user.id;
    } catch {
      return undefined;
    }
  }

  private sanitizeProps(): Record<string, any> {
    // Sanitize props to avoid circular references and sensitive data
    try {
      return JSON.parse(JSON.stringify(this.props, (key, value) => {
        if (key === 'children' || typeof value === 'function') {
          return '[Filtered]';
        }
        return value;
      }));
    } catch {
      return { error: 'Failed to serialize props' };
    }
  }

  handleReload = () => {
    logger.info('User clicked reload after error', 'ErrorBoundary');
    window.location.reload();
  };

  handleGoHome = () => {
    logger.info('User clicked go home after error', 'ErrorBoundary');
    window.location.href = '/dashboard';
  };

  handleRetry = () => {
    logger.info('User clicked retry after error', this.props.context || 'ErrorBoundary');
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      errorContext: null
    });
  };

  render() {
    if (this.state.hasError) {
      // Custom fallback if provided
      if (this.props.fallback) {
        return this.props.fallback;
      }

      // Default error UI
      return (
        <div className="flex flex-col items-center justify-center min-h-[500px] bg-gray-100 dark:bg-gray-950 text-center p-8">
          <div className="max-w-md w-full bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 p-8">
            <div className="flex justify-center mb-6">
              <div className="w-20 h-20 bg-gradient-to-br from-red-100 to-orange-200 dark:from-red-900/50 dark:to-orange-900/70 rounded-full flex items-center justify-center">
                <AlertTriangleIcon className="w-10 h-10 text-red-600 dark:text-red-400" />
              </div>
            </div>

            <h1 className="text-2xl font-bold text-gray-800 dark:text-gray-200 mb-2">
              Terjadi Kesalahan
            </h1>

            <p className="text-gray-600 dark:text-gray-400 mb-6">
              Maaf, terjadi kesalahan yang tidak terduga. Tim kami telah diberitahu tentang masalah ini.
            </p>

            {import.meta.env.DEV && this.state.error && (
              <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 rounded-xl text-left">
                <p className="text-sm font-mono text-red-700 dark:text-red-300 break-all">
                  {this.state.error.message}
                </p>
                {this.state.errorInfo && (
                  <details className="mt-2">
                    <summary className="text-xs text-red-600 dark:text-red-400 cursor-pointer">
                      Stack trace
                    </summary>
                    <pre className="mt-2 text-xs text-red-600 dark:text-red-400 overflow-auto max-h-40">
                      {this.state.errorInfo.componentStack}
                    </pre>
                  </details>
                )}
              </div>
            )}

            <div className="flex gap-3">
              <Button
                onClick={this.handleRetry}
                className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white"
              >
                <RefreshCwIcon className="w-4 h-4 mr-2" />
                Coba Lagi
              </Button>
              <Button
                onClick={this.handleGoHome}
                variant="outline"
                className="flex-1"
              >
                <HomeIcon className="w-4 h-4 mr-2" />
                Beranda
              </Button>
            </div>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

/**
 * HOC to wrap components with error boundary
 */
export function withErrorBoundary<P extends object>(
  WrappedComponent: React.ComponentType<P>,
  context?: string
) {
  return function WithErrorBoundary(props: P) {
    return (
      <ErrorBoundary context={context}>
        <WrappedComponent {...props} />
      </ErrorBoundary>
    );
  };
}

/**
 * Async error boundary wrapper for Suspense fallbacks
 */
export const AsyncErrorBoundary: React.FC<{
  children: ReactNode;
  context?: string;
}> = ({ children, context }) => {
  return (
    <ErrorBoundary context={context}>
      <React.Suspense
        fallback={
          <div className="flex items-center justify-center min-h-[200px]">
            <div className="animate-spin w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full"></div>
          </div>
        }
      >
        {children}
      </React.Suspense>
    </ErrorBoundary>
  );
};

import React, { useState, useEffect, useCallback, createContext, useContext, useRef } from 'react';
import { X, Check, AlertCircle, Info, AlertTriangle, Undo2, ChevronRight, Loader2 } from 'lucide-react';

/**
 * Micro-interactions & Feedback System
 * Features: Haptic feedback, toast notifications, progress indicators, undo functionality
 */

// ============================================
// HAPTIC FEEDBACK
// ============================================

type HapticType = 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' | 'selection';

interface HapticPatterns {
    [key: string]: number[];
}

const hapticPatterns: HapticPatterns = {
    light: [10],
    medium: [25],
    heavy: [50],
    success: [10, 50, 10],
    warning: [30, 30, 30],
    error: [50, 100, 50],
    selection: [5]
};

export function useHapticFeedback() {
    const isSupported = typeof navigator !== 'undefined' && 'vibrate' in navigator;

    const vibrate = useCallback((type: HapticType = 'light') => {
        if (!isSupported) return false;

        const pattern = hapticPatterns[type] || hapticPatterns.light;
        return navigator.vibrate(pattern);
    }, [isSupported]);

    const vibratePattern = useCallback((pattern: number[]) => {
        if (!isSupported) return false;
        return navigator.vibrate(pattern);
    }, [isSupported]);

    const stop = useCallback(() => {
        if (!isSupported) return;
        navigator.vibrate(0);
    }, [isSupported]);

    return {
        isSupported,
        vibrate,
        vibratePattern,
        stop,
        // Shorthand methods
        light: () => vibrate('light'),
        medium: () => vibrate('medium'),
        heavy: () => vibrate('heavy'),
        success: () => vibrate('success'),
        warning: () => vibrate('warning'),
        error: () => vibrate('error'),
        selection: () => vibrate('selection')
    };
}

// ============================================
// TOAST NOTIFICATIONS
// ============================================

export type ToastType = 'success' | 'error' | 'warning' | 'info' | 'loading';

export interface ToastAction {
    label: string;
    onClick: () => void;
}

export interface Toast {
    id: string;
    type: ToastType;
    title: string;
    message?: string;
    duration?: number; // ms, 0 = never auto-dismiss
    action?: ToastAction;
    undoAction?: () => void;
    dismissible?: boolean;
    progress?: number; // 0-100 for loading type
}

interface ToastContextValue {
    toasts: Toast[];
    addToast: (toast: Omit<Toast, 'id'>) => string;
    removeToast: (id: string) => void;
    updateToast: (id: string, updates: Partial<Toast>) => void;
    clearAll: () => void;
    // Shorthand methods
    success: (title: string, options?: Partial<Toast>) => string;
    error: (title: string, options?: Partial<Toast>) => string;
    warning: (title: string, options?: Partial<Toast>) => string;
    info: (title: string, options?: Partial<Toast>) => string;
    loading: (title: string, options?: Partial<Toast>) => string;
    promise: <T>(
        promise: Promise<T>,
        messages: { loading: string; success: string; error: string }
    ) => Promise<T>;
}

const ToastContext = createContext<ToastContextValue | null>(null);

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within ToastProvider');
    }
    return context;
};

export const ToastProvider: React.FC<{
    children: React.ReactNode;
    position?: 'top-right' | 'top-left' | 'bottom-right' | 'bottom-left' | 'top-center' | 'bottom-center';
    maxToasts?: number;
}> = ({
    children,
    position = 'bottom-right',
    maxToasts = 5
}) => {
        const [toasts, setToasts] = useState<Toast[]>([]);
        const haptic = useHapticFeedback();

        const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
            const id = `toast-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
            const newToast: Toast = {
                ...toast,
                id,
                duration: toast.duration ?? (toast.type === 'loading' ? 0 : 5000),
                dismissible: toast.dismissible ?? true
            };

            // Haptic feedback based on type
            if (toast.type === 'success') haptic.success();
            else if (toast.type === 'error') haptic.error();
            else if (toast.type === 'warning') haptic.warning();
            else haptic.light();

            setToasts(prev => {
                const updated = [newToast, ...prev];
                return updated.slice(0, maxToasts);
            });

            return id;
        }, [haptic, maxToasts]);

        const removeToast = useCallback((id: string) => {
            setToasts(prev => prev.filter(t => t.id !== id));
        }, []);

        const updateToast = useCallback((id: string, updates: Partial<Toast>) => {
            setToasts(prev => prev.map(t =>
                t.id === id ? { ...t, ...updates } : t
            ));
        }, []);

        const clearAll = useCallback(() => {
            setToasts([]);
        }, []);

        // Shorthand methods
        const success = useCallback((title: string, options?: Partial<Toast>) =>
            addToast({ type: 'success', title, ...options }), [addToast]);

        const error = useCallback((title: string, options?: Partial<Toast>) =>
            addToast({ type: 'error', title, duration: 0, ...options }), [addToast]);

        const warning = useCallback((title: string, options?: Partial<Toast>) =>
            addToast({ type: 'warning', title, ...options }), [addToast]);

        const info = useCallback((title: string, options?: Partial<Toast>) =>
            addToast({ type: 'info', title, ...options }), [addToast]);

        const loading = useCallback((title: string, options?: Partial<Toast>) =>
            addToast({ type: 'loading', title, duration: 0, dismissible: false, ...options }), [addToast]);

        const promise = useCallback(async <T,>(
            promiseToResolve: Promise<T>,
            messages: { loading: string; success: string; error: string }
        ): Promise<T> => {
            const id = loading(messages.loading);

            try {
                const result = await promiseToResolve;
                updateToast(id, {
                    type: 'success',
                    title: messages.success,
                    duration: 5000,
                    dismissible: true
                });
                haptic.success();
                return result;
            } catch (err) {
                updateToast(id, {
                    type: 'error',
                    title: messages.error,
                    message: err instanceof Error ? err.message : undefined,
                    duration: 0,
                    dismissible: true
                });
                haptic.error();
                throw err;
            }
        }, [loading, updateToast, haptic]);

        const positionClasses = {
            'top-right': 'top-4 right-4',
            'top-left': 'top-4 left-4',
            'bottom-right': 'bottom-4 right-4',
            'bottom-left': 'bottom-4 left-4',
            'top-center': 'top-4 left-1/2 -translate-x-1/2',
            'bottom-center': 'bottom-4 left-1/2 -translate-x-1/2'
        };

        return (
            <ToastContext.Provider value={{
                toasts, addToast, removeToast, updateToast, clearAll,
                success, error, warning, info, loading, promise
            }}>
                {children}

                {/* Toast Container */}
                <div
                    className={`fixed ${positionClasses[position]} z-[100] flex flex-col gap-2 w-full max-w-sm pointer-events-none`}
                    role="region"
                    aria-label="Notifikasi"
                    aria-live="polite"
                >
                    {toasts.map(toast => (
                        <ToastItem
                            key={toast.id}
                            toast={toast}
                            onDismiss={() => removeToast(toast.id)}
                        />
                    ))}
                </div>
            </ToastContext.Provider>
        );
    };

// Toast Item Component
const ToastItem: React.FC<{ toast: Toast; onDismiss: () => void }> = ({ toast, onDismiss }) => {
    const [isExiting, setIsExiting] = useState(false);
    const [progress, setProgress] = useState(100);
    const progressRef = useRef<NodeJS.Timeout>();

    const handleDismiss = useCallback(() => {
        setIsExiting(true);
        setTimeout(onDismiss, 200);
    }, [onDismiss]);

    // Auto-dismiss timer with progress
    useEffect(() => {
        if (toast.duration && toast.duration > 0) {
            const startTime = Date.now();
            const updateProgress = () => {
                const elapsed = Date.now() - startTime;
                const remaining = Math.max(0, 100 - (elapsed / toast.duration!) * 100);
                setProgress(remaining);

                if (remaining > 0) {
                    progressRef.current = setTimeout(updateProgress, 50);
                } else {
                    handleDismiss();
                }
            };

            progressRef.current = setTimeout(updateProgress, 50);

            return () => {
                if (progressRef.current) clearTimeout(progressRef.current);
            };
        }
    }, [toast.duration, handleDismiss]);

    const iconMap = {
        success: <Check className="w-5 h-5 text-emerald-500" />,
        error: <AlertCircle className="w-5 h-5 text-red-500" />,
        warning: <AlertTriangle className="w-5 h-5 text-amber-500" />,
        info: <Info className="w-5 h-5 text-blue-500" />,
        loading: <Loader2 className="w-5 h-5 text-indigo-500 animate-spin" />
    };

    const bgColorMap = {
        success: 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800',
        error: 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800',
        warning: 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800',
        info: 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800',
        loading: 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800'
    };

    const progressColorMap = {
        success: 'bg-emerald-500',
        error: 'bg-red-500',
        warning: 'bg-amber-500',
        info: 'bg-blue-500',
        loading: 'bg-indigo-500'
    };

    return (
        <div
            role="alert"
            className={`
                pointer-events-auto
                relative overflow-hidden
                p-4 rounded-xl border shadow-lg
                transform transition-all duration-200
                ${bgColorMap[toast.type]}
                ${isExiting ? 'opacity-0 translate-x-full' : 'opacity-100 translate-x-0 animate-slide-in-right'}
            `}
        >
            <div className="flex items-start gap-3">
                {/* Icon */}
                <div className="flex-shrink-0">
                    {iconMap[toast.type]}
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                    <p className="font-medium text-slate-900 dark:text-white">
                        {toast.title}
                    </p>
                    {toast.message && (
                        <p className="text-sm text-slate-600 dark:text-slate-400 mt-0.5">
                            {toast.message}
                        </p>
                    )}

                    {/* Actions */}
                    <div className="flex items-center gap-2 mt-2">
                        {toast.undoAction && (
                            <button
                                onClick={() => {
                                    toast.undoAction?.();
                                    handleDismiss();
                                }}
                                className="inline-flex items-center gap-1 text-sm font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300"
                            >
                                <Undo2 className="w-3.5 h-3.5" />
                                Urungkan
                            </button>
                        )}
                        {toast.action && (
                            <button
                                onClick={() => {
                                    toast.action?.onClick();
                                    handleDismiss();
                                }}
                                className="inline-flex items-center gap-1 text-sm font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300"
                            >
                                {toast.action.label}
                                <ChevronRight className="w-3.5 h-3.5" />
                            </button>
                        )}
                    </div>
                </div>

                {/* Dismiss button */}
                {toast.dismissible && (
                    <button
                        onClick={handleDismiss}
                        className="flex-shrink-0 p-1 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 rounded-lg hover:bg-white/50 dark:hover:bg-slate-800/50"
                        aria-label="Tutup notifikasi"
                    >
                        <X className="w-4 h-4" />
                    </button>
                )}
            </div>

            {/* Progress bar */}
            {toast.type === 'loading' && toast.progress !== undefined ? (
                <div className="absolute bottom-0 left-0 right-0 h-1 bg-slate-200 dark:bg-slate-700">
                    <div
                        className={`h-full ${progressColorMap[toast.type]} transition-all duration-100`}
                        style={{ width: `${toast.progress}%` }}
                    />
                </div>
            ) : toast.duration && toast.duration > 0 ? (
                <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-slate-200/50 dark:bg-slate-700/50">
                    <div
                        className={`h-full ${progressColorMap[toast.type]} transition-all`}
                        style={{ width: `${progress}%` }}
                    />
                </div>
            ) : null}
        </div>
    );
};

// ============================================
// PROGRESS INDICATOR
// ============================================

interface ProgressIndicatorProps {
    value: number; // 0-100
    showLabel?: boolean;
    size?: 'sm' | 'md' | 'lg';
    variant?: 'linear' | 'circular';
    color?: string;
    className?: string;
}

export const ProgressIndicator: React.FC<ProgressIndicatorProps> = ({
    value,
    showLabel = true,
    size = 'md',
    variant = 'linear',
    color = 'indigo',
    className = ''
}) => {
    const clampedValue = Math.min(100, Math.max(0, value));

    const sizeClasses = {
        sm: variant === 'linear' ? 'h-1' : 'w-8 h-8',
        md: variant === 'linear' ? 'h-2' : 'w-12 h-12',
        lg: variant === 'linear' ? 'h-3' : 'w-16 h-16'
    };

    if (variant === 'circular') {
        const radius = size === 'sm' ? 14 : size === 'md' ? 20 : 28;
        const circumference = 2 * Math.PI * radius;
        const strokeDashoffset = circumference - (clampedValue / 100) * circumference;

        return (
            <div className={`relative ${sizeClasses[size]} ${className}`}>
                <svg className="w-full h-full -rotate-90" viewBox="0 0 64 64">
                    {/* Background circle */}
                    <circle
                        cx="32"
                        cy="32"
                        r={radius}
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="4"
                        className="text-slate-200 dark:text-slate-700"
                    />
                    {/* Progress circle */}
                    <circle
                        cx="32"
                        cy="32"
                        r={radius}
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="4"
                        strokeLinecap="round"
                        className={`text-${color}-500 transition-all duration-300`}
                        style={{
                            strokeDasharray: circumference,
                            strokeDashoffset
                        }}
                    />
                </svg>
                {showLabel && size !== 'sm' && (
                    <span className="absolute inset-0 flex items-center justify-center text-xs font-medium text-slate-700 dark:text-slate-300">
                        {Math.round(clampedValue)}%
                    </span>
                )}
            </div>
        );
    }

    return (
        <div className={className}>
            <div className={`w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden ${sizeClasses[size]}`}>
                <div
                    className={`h-full bg-${color}-500 rounded-full transition-all duration-300`}
                    style={{ width: `${clampedValue}%` }}
                    role="progressbar"
                    aria-valuenow={clampedValue}
                    aria-valuemin={0}
                    aria-valuemax={100}
                />
            </div>
            {showLabel && (
                <div className="mt-1 text-right text-sm text-slate-500 dark:text-slate-400">
                    {Math.round(clampedValue)}%
                </div>
            )}
        </div>
    );
};

