    onNavigate,
    className = ''
}) => {
    const currentIndex = pages.indexOf(currentPath);

    const swipeRef = useSwipeGesture({
        onSwipeLeft: () => {
            if (currentIndex < pages.length - 1) {
                onNavigate(pages[currentIndex + 1]);
            }
        },
        onSwipeRight: () => {
            if (currentIndex > 0) {
                onNavigate(pages[currentIndex - 1]);
            }
        }
    });

    return (
        <div ref={swipeRef} className={className}>
            {children}
        </div>
    );
};

