import React, { useState, useEffect, useRef, useId } from 'react';

/**
 * Skeleton & Loading Components
 * Features: Shimmer effect, skeleton screens, progressive image loading
 */

// ============================================
// SHIMMER ANIMATION STYLES
// ============================================

const shimmerClass = `
    relative overflow-hidden
    before:absolute before:inset-0
    before:-translate-x-full
    before:animate-[shimmer_1.5s_infinite]
    before:bg-gradient-to-r
    before:from-transparent before:via-white/20 before:to-transparent
`;

// Add to your global CSS:
// @keyframes shimmer {
//   100% { transform: translateX(100%); }
// }

// ============================================
// BASE SKELETON
// ============================================

interface SkeletonProps {
    className?: string;
    width?: string | number;
    height?: string | number;
    rounded?: 'none' | 'sm' | 'md' | 'lg' | 'full';
    animate?: boolean;
}

export const Skeleton: React.FC<SkeletonProps> = ({
    className = '',
    width,
    height,
    rounded = 'md',
    animate = true
}) => {
    const roundedClass = {
        none: '',
        sm: 'rounded-sm',
        md: 'rounded-md',
        lg: 'rounded-lg',
        full: 'rounded-full'
    }[rounded];

    return (
        <div
            className={`
                bg-slate-200 dark:bg-slate-700 
                ${roundedClass}
                ${animate ? 'animate-pulse' : ''}
                ${className}
            `}
            style={{
                width: typeof width === 'number' ? `${width}px` : width,
                height: typeof height === 'number' ? `${height}px` : height
            }}
        />
    );
};

// Skeleton with shimmer effect
export const SkeletonShimmer: React.FC<SkeletonProps> = ({
    className = '',
    width,
    height,
    rounded = 'md'
}) => {
    const roundedClass = {
        none: '',
        sm: 'rounded-sm',
        md: 'rounded-md',
        lg: 'rounded-lg',
        full: 'rounded-full'
    }[rounded];

    return (
        <div
            className={`
                bg-slate-200 dark:bg-slate-700 
                ${roundedClass}
                relative overflow-hidden
                ${className}
            `}
            style={{
                width: typeof width === 'number' ? `${width}px` : width,
                height: typeof height === 'number' ? `${height}px` : height
            }}
        >
            <div className="absolute inset-0 animate-shimmer-slide bg-gradient-to-r from-transparent via-white/30 dark:via-white/10 to-transparent" />
        </div>
    );
};

// ============================================
// TEXT SKELETON
// ============================================

interface SkeletonTextProps {
    lines?: number;
    className?: string;
    animate?: boolean;
}

export const SkeletonText: React.FC<SkeletonTextProps> = ({
    lines = 3,
    className = '',
    animate = true
}) => {
    return (
        <div className={`space-y-2 ${className}`}>
            {Array.from({ length: lines }).map((_, i) => (
                <Skeleton
                    key={i}
                    height={16}
                    width={i === lines - 1 ? '75%' : '100%'}
                    animate={animate}
                />
            ))}
        </div>
    );
};

// ============================================
// AVATAR SKELETON
// ============================================

interface SkeletonAvatarProps {
    size?: 'sm' | 'md' | 'lg' | 'xl';
    className?: string;
}

export const SkeletonAvatar: React.FC<SkeletonAvatarProps> = ({
    size = 'md',
    className = ''
}) => {
    const sizeMap = {
        sm: 32,
        md: 40,
        lg: 56,
        xl: 80
    };

    return (
        <SkeletonShimmer
            width={sizeMap[size]}
            height={sizeMap[size]}
            rounded="full"
            className={className}
        />
    );
};

// ============================================
// CARD SKELETON
// ============================================

interface SkeletonCardProps {
    hasImage?: boolean;
    hasAvatar?: boolean;
    lines?: number;
    className?: string;
}

export const SkeletonCard: React.FC<SkeletonCardProps> = ({
    hasImage = false,
    hasAvatar = false,
    lines = 2,
    className = ''
}) => {
    return (
        <div className={`bg-white dark:bg-slate-800 rounded-xl p-4 shadow-sm ${className}`}>
            {hasImage && (
                <SkeletonShimmer
                    width="100%"
                    height={160}
                    rounded="lg"
                    className="mb-4"
                />
            )}
            <div className="flex items-start gap-3">
                {hasAvatar && <SkeletonAvatar size="md" />}
                <div className="flex-1">
                    <SkeletonShimmer height={20} width="60%" className="mb-2" />
                    <SkeletonText lines={lines} />
                </div>
            </div>
        </div>
    );
};

// ============================================
// LIST ITEM SKELETON
// ============================================

interface SkeletonListItemProps {
    hasAvatar?: boolean;
    hasAction?: boolean;
    className?: string;
}

export const SkeletonListItem: React.FC<SkeletonListItemProps> = ({
    hasAvatar = true,
    hasAction = false,
    className = ''
}) => {
    return (
        <div className={`flex items-center gap-4 p-4 ${className}`}>
            {hasAvatar && <SkeletonAvatar size="md" />}
            <div className="flex-1">
                <SkeletonShimmer height={18} width="50%" className="mb-2" />
                <SkeletonShimmer height={14} width="30%" />
            </div>
            {hasAction && <SkeletonShimmer height={32} width={80} rounded="lg" />}
        </div>
    );
};

export const SkeletonList: React.FC<{
    count?: number;
    hasAvatar?: boolean;
    hasAction?: boolean;
    className?: string;
}> = ({
    count = 5,
    hasAvatar = true,
    hasAction = false,
    className = ''
}) => {
        return (
            <div className={`divide-y divide-slate-200 dark:divide-slate-700 ${className}`}>
                {Array.from({ length: count }).map((_, i) => (
                    <SkeletonListItem key={i} hasAvatar={hasAvatar} hasAction={hasAction} />
                ))}
            </div>
        );
    };

// ============================================
// TABLE SKELETON
// ============================================

interface SkeletonTableProps {
    rows?: number;
    columns?: number;
    hasHeader?: boolean;
