// ============================================
// PROGRESSIVE IMAGE LOADING
// ============================================

interface ProgressiveImageProps {
    src: string;
    alt: string;
    placeholder?: string;
    className?: string;
    width?: number;
    height?: number;
    blurDataURL?: string;
}

export const ProgressiveImage: React.FC<ProgressiveImageProps> = ({
    src,
    alt,
    placeholder,
    className = '',
    width,
    height,
    blurDataURL
}) => {
    const [isError, setIsError] = useState(false);
    const imgRef = useRef<HTMLImageElement>(null);

    // Generate blur placeholder if not provided
    const defaultPlaceholder = `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 ${width || 400} ${height || 300}'%3E%3Crect width='100%25' height='100%25' fill='%23E2E8F0'/%3E%3C/svg%3E`;

    React.useLayoutEffect(() => {
        if (imgRef.current?.complete) {
            setIsLoaded(true);
        }
    }, []);

    return (
        <div
            className={`relative overflow-hidden ${className}`}
            style={{ width, height }}
        >
            {/* Blur placeholder */}
            {!isLoaded && !isError && (
                <>
                    <img
                        src={blurDataURL || placeholder || defaultPlaceholder}
                        alt=""
                        className="absolute inset-0 w-full h-full object-cover blur-lg scale-110"
                        aria-hidden="true"
                    />
                    <div className="absolute inset-0 animate-pulse bg-slate-200/50 dark:bg-slate-700/50" />
                </>
            )}

            {/* Error state */}
            {isError && (
                <div className="absolute inset-0 flex items-center justify-center bg-slate-100 dark:bg-slate-800">
                    <svg className="w-8 h-8 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                </div>
            )}

            {/* Main image */}
            <img
                ref={imgRef}
                src={src}
                alt={alt}
                className={`w-full h-full object-cover transition-opacity duration-500 ${isLoaded ? 'opacity-100' : 'opacity-0'
                    }`}
                onLoad={() => setIsLoaded(true)}
                onError={() => setIsError(true)}
            />
        </div>
    );
};

// ============================================
// LAZY LOADING WRAPPER
// ============================================

interface LazyLoadProps {
    children: React.ReactNode;
    skeleton?: React.ReactNode;
    height?: number | string;
    offset?: number;
    className?: string;
}

export const LazyLoad: React.FC<LazyLoadProps> = ({
    children,
    skeleton,
    height = 200,
    offset = 200,
    className = ''
}) => {
    const [isVisible, setIsVisible] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                    observer.disconnect();
                }
            },
            { rootMargin: `${offset}px` }
        );

        if (containerRef.current) {
            observer.observe(containerRef.current);
        }

        return () => observer.disconnect();
    }, [offset]);

    return (
        <div
            ref={containerRef}
            className={className}
            style={{ minHeight: height }}
        >
            {isVisible ? children : (skeleton || <Skeleton height={height} width="100%" />)}
        </div>
    );
};

// ============================================
// CONTENT LOADER (SVG-BASED)
// ============================================

interface ContentLoaderProps {
    width?: number;
    height?: number;
    speed?: number;
    backgroundColor?: string;
    foregroundColor?: string;
    children?: React.ReactNode;
}

export const ContentLoader: React.FC<ContentLoaderProps> = ({
    width = 400,
    height = 130,
    speed = 2,
    backgroundColor = '#e2e8f0',
    foregroundColor = '#f8fafc',
    children
}) => {
    const idBase = useId();
    const idClip = `${idBase}-clip`;
    const idGradient = `${idBase}-gradient`;

    return (
        <svg
            width={width}
            height={height}
            viewBox={`0 0 ${width} ${height}`}
            style={{ width: '100%', height: 'auto' }}
        >
            <defs>
                <clipPath id={idClip}>
                    {children || (
                        <>
                            {/* Default: Card-like content */}
                            <circle cx="30" cy="30" r="30" />
                            <rect x="75" y="15" rx="4" ry="4" width="150" height="12" />
                            <rect x="75" y="35" rx="4" ry="4" width="100" height="10" />
                            <rect x="0" y="75" rx="4" ry="4" width="400" height="10" />
                            <rect x="0" y="95" rx="4" ry="4" width="370" height="10" />
                            <rect x="0" y="115" rx="4" ry="4" width="200" height="10" />
                        </>
                    )}
                </clipPath>
                <linearGradient id={idGradient}>
                    <stop offset="0%" stopColor={backgroundColor}>
                        <animate
                            attributeName="offset"
                            values="-2; -2; 1"
                            keyTimes="0; 0.25; 1"
                            dur={`${speed}s`}
                            repeatCount="indefinite"
                        />
                    </stop>
                    <stop offset="50%" stopColor={foregroundColor}>
                        <animate
                            attributeName="offset"
                            values="-1; -1; 2"
                            keyTimes="0; 0.25; 1"
                            dur={`${speed}s`}
                            repeatCount="indefinite"
                        />
                    </stop>
                    <stop offset="100%" stopColor={backgroundColor}>
                        <animate
                            attributeName="offset"
                            values="0; 0; 3"
                            keyTimes="0; 0.25; 1"
                            dur={`${speed}s`}
                            repeatCount="indefinite"
                        />
                    </stop>
                </linearGradient>
            </defs>
            <rect
                x="0"
                y="0"
                width={width}
                height={height}
                clipPath={`url(#${idClip})`}
                fill={`url(#${idGradient})`}
            />
        </svg>
    );
};

