            icon: <RefreshCw className="w-4 h-4 animate-spin" />,
            label: 'Sinkron...',
            color: 'text-blue-500',
            bg: 'bg-blue-100 dark:bg-blue-900/30'
        },
        pending: {
            icon: <Clock className="w-4 h-4" />,
            label: `${pendingCount}`,
            color: 'text-amber-500',
            bg: 'bg-amber-100 dark:bg-amber-900/30'
