// ============================================
// ONBOARDING TOOLTIP
// ============================================

interface OnboardingTooltipProps {
    step: {
        id: string;
        title: string;
        description: string;
        target?: string;
        position?: 'top' | 'bottom' | 'left' | 'right' | 'center';
    };
    currentStep: number;
    totalSteps: number;
    onNext: () => void;
    onPrevious: () => void;
    onSkip: () => void;
    isFirst: boolean;
    isLast: boolean;
}

export const OnboardingTooltip: React.FC<OnboardingTooltipProps> = ({
    step,
    currentStep,
    totalSteps,
    onNext,
    onPrevious,
    onSkip,
    isFirst,
    isLast
}) => {
    const [position, setPosition] = useState({ top: 0, left: 0 });
    const tooltipRef = useRef<HTMLDivElement>(null);

    React.useLayoutEffect(() => {
        if (step.position === 'center' || !step.target) {
            // Center on screen
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setPosition({
                top: window.innerHeight / 2 - 100,
                left: window.innerWidth / 2 - 175
            });
            return;
        }

        const target = document.querySelector(step.target);
        if (!target || !tooltipRef.current) return;

        const targetRect = target.getBoundingClientRect();
        const tooltipRect = tooltipRef.current.getBoundingClientRect();
        const gap = 12;

        let top = 0;
        let left = 0;

        switch (step.position) {
            case 'bottom':
                top = targetRect.bottom + gap;
                left = targetRect.left + targetRect.width / 2 - tooltipRect.width / 2;
                break;
            case 'top':
                top = targetRect.top - tooltipRect.height - gap;
                left = targetRect.left + targetRect.width / 2 - tooltipRect.width / 2;
                break;
            case 'left':
                top = targetRect.top + targetRect.height / 2 - tooltipRect.height / 2;
                left = targetRect.left - tooltipRect.width - gap;
                break;
            case 'right':
                top = targetRect.top + targetRect.height / 2 - tooltipRect.height / 2;
                left = targetRect.right + gap;
                break;
        }

        // Keep within viewport
        left = Math.max(16, Math.min(left, window.innerWidth - tooltipRect.width - 16));
        top = Math.max(16, Math.min(top, window.innerHeight - tooltipRect.height - 16));

        // eslint-disable-next-line react-hooks/set-state-in-effect
        setPosition({ top, left });
    }, [step]);

    return (
        <>
            {/* Backdrop */}
            <div className="fixed inset-0 bg-black/50 z-[9998]" onClick={onSkip} />

            {/* Highlight target element */}
            {step.target && (
                <HighlightOverlay target={step.target} />
            )}

            {/* Tooltip */}
            <div
                ref={tooltipRef}
                className="fixed z-[9999] w-[350px] bg-white dark:bg-slate-800 rounded-2xl shadow-2xl p-6"
                style={{ top: position.top, left: position.left }}
            >
                {/* Progress dots */}
                <div className="flex justify-center gap-1.5 mb-4">
                    {Array.from({ length: totalSteps }).map((_, i) => (
                        <div
                            key={i}
                            className={`w-2 h-2 rounded-full transition-colors ${i === currentStep
                                ? 'bg-indigo-500'
                                : i < currentStep
                                    ? 'bg-indigo-300'
                                    : 'bg-slate-300 dark:bg-slate-600'
                                }`}
                        />
                    ))}
                </div>

                {/* Icon */}
                {step.position === 'center' && (
                    <div className="flex justify-center mb-4">
                        <div className="w-16 h-16 bg-indigo-100 dark:bg-indigo-900/30 rounded-full flex items-center justify-center">
                            <Sparkles className="w-8 h-8 text-indigo-500" />
                        </div>
                    </div>
                )}

                <h3 className="text-lg font-semibold text-slate-900 dark:text-white mb-2">
                    {step.title}
                </h3>
                <p className="text-slate-600 dark:text-slate-400 text-sm mb-6">
                    {step.description}
                </p>

                {/* Actions */}
                <div className="flex items-center justify-between">
                    <button
                        onClick={onSkip}
                        className="text-sm text-slate-500 hover:text-slate-700 dark:hover:text-slate-300"
                    >
                        Lewati
                    </button>
                    <div className="flex gap-2">
                        {!isFirst && (
                            <button
                                onClick={onPrevious}
                                className="p-2 rounded-lg bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 transition-colors"
                            >
                                <ChevronLeft className="w-5 h-5" />
                            </button>
                        )}
                        <button
                            onClick={onNext}
                            className="px-4 py-2 bg-indigo-500 hover:bg-indigo-600 text-white rounded-lg font-medium transition-colors"
                        >
                            {isLast ? 'Selesai' : 'Lanjut'}
                        </button>
                    </div>
                </div>
            </div>
        </>
    );
};

// Highlight overlay for target element
const HighlightOverlay: React.FC<{ target: string }> = ({ target }) => {
    const [rect, setRect] = useState<DOMRect | null>(null);

    React.useLayoutEffect(() => {
        const el = document.querySelector(target);
        if (el) {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setRect(el.getBoundingClientRect());
        }
    }, [target]);

    if (!rect) return null;

    return (
        <div
            className="fixed z-[9998] ring-4 ring-indigo-500 ring-offset-4 rounded-lg pointer-events-none"
            style={{
                top: rect.top,
                left: rect.left,
                width: rect.width,
                height: rect.height
            }}
        />
    );
};

// ============================================
// ONBOARDING PROVIDER
// ============================================

interface OnboardingOverlayProps {
    flowId: string;
    steps: typeof ONBOARDING_FLOWS.newUser;
    autoStart?: boolean;
}

export const OnboardingOverlay: React.FC<OnboardingOverlayProps> = ({
    flowId,
    steps,
    autoStart = true
}) => {
    const {
        isActive,
        currentStep,
        currentStepData,
        totalSteps,
        isFirstStep,
        isLastStep,
        isFlowCompleted,
        start,
        next,
        previous,
        skip
    } = useOnboarding(flowId, steps);

    // Auto-start for new users
    useEffect(() => {
        if (autoStart && !isFlowCompleted) {
            start();
        }
    }, [autoStart, isFlowCompleted, start]);

    if (!isActive || !currentStepData) return null;

    return (
        <OnboardingTooltip
            step={currentStepData}
            currentStep={currentStep}
            totalSteps={totalSteps}
            onNext={next}
            onPrevious={previous}
            onSkip={skip}
            isFirst={isFirstStep}
            isLast={isLastStep}
        />
    );
};

