import React from 'react';
import { Flame, TrendingUp, Award } from 'lucide-react';

interface StreakData {
    studentId: string;
    studentName: string;
    currentStreak: number;
    longestStreak: number;
    attendanceRate: number;
}

interface AttendanceStreakIndicatorProps {
    streaks: StreakData[];
    onStudentClick?: (studentId: string) => void;
}

export const AttendanceStreakIndicator: React.FC<AttendanceStreakIndicatorProps> = ({
    streaks,
    onStudentClick,
}) => {
    // Sort by current streak (highest first)
    const topStreaks = React.useMemo(() => (
        [...streaks]
            .filter(s => s.currentStreak > 0)
            .sort((a, b) => b.currentStreak - a.currentStreak)
            .slice(0, 5)
    ), [streaks]);

    if (topStreaks.length === 0) {
        return null;
    }

    const getStreakColor = (streak: number) => {
        if (streak >= 30) return 'from-yellow-500 to-orange-500';
        if (streak >= 14) return 'from-purple-500 to-pink-500';
        if (streak >= 7) return 'from-blue-500 to-indigo-500';
        return 'from-emerald-500 to-teal-500';
    };

    const getStreakEmoji = (streak: number) => {
        if (streak >= 30) return '≡ƒÅå';
        if (streak >= 14) return 'Γ¡É';
        if (streak >= 7) return '≡ƒöÑ';
        return 'Γ£¿';
    };

    return (
        <div className="bg-gradient-to-br from-orange-50 to-amber-50 dark:from-orange-900/20 dark:to-amber-900/20 rounded-xl p-4 border border-orange-200 dark:border-orange-700/50 shadow-sm">
            <div className="flex items-center gap-3 mb-4">
                <div className="w-9 h-9 rounded-lg bg-gradient-to-br from-orange-500 to-amber-500 flex items-center justify-center shadow-lg shadow-orange-500/30">
