import React, { useState, useEffect, useRef } from 'react';
import QRCode from 'qrcode';
import { Button } from '../ui/Button';
import { Modal } from '../ui/Modal';
import { DownloadIcon, CopyIcon, QrCodeIcon, RefreshCwIcon } from 'lucide-react';

interface QRCodeGeneratorProps {
    isOpen: boolean;
    onClose: () => void;
    classId: string;
    className: string;
    date: string;
    userId: string;
}

interface QRData {
    type: 'attendance';
    classId: string;
    date: string;
    userId: string;
    token: string;
    expiresAt: string;
}

export const QRCodeGenerator: React.FC<QRCodeGeneratorProps> = ({
    isOpen,
    onClose,
    classId,
    className,
    date,
    userId,
}) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [qrDataUrl, setQrDataUrl] = useState<string>('');
    const [token, setToken] = useState<string>('');
    const [expiresAt, setExpiresAt] = useState<Date>(new Date());
    const [timeLeft, setTimeLeft] = useState<string>('');

    // Generate a unique token for this QR session
    const generateToken = () => {
        const newToken = crypto.randomUUID().split('-').pop() || '';
        const expiry = new Date(Date.now() + 15 * 60 * 1000); // 15 minutes
        setToken(newToken);
        setExpiresAt(expiry);
        return { token: newToken, expiry };
    };

    // Generate QR code
    const generateQR = async () => {
        const { token: newToken, expiry } = generateToken();

        const qrData: QRData = {
            type: 'attendance',
            classId,
            date,
            userId,
            token: newToken,
            expiresAt: expiry.toISOString(),
        };

        try {
            const url = await QRCode.toDataURL(JSON.stringify(qrData), {
                width: 300,
                margin: 2,
                color: {
                    dark: '#065f46',
                    light: '#ffffff',
                },
                errorCorrectionLevel: 'M',
            });
            setQrDataUrl(url);
        } catch (err) {
            console.error('Error generating QR code:', err);
        }
    };

    // Countdown timer
    useEffect(() => {
        if (!isOpen) return;

        const timer = setInterval(() => {
            const now = new Date();
            const diff = expiresAt.getTime() - now.getTime();

            if (diff <= 0) {
                setTimeLeft('Expired');
                generateQR(); // Auto-refresh when expired
            } else {
                const minutes = Math.floor(diff / 60000);
                const seconds = Math.floor((diff % 60000) / 1000);
                setTimeLeft(`${minutes}:${seconds.toString().padStart(2, '0')}`);
            }
        }, 1000);

        return () => clearInterval(timer);
    }, [expiresAt, isOpen]);

    // Generate QR on open
    useEffect(() => {
        if (isOpen && classId) {
            setTimeout(generateQR, 0);
        }
    }, [isOpen, classId, date]);

    const handleDownload = () => {
        if (!qrDataUrl) return;
        const link = document.createElement('a');
        link.download = `qr-absensi-${className}-${date}.png`;
        link.href = qrDataUrl;
        link.click();
    };

    const handleCopyLink = async () => {
        const attendanceLink = `${window.location.origin}/scan-absensi?token=${token}&class=${classId}&date=${date}`;
        await navigator.clipboard.writeText(attendanceLink);
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title="QR Code Absensi"
            icon={<QrCodeIcon className="w-5 h-5" />}
        >
            <div className="space-y-6">
                {/* QR Code Display */}
                <div className="flex flex-col items-center">
                    <div className="relative p-4 bg-white rounded-2xl shadow-lg">
                        {qrDataUrl ? (
                            <img
                                src={qrDataUrl}
                                alt="QR Code Absensi"
                                className="w-64 h-64"
                            />
                        ) : (
                            <div className="w-64 h-64 bg-gray-100 rounded-xl animate-pulse flex items-center justify-center">
                                <span className="text-gray-400">Generating...</span>
                            </div>
                        )}

                        {/* Timer Badge */}
                        <div className={`absolute -top-2 -right-2 px-3 py-1 rounded-full text-xs font-bold ${timeLeft === 'Expired'
                                ? 'bg-red-500 text-white'
                                : 'bg-green-600 text-white'
                            }`}>
                            {timeLeft}
                        </div>
                    </div>

                    {/* Class Info */}
                    <div className="mt-4 text-center">
                        <h3 className="font-bold text-lg text-slate-900 dark:text-white">
                            {className}
                        </h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400">
                            {new Date(date).toLocaleDateString('id-ID', {
                                weekday: 'long',
                                day: 'numeric',
                                month: 'long',
                                year: 'numeric',
                            })}
                        </p>
                    </div>
                </div>

                {/* Actions */}
                <div className="grid grid-cols-3 gap-3">
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={generateQR}
                        className="flex flex-col items-center gap-1 h-auto py-3"
                    >
                        <RefreshCwIcon className="w-4 h-4" />
                        <span className="text-xs">Refresh</span>
                    </Button>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleDownload}
                        className="flex flex-col items-center gap-1 h-auto py-3"
                    >
                        <DownloadIcon className="w-4 h-4" />
                        <span className="text-xs">Download</span>
                    </Button>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleCopyLink}
                        className="flex flex-col items-center gap-1 h-auto py-3"
                    >
                        <CopyIcon className="w-4 h-4" />
                        <span className="text-xs">Copy Link</span>
                    </Button>
                </div>

                {/* Instructions */}
                <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-xl">
                    <h4 className="font-medium text-green-700 dark:text-green-300 mb-2">
                        Cara Penggunaan:
                    </h4>
                    <ol className="text-sm text-green-600 dark:text-green-400 space-y-1 list-decimal list-inside">
                        <li>Tampilkan QR ini di layar kelas</li>
                        <li>Siswa scan menggunakan aplikasi kamera</li>
                        <li>Absensi otomatis tercatat</li>
                        <li>QR berlaku selama 15 menit</li>
                    </ol>
                </div>
            </div>
        </Modal>
    );
};

export default QRCodeGenerator;

import React, { useState, useMemo } from 'react';
import { Modal } from '../ui/Modal';
import { Button } from '../ui/Button';
import { Input } from '../ui/Input';
import {
    UsersIcon,
    SendIcon,
    CheckIcon,
    AlertCircleIcon,
    SearchIcon,
    FileTextIcon,
    ChevronDownIcon
} from '../Icons';
import { MESSAGE_TEMPLATES, TEMPLATE_CATEGORIES, MessageTemplate, applyTemplate } from '../../data/messageTemplates';
import { getStudentAvatar } from '../../utils/avatarUtils';

interface Student {
    id: string;
    name: string;
    class_id: string;
    avatar_url?: string;
    gender?: string;
}

interface Class {
    id: string;
    name: string;
}

interface BulkMessageModalProps {
    isOpen: boolean;
    onClose: () => void;
    students: Student[];
    classes: Class[];
    onSendBulkMessage: (studentIds: string[], message: string) => Promise<void>;
    isOnline: boolean;
}

type SelectionMode = 'all' | 'class' | 'custom';

export const BulkMessageModal: React.FC<BulkMessageModalProps> = ({
    isOpen,
    onClose,
    students,
    classes,
    onSendBulkMessage,
    isOnline
}) => {
    const [message, setMessage] = useState('');
    const [selectionMode, setSelectionMode] = useState<SelectionMode>('all');
    const [selectedClassId, setSelectedClassId] = useState<string>('');
    const [selectedStudentIds, setSelectedStudentIds] = useState<Set<string>>(new Set());
    const [searchQuery, setSearchQuery] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [showTemplates, setShowTemplates] = useState(false);
    const [selectedCategory, setSelectedCategory] = useState<MessageTemplate['category'] | 'all'>('all');
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    // Get recipients based on selection mode
    const recipients = useMemo(() => {
        switch (selectionMode) {
            case 'all':
                return students;
            case 'class':
                return students.filter(s => s.class_id === selectedClassId);
            case 'custom':
                return students.filter(s => selectedStudentIds.has(s.id));
            default:
                return [];
        }
    }, [selectionMode, students, selectedClassId, selectedStudentIds]);

    // Filter students for custom selection
    const filteredStudents = useMemo(() => {
        if (!searchQuery.trim()) return students;
        const query = searchQuery.toLowerCase();
        return students.filter(s => s.name.toLowerCase().includes(query));
    }, [students, searchQuery]);

    // Get filtered templates
    const filteredTemplates = useMemo(() => {
        if (selectedCategory === 'all') return MESSAGE_TEMPLATES;
        return MESSAGE_TEMPLATES.filter(t => t.category === selectedCategory);
    }, [selectedCategory]);

    const handleToggleStudent = (studentId: string) => {
        const newSet = new Set(selectedStudentIds);
        if (newSet.has(studentId)) {
            newSet.delete(studentId);
        } else {
            newSet.add(studentId);
        }
        setSelectedStudentIds(newSet);
    };

    const handleSelectAll = () => {
        if (selectedStudentIds.size === filteredStudents.length) {
            setSelectedStudentIds(new Set());
        } else {
            setSelectedStudentIds(new Set(filteredStudents.map(s => s.id)));
        }
    };

    const handleSelectTemplate = (template: MessageTemplate) => {
        // Apply template without student name (will be generic)
        const msg = template.message.replace(/\{\{nama_siswa\}\}/g, '[Nama Siswa]');
        setMessage(msg);
        setShowTemplates(false);
    };

    const handleSend = async () => {
        if (!message.trim() || recipients.length === 0) return;

        setIsSending(true);
        setError(null);

        try {
            await onSendBulkMessage(recipients.map(r => r.id), message);
            setSuccess(true);
            setTimeout(() => {
                onClose();
                // Reset state
                setMessage('');
                setSelectionMode('all');
                setSelectedStudentIds(new Set());
                setSuccess(false);
            }, 2000);
        } catch (err: any) {
            setError(err.message || 'Gagal mengirim pesan');
        } finally {
            setIsSending(false);
        }
    };

    const handleClose = () => {
        if (!isSending) {
            onClose();
            setMessage('');
            setError(null);
            setSuccess(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={handleClose} title="Kirim Pesan ke Orang Tua">
            <div className="space-y-6">
                {/* Success State */}
                {success ? (
                    <div className="flex flex-col items-center justify-center py-12 text-center">
                        <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-4">
                            <CheckIcon className="w-8 h-8 text-green-600 dark:text-green-400" />
                        </div>
                        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                            Pesan Terkirim!
                        </h3>
                        <p className="text-sm text-gray-500 dark:text-gray-400">
                            Pesan berhasil dikirim ke {recipients.length} wali murid
                        </p>
                    </div>
                ) : (
                    <>
                        {/* Selection Mode */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-3">
                                Kirim Ke
                            </label>
                            <div className="flex flex-wrap gap-2">
                                <button
                                    onClick={() => setSelectionMode('all')}
                                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${selectionMode === 'all'
                                        ? 'bg-blue-600 text-white'
                                        : 'bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
                                        }`}
                                >
                                    <UsersIcon className="w-4 h-4 inline-block mr-2" />
                                    Semua Siswa ({students.length})
                                </button>
                                <button
                                    onClick={() => setSelectionMode('class')}
                                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${selectionMode === 'class'
                                        ? 'bg-blue-600 text-white'
                                        : 'bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
                                        }`}
                                >
                                    Per Kelas
                                </button>
                                <button
                                    onClick={() => setSelectionMode('custom')}
                                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${selectionMode === 'custom'
                                        ? 'bg-blue-600 text-white'
                                        : 'bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'
                                        }`}
                                >
                                    Pilih Manual
                                </button>
                            </div>
                        </div>

                        {/* Class Selection */}
                        {selectionMode === 'class' && (
                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Pilih Kelas
                                </label>
                                <select
                                    value={selectedClassId}
                                    onChange={e => setSelectedClassId(e.target.value)}
                                    className="w-full h-10 px-3 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300"
                                >
                                    <option value="">-- Pilih Kelas --</option>
                                    {classes.map(cls => (
                                        <option key={cls.id} value={cls.id}>
                                            {cls.name} ({students.filter(s => s.class_id === cls.id).length} siswa)
                                        </option>
                                    ))}
                                </select>
                            </div>
                        )}

                        {/* Custom Selection */}
                        {selectionMode === 'custom' && (
                            <div>
                                <div className="flex items-center justify-between mb-2">
                                    <label className="text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Pilih Siswa ({selectedStudentIds.size} dipilih)
                                    </label>
                                    <button
                                        onClick={handleSelectAll}
                                        className="text-xs text-blue-600 dark:text-blue-400 hover:underline"
                                    >
                                        {selectedStudentIds.size === filteredStudents.length ? 'Batalkan Semua' : 'Pilih Semua'}
                                    </button>
                                </div>
                                <div className="relative mb-2">
                                    <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                                    <Input
                                        value={searchQuery}
                                        onChange={e => setSearchQuery(e.target.value)}
                                        placeholder="Cari siswa..."
                                        className="pl-9"
                                    />
                                </div>
                                <div className="max-h-40 overflow-y-auto border border-gray-200 dark:border-gray-700 rounded-lg divide-y divide-gray-100 dark:divide-gray-700">
                                    {filteredStudents.map(student => (
                                        <label
                                            key={student.id}
                                            className="flex items-center gap-3 p-3 hover:bg-gray-50 dark:hover:bg-gray-800/50 cursor-pointer"
                                        >
                                            <input
                                                type="checkbox"
                                                checked={selectedStudentIds.has(student.id)}
                                                onChange={() => handleToggleStudent(student.id)}
                                                className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                            />
                                            <img
                                                src={getStudentAvatar(student.avatar_url, student.gender, student.id)}
                                                alt={student.name}
                                                className="w-8 h-8 rounded-full object-cover"
                                            />
                                            <span className="text-sm text-gray-900 dark:text-white">{student.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Recipients Preview */}
                        <div className="bg-gray-50 dark:bg-gray-800/50 rounded-lg p-3">
                            <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                                <UsersIcon className="w-4 h-4" />
                                <span>
                                    Akan dikirim ke <strong className="text-gray-900 dark:text-white">{recipients.length}</strong> wali murid
                                </span>
                            </div>
                        </div>

                        {/* Template Selector */}
                        <div className="relative">
                            <button
                                onClick={() => setShowTemplates(!showTemplates)}
                                className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                            >
                                <FileTextIcon className="w-4 h-4" />
                                <span>Gunakan Template</span>
                                <ChevronDownIcon className={`w-4 h-4 transition-transform ${showTemplates ? 'rotate-180' : ''}`} />
                            </button>

                            {showTemplates && (
                                <div className="absolute top-full left-0 mt-2 w-full bg-white dark:bg-gray-800 rounded-xl shadow-xl border border-gray-200 dark:border-gray-700 z-50 max-h-60 overflow-hidden">
                                    <div className="flex items-center gap-1 p-2 border-b border-gray-200 dark:border-gray-700 overflow-x-auto">
                                        <button
                                            onClick={() => setSelectedCategory('all')}
                                            className={`px-3 py-1.5 text-xs font-medium rounded-lg whitespace-nowrap transition-colors ${selectedCategory === 'all' ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-600' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
                                        >
                                            Semua
                                        </button>
                                        {Object.entries(TEMPLATE_CATEGORIES).map(([key, { label }]) => (
                                            <button
                                                key={key}
                                                onClick={() => setSelectedCategory(key as MessageTemplate['category'])}
                                                className={`px-3 py-1.5 text-xs font-medium rounded-lg whitespace-nowrap transition-colors ${selectedCategory === key ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-600' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-700'}`}
                                            >
                                                {label}
                                            </button>
                                        ))}
                                    </div>
                                    <div className="max-h-40 overflow-y-auto">
                                        {filteredTemplates.map(template => (
                                            <button
                                                key={template.id}
                                                onClick={() => handleSelectTemplate(template)}
                                                className="w-full text-left p-3 hover:bg-gray-50 dark:hover:bg-gray-700/50 border-b border-gray-100 dark:border-gray-700/50 last:border-0"
                                            >
                                                <span className="font-medium text-sm text-gray-900 dark:text-white">{template.title}</span>
                                                <p className="text-xs text-gray-500 dark:text-gray-400 line-clamp-1 mt-1">{template.message.substring(0, 60)}...</p>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Message Input */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Pesan
                            </label>
                            <textarea
                                value={message}
                                onChange={e => setMessage(e.target.value)}
                                placeholder="Tulis pesan untuk wali murid..."
                                className="w-full h-32 px-4 py-3 text-sm rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 resize-none focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                                disabled={isSending}
                            />
                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                                Gunakan [Nama Siswa] untuk placeholder nama
                            </p>
                        </div>

                        {/* Error Message */}
                        {error && (
                            <div className="flex items-center gap-2 p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg text-red-600 dark:text-red-400 text-sm">
                                <AlertCircleIcon className="w-4 h-4 flex-shrink-0" />
                                <span>{error}</span>
                            </div>
                        )}

                        {/* Actions */}
                        <div className="flex justify-end gap-3 pt-4 border-t border-gray-200 dark:border-gray-700">
                            <Button
                                variant="outline"
                                onClick={handleClose}
                                disabled={isSending}
                            >
                                Batal
                            </Button>
                            <Button
                                onClick={handleSend}
                                disabled={!isOnline || !message.trim() || recipients.length === 0 || isSending}
                                className="bg-gradient-to-r from-blue-600 to-indigo-600"
                            >
                                {isSending ? (
                                    <>
                                        <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2" />
                                        Mengirim...
                                    </>
                                ) : (
                                    <>
                                        <SendIcon className="w-4 h-4 mr-2" />
                                        Kirim ke {recipients.length} Wali
                                    </>
                                )}
                            </Button>
                        </div>
                    </>
                )}
            </div>
        </Modal>
    );
};

export default BulkMessageModal;

import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '../../services/supabase';
import { useAuth } from '../../hooks/useAuth';
import { MessageSquareIcon, UsersIcon, ChevronRightIcon, ClockIcon, InboxIcon } from '../Icons';
import { Button } from '../ui/Button';
import { Skeleton } from '../ui/Skeleton';
import { EmptyState } from '../ui/EmptyState';

interface ParentMessageWithStudent {
    id: string;
    created_at: string;
    message: string;
    sender: 'teacher' | 'parent';
    is_read: boolean;
    student_id: string;
    student_name: string;
    student_avatar: string;
}

const ParentMessagesWidget: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();

    const { data, isLoading } = useQuery({
        queryKey: ['parentMessages', user?.id],
        queryFn: async (): Promise<{ messages: ParentMessageWithStudent[]; unreadCount: number }> => {
            // Fetch recent parent messages with student info
            const { data: communications, error } = await supabase
                .from('communications')
                .select(`
                    id,
                    created_at,
                    message,
                    sender,
                    is_read,
                    student_id,
                    students!inner(name, avatar_url)
                `)
                .eq('user_id', user!.id)
                .eq('sender', 'parent')
                .order('created_at', { ascending: false })
                .limit(5);

            if (error) throw error;

            const messages: ParentMessageWithStudent[] = (communications || []).map((msg: any) => ({
                id: msg.id,
                created_at: msg.created_at,
                message: msg.message,
                sender: msg.sender,
                is_read: msg.is_read,
                student_id: msg.student_id,
                student_name: msg.students?.name || 'Unknown',
                student_avatar: msg.students?.avatar_url || '',
            }));

            // Count unread messages
            const { count } = await supabase
                .from('communications')
                .select('*', { count: 'exact', head: true })
                .eq('user_id', user!.id)
                .eq('sender', 'parent')
                .eq('is_read', false);

            return { messages, unreadCount: count || 0 };
        },
        enabled: !!user,
        refetchInterval: 30000, // Refetch every 30 seconds
    });

    const formatTime = (dateString: string) => {
        const date = new Date(dateString);
        const now = new Date();
        const diffMs = now.getTime() - date.getTime();
        const diffMins = Math.floor(diffMs / 60000);
        const diffHours = Math.floor(diffMs / 3600000);
        const diffDays = Math.floor(diffMs / 86400000);

        if (diffMins < 1) return 'Baru saja';
        if (diffMins < 60) return `${diffMins} menit lalu`;
        if (diffHours < 24) return `${diffHours} jam lalu`;
        if (diffDays < 7) return `${diffDays} hari lalu`;
        return date.toLocaleDateString('id-ID', { day: 'numeric', month: 'short' });
    };

    const handleMessageClick = (studentId: string) => {
        navigate(`/siswa/${studentId}`, { state: { openTab: 'communication' } });
    };

    if (isLoading) {
        return (
            <div className="bg-white dark:bg-slate-900 rounded-xl p-0 overflow-hidden border border-slate-200/60 dark:border-slate-700/60 shadow-sm">
                <div className="p-6 border-b border-slate-200/50 dark:border-white/5">
                    <Skeleton className="h-6 w-48" />
                </div>
                <div className="p-4 space-y-3">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="flex items-center gap-3 p-3">
                            <Skeleton className="w-10 h-10 rounded-full" />
                            <div className="flex-1 space-y-2">
                                <Skeleton className="h-4 w-24" />
                                <Skeleton className="h-3 w-full" />
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    const { messages = [], unreadCount = 0 } = data || {};

    return (
        <div className="bg-white dark:bg-slate-900 rounded-xl p-0 overflow-hidden border border-slate-200/60 dark:border-slate-700/60 shadow-sm">
            {/* Header */}
            <div className="p-4 border-b border-slate-200/60 dark:border-slate-700/60 bg-emerald-500/10">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-lg bg-emerald-500 flex items-center justify-center shadow-sm">
                            <MessageSquareIcon className="w-5 h-5 text-white" />
                        </div>
                        <div>
                            <h3 className="font-bold text-lg text-slate-800 dark:text-white">Pesan Orang Tua</h3>
                            <p className="text-xs text-slate-500 dark:text-slate-400">
                                {unreadCount > 0 ? (
                                    <span className="text-blue-600 dark:text-blue-400 font-medium">
                                        {unreadCount} pesan belum dibaca
                                    </span>
                                ) : (
                                    'Semua pesan telah dibaca'
                                )}
                            </p>
                        </div>
                    </div>
                    {unreadCount > 0 && (
                        <span className="w-6 h-6 bg-red-500 rounded-full text-white text-xs font-bold flex items-center justify-center animate-pulse">
                            {unreadCount > 9 ? '9+' : unreadCount}
                        </span>
                    )}
                </div>
            </div>

            {/* Messages List */}
            <div className="max-h-[320px] overflow-y-auto custom-scrollbar">
                {messages.length === 0 ? (
                    <EmptyState
                        icon={<InboxIcon />}
                        title="Belum ada pesan"
                        description="Pesan dari orang tua akan muncul di sini."
                        actionLabel="Hubungi Orang Tua"
                        onAction={() => navigate('/siswa')}
                    />
                ) : (
                    <ul className="divide-y divide-slate-100 dark:divide-slate-800">
                        {messages.map((msg) => (
                            <li key={msg.id}>
                                <button
                                    onClick={() => handleMessageClick(msg.student_id)}
                                    className="w-full p-4 flex items-start gap-3 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors text-left group"
                                >
                                    {/* Avatar */}
                                    <div className="relative flex-shrink-0">
                                        {msg.student_avatar ? (
                                            <img
                                                src={msg.student_avatar}
                                                alt={msg.student_name}
                                                className="w-10 h-10 rounded-full object-cover border-2 border-white dark:border-slate-800 shadow-sm"
                                            />
                                        ) : (
                                            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-emerald-400 to-emerald-600 flex items-center justify-center text-white font-bold text-sm">
                                                {msg.student_name.charAt(0).toUpperCase()}
                                            </div>
                                        )}
                                        {!msg.is_read && (
                                            <span className="absolute -top-0.5 -right-0.5 w-3 h-3 bg-blue-500 rounded-full border-2 border-white dark:border-slate-900" />
                                        )}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center justify-between gap-2 mb-1">
                                            <span className={`text-sm font-semibold truncate ${!msg.is_read ? 'text-slate-900 dark:text-white' : 'text-slate-600 dark:text-slate-400'}`}>
                                                Wali {msg.student_name}
                                            </span>
                                            <div className="flex items-center gap-1 text-xs text-slate-400 dark:text-slate-500 flex-shrink-0">
                                                <ClockIcon className="w-3 h-3" />
                                                <span>{formatTime(msg.created_at)}</span>
                                            </div>
                                        </div>
                                        <p className={`text-sm line-clamp-2 ${!msg.is_read ? 'text-slate-700 dark:text-slate-300' : 'text-slate-500 dark:text-slate-400'}`}>
