            textColor: 0,
            fontStyle: 'bold',
            lineWidth: 0.1,
            lineColor: [0, 0, 0]
        },
        bodyStyles: {
            lineWidth: 0.1,
            lineColor: [0, 0, 0],
            textColor: 0
        },
        columnStyles: {
            0: { cellWidth: 12, halign: 'center' },
            1: { cellWidth: 70 },
            2: { cellWidth: 20, halign: 'center' },
            3: { cellWidth: 'auto' }
        },
        styles: { fontSize: 10, cellPadding: 3, font: 'helvetica' }
    });

    // Attendance Summary
    let finalY = (doc as any).lastAutoTable.finalY + 10;

