  const handleGenerateAnalysis = async () => {
    setIsLoading(true);
    setLoadingStep(1);
    try {
      const result = await generateComprehensiveChildAnalysis(studentData);
      setAnalysis(result);
      // Save to local storage
      localStorage.setItem(getStorageKey(), JSON.stringify(result));
