const ExtracurricularPage: React.FC = () => {
    const { user } = useAuth();
    const toast = useToast();
    const queryClient = useQueryClient();
    const { activeSemester } = useSemester();

    // State
    const [activeTab, setActiveTab] = useState<TabType>('list');
