                            >
                                {isGeneratingAi ? <span className="animate-spin mr-1">ΓÅ│</span> : <SparklesIcon className="w-3 h-3 mr-1" />}
                                Buat dengan AI
                            </Button>
                        </div>
                        <textarea
                            value={customNote}
                            onChange={(e) => setCustomNote(e.target.value)}
