/**
 * Custom hook for managing extracurricular data
 * Encapsulates all queries and mutations for the extracurricular module
 */
import { useMemo } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { supabase } from '../../../services/supabase';
import { useAuth } from '../../../hooks/useAuth';
import { useSemester } from '../../../contexts/SemesterContext';
import { useToast } from '../../../hooks/useToast';
import {
    Extracurricular,
    ExtracurricularAttendance,
    ExtracurricularGrade,
    Student,
    ExtracurricularStudent,
    EnrollmentView,
    Class,
} from './types';

export interface UseExtracurricularDataOptions {
    selectedExtracurricular: string;
    selectedClassId: string;
    selectedDate: string;
}

export function useExtracurricularData(options: UseExtracurricularDataOptions) {
    const { selectedExtracurricular, selectedClassId, selectedDate } = options;
    const { user } = useAuth();
    const { activeSemester } = useSemester();
    const queryClient = useQueryClient();
    const toast = useToast();

    // ==================== QUERIES ====================

    // Fetch all extracurriculars
    const { data: extracurriculars = [], isLoading: loadingExtracurriculars } = useQuery({
        queryKey: ['extracurriculars', user?.id],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('extracurriculars')
                .select('*')
                .eq('user_id', user!.id)
                .order('name');
            if (error) throw error;
            return data as Extracurricular[];
        },
        enabled: !!user,
    });

    const selectedExtracurricularData = useMemo(() => {
        return extracurriculars.find((e) => e.id === selectedExtracurricular);
    }, [extracurriculars, selectedExtracurricular]);

    // Fetch classes
    const { data: classes = [] } = useQuery({
        queryKey: ['classes', user?.id],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('classes')
                .select('*')
                .eq('user_id', user!.id)
                .is('deleted_at', null)
                .order('name');
            if (error) throw error;
            return data as Class[];
        },
        enabled: !!user,
    });

    const selectedClassName = useMemo(() => {
        if (!selectedClassId) return '';
        return classes.find((c) => c.id === selectedClassId)?.name || '';
    }, [classes, selectedClassId]);

    const normalizedClassName = useMemo(() => {
        if (!selectedClassName) return '';
        return selectedClassName.trim().replace(/\s+/g, ' ').toUpperCase();
    }, [selectedClassName]);

    // Fetch students based on selected class
    const { data: students = [] } = useQuery({
        queryKey: ['students', user?.id, selectedClassId],
        queryFn: async () => {
            let query = supabase
                .from('students')
                .select('*')
                .is('deleted_at', null)
                .eq('user_id', user!.id)
                .order('name');

            if (selectedClassId) {
                query = query.eq('class_id', selectedClassId);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data as Student[];
        },
        enabled: !!user,
    });

    // Fetch extracurricular-only students
    const { data: extracurricularStudents = [] } = useQuery({
        queryKey: ['extracurricular_students', user?.id, normalizedClassName],
        queryFn: async () => {
            let query = supabase
                .from('extracurricular_students')
                .select('*')
                .eq('user_id', user!.id)
                .order('name');

            if (normalizedClassName) {
                query = query.eq('class_name', normalizedClassName);
            }

            const { data, error } = await query;
            if (error) throw error;
            return data as ExtracurricularStudent[];
        },
        enabled: !!user,
    });

    // Fetch ALL extracurricular students (for student list tab)
    const { data: allExtracurricularStudents = [], isLoading: loadingAllExtraStudents } = useQuery({
        queryKey: ['all_extracurricular_students', user?.id],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('extracurricular_students')
                .select('*')
                .eq('user_id', user!.id)
                .order('name');
            if (error) throw error;
            return data as ExtracurricularStudent[];
        },
        enabled: !!user,
    });

    // Fetch enrollments for selected extracurricular
    const { data: enrollments = [] } = useQuery({
        queryKey: ['student_extracurriculars', selectedExtracurricular, activeSemester?.id],
        queryFn: async () => {
            const [studentRes, extraRes] = await Promise.all([
                supabase
                    .from('student_extracurriculars')
                    .select('id, student_id, extracurricular_id, semester_id, students(id, name, class_id, classes(name))')
                    .eq('extracurricular_id', selectedExtracurricular)
                    .eq('semester_id', activeSemester!.id)
                    .not('student_id', 'is', null),
                supabase
                    .from('student_extracurriculars')
                    .select('id, extracurricular_student_id, extracurricular_id, semester_id, extracurricular_students(id, name, class_name)')
                    .eq('extracurricular_id', selectedExtracurricular)
                    .eq('semester_id', activeSemester!.id)
                    .not('extracurricular_student_id', 'is', null),
            ]);

            if (studentRes.error) throw studentRes.error;
            if (extraRes.error) throw extraRes.error;

            const studentEnrollments = (studentRes.data || []).map((row: any): EnrollmentView => ({
                id: row.id,
                participantId: row.student_id,
                participantType: 'student',
                name: row.students?.name || 'Siswa',
                className: row.students?.classes?.name || null,
            }));

            const extraEnrollments = (extraRes.data || []).map((row: any): EnrollmentView => ({
                id: row.id,
                participantId: row.extracurricular_student_id,
                participantType: 'extracurricular_student',
                name: row.extracurricular_students?.name || 'Siswa Ekskul',
                className: row.extracurricular_students?.class_name || null,
            }));

            return [...studentEnrollments, ...extraEnrollments];
        },
        enabled: !!selectedExtracurricular && !!activeSemester,
    });

    // Fetch attendance for selected extracurricular and date
    const { data: attendanceRecords = [] } = useQuery({
        queryKey: ['extracurricular_attendance', selectedExtracurricular, selectedDate],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('extracurricular_attendance')
                .select('*')
                .eq('extracurricular_id', selectedExtracurricular)
                .eq('date', selectedDate);
            if (error) throw error;
            return data as ExtracurricularAttendance[];
        },
        enabled: !!selectedExtracurricular && !!selectedDate,
    });

    // Fetch grades for selected extracurricular
    const { data: grades = [] } = useQuery({
        queryKey: ['extracurricular_grades', selectedExtracurricular, activeSemester?.id],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('extracurricular_grades')
                .select('*')
                .eq('extracurricular_id', selectedExtracurricular)
                .eq('semester_id', activeSemester!.id);
            if (error) throw error;
            return data as ExtracurricularGrade[];
        },
        enabled: !!selectedExtracurricular && !!activeSemester,
    });

    // ==================== DERIVED DATA ====================

    const classNameById = useMemo(() => {
        const map = new Map<string, string>();
        classes.forEach((c: Class) => map.set(c.id, c.name));
        return map;
    }, [classes]);

    const participants = useMemo(() => {
        const baseStudents = students.map((s) => ({
            id: s.id,
            type: 'student' as const,
            name: s.name,
            className: s.class_id ? classNameById.get(s.class_id) || null : null,
        }));

        const extra = extracurricularStudents.map((s) => ({
            id: s.id,
            type: 'extracurricular_student' as const,
            name: s.name,
            className: s.class_name || null,
        }));

        return [...baseStudents, ...extra];
    }, [students, extracurricularStudents, classNameById]);

    const enrolledParticipantIds = useMemo(() => {
        return new Set(enrollments.map((e) => `${e.participantType}:${e.participantId}`));
    }, [enrollments]);

    const attendanceMap = useMemo(() => {
        const map: Record<string, string> = {};
        attendanceRecords.forEach((a) => {
            const key = a.student_id
                ? `student:${a.student_id}`
                : a.extracurricular_student_id
                    ? `extracurricular_student:${a.extracurricular_student_id}`
                    : '';
            if (key) map[key] = a.status;
        });
        return map;
    }, [attendanceRecords]);

    const gradesMap = useMemo(() => {
        const map: Record<string, ExtracurricularGrade> = {};
        grades.forEach((g: ExtracurricularGrade) => {
            const key = g.student_id
                ? `student:${g.student_id}`
                : g.extracurricular_student_id
                    ? `extracurricular_student:${g.extracurricular_student_id}`
                    : '';
            if (key) map[key] = g;
        });
        return map;
    }, [grades]);

    const uniqueExtraStudentClasses = useMemo(() => {
        const classSet = new Set<string>();
        allExtracurricularStudents.forEach((s) => {
            if (s.class_name) classSet.add(s.class_name);
        });
        return Array.from(classSet).sort();
    }, [allExtracurricularStudents]);

    return {
        // Loading states
        loadingExtracurriculars,
        loadingAllExtraStudents,

        // Core data
        extracurriculars,
        selectedExtracurricularData,
        classes,
        students,
        extracurricularStudents,
        allExtracurricularStudents,
        enrollments,
        attendanceRecords,
        grades,
        activeSemester,

        // Derived/computed data
        participants,
        enrolledParticipantIds,
        attendanceMap,
        gradesMap,
        uniqueExtraStudentClasses,
        classNameById,

        // Query client for invalidation
        queryClient,
        toast,
        user,
    };
}

export function normalizeClassName(value: string) {
    return value.trim().replace(/\s+/g, ' ').toUpperCase();
}

import React from 'react';
import { Button } from '../../../ui/Button';
import { XCircleIcon, DownloadIcon, BarChartIcon } from '../../../Icons';
import { InputMode, ViolationRow } from '../types';
import { exportGradesToExcel } from '../../../../utils/gradeExporter';
import { DropdownMenu, DropdownTrigger, DropdownContent, DropdownItem } from '../../../ui/DropdownMenu';
import { FileTextIcon, FileSpreadsheetIcon } from 'lucide-react';
import { exportViolationsToPDF, exportViolationsToExcel } from '../../../../services/violationExport';
import { useAuth } from '../../../../hooks/useAuth';
import { useToast } from '../../../../hooks/useToast';

interface Step2_FooterProps {
    summaryText: string;
    mode: InputMode | null;
    selectedStudentIds: Set<string>;
    gradedCount: number;
    setScores: (scores: Record<string, string>) => void;
    setSelectedStudentIds: (ids: Set<string>) => void;
    isExporting: boolean;
    exportProgress: string;
    handleSubmit: () => void;
    isSubmitDisabled: boolean;
    submitButtonTooltip: string;
    isSubmitting: boolean;
    isDeleting: boolean;
    // New props for export
    scores?: Record<string, string>;
    students?: { id: string; name: string }[];
    subjectGradeInfo?: { subject: string; assessment_name: string };
    className?: string;
    existingViolations?: any[];
    onShowChart?: () => void;
}

export const Step2_Footer: React.FC<Step2_FooterProps> = ({
    summaryText, mode, selectedStudentIds, gradedCount, setScores, setSelectedStudentIds,
    isExporting, exportProgress, handleSubmit, isSubmitDisabled, submitButtonTooltip,
    isSubmitting, isDeleting,
    scores, students, subjectGradeInfo, className, existingViolations, onShowChart
}) => {
    const handleExportExcel = async () => {
        if (!scores || !students) return;

        const data = students.map(s => ({
            studentName: s.name,
            studentId: s.id,
            score: scores[s.id] || '',
        }));

        try {
            await exportGradesToExcel(data, {
                filename: `nilai_${subjectGradeInfo?.subject || 'mapel'}_${subjectGradeInfo?.assessment_name || 'penilaian'}.xlsx`,
                subject: subjectGradeInfo?.subject,
                assessmentName: subjectGradeInfo?.assessment_name,
                className: className,
                includeStats: true,
            });
        } catch (error) {
            toast.error(error instanceof Error ? error.message : 'Gagal export nilai.');
        }
    };

    const { user } = useAuth();
    const toast = useToast();

    const handleViolationExport = async (type: 'pdf' | 'excel') => {
        if (!existingViolations || !students) return;

        const options = {
            studentName: 'Semua Siswa',
            className: className || 'Kelas',
            schoolName: user?.school_name || 'Sekolah',
            violations: existingViolations as ViolationRow[]
        };

        if (type === 'pdf') {
            await exportViolationsToPDF(options);
            toast.success('Mengunduh Laporan Pelanggaran (PDF)...');
        } else {
            await exportViolationsToExcel(options);
            toast.success('Mengunduh Laporan Pelanggaran (Excel)...');
        }
    };

    return (
        <footer className="sticky bottom-4 sm:bottom-6 md:bottom-8 z-30 animate-fade-in-up">
            <div className="bg-white/90 dark:bg-gray-900/80 backdrop-blur-xl border border-slate-200 dark:border-white/10 rounded-2xl p-4 flex flex-col sm:flex-row justify-between items-center gap-4 shadow-2xl shadow-black/10 dark:shadow-black/50 mx-auto max-w-4xl ring-1 ring-slate-200 dark:ring-white/10">
                <div className="flex items-center gap-4">
                    <div className="px-4 py-2 rounded-xl bg-slate-100 dark:bg-white/5 border border-slate-200 dark:border-white/10">
                        <p className="text-sm font-medium text-green-700 dark:text-green-200">{summaryText}</p>
                    </div>
                    {(mode !== 'subject_grade' && selectedStudentIds.size > 0) || (mode === 'subject_grade' && gradedCount > 0) ? (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => mode === 'subject_grade' ? setScores({}) : setSelectedStudentIds(new Set())}
                            className="text-gray-400 hover:text-red-600 dark:hover:text-white hover:bg-red-50 dark:hover:bg-white/10 transition-colors"
                        >
                            <XCircleIcon className="w-4 h-4 mr-1" /> Bersihkan
                        </Button>
                    ) : null}
                </div>

                <div className="flex items-center gap-2">
                    {/* Chart Button */}
                    {mode === 'subject_grade' && onShowChart && gradedCount > 0 && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={onShowChart}
                            className="text-green-400 hover:text-green-300 hover:bg-green-500/10"
                        >
                            <BarChartIcon className="w-4 h-4 mr-1" />
                            Chart
                        </Button>
                    )}

                    {/* Export Button */}
                    {mode === 'subject_grade' && scores && students && gradedCount > 0 && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={handleExportExcel}
                            className="text-emerald-400 hover:text-emerald-300 hover:bg-emerald-500/10"
                        >
                            <DownloadIcon className="w-4 h-4 mr-1" />
                            Export
                        </Button>
                    )}

                    {/* Violation Export Button */}
                    {mode === 'violation' && existingViolations && existingViolations.length > 0 && (
                        <DropdownMenu>
                            <DropdownTrigger className="relative inline-flex items-center gap-2 bg-gradient-to-r from-orange-500/10 to-amber-500/10 border border-orange-500/30 text-orange-500 dark:text-orange-400 hover:from-orange-500/20 hover:to-amber-500/20 hover:border-orange-500/50 transition-all duration-300 text-sm px-3 py-1.5 rounded-lg font-medium">

                                <DownloadIcon className="w-4 h-4" />
                                <span>Export Data</span>
                                <span className="absolute -top-2 -right-2 flex items-center justify-center min-w-[20px] h-5 px-1.5 text-[10px] font-bold rounded-full bg-orange-500 text-white shadow-lg shadow-orange-500/30">
                                    {existingViolations.length}
                                </span>

                            </DropdownTrigger>
                            <DropdownContent className="min-w-[180px]">
                                <div className="px-3 py-2 border-b border-gray-200 dark:border-gray-700">
                                    <p className="text-xs font-medium text-gray-500 dark:text-gray-400">Export {existingViolations.length} pelanggaran</p>
                                </div>
                                <DropdownItem
                                    onClick={() => handleViolationExport('pdf')}
                                    icon={<FileTextIcon className="w-4 h-4 text-red-500" />}
                                    className="gap-3"
                                >
                                    <div>
                                        <p className="font-medium">PDF (Formal)</p>
                                        <p className="text-xs text-gray-500 dark:text-gray-400">Laporan formal dengan kop</p>
                                    </div>
                                </DropdownItem>
                                <DropdownItem
                                    onClick={() => handleViolationExport('excel')}
                                    icon={<FileSpreadsheetIcon className="w-4 h-4 text-green-600" />}
                                    className="gap-3"
                                >
                                    <div>
                                        <p className="font-medium">Excel</p>
                                        <p className="text-xs text-gray-500 dark:text-gray-400">Data terstruktur untuk analisis</p>
                                    </div>
                                </DropdownItem>
                            </DropdownContent>
                        </DropdownMenu>
                    )}

                    {isExporting ? (
                        <div className="w-full sm:w-64 text-center">
                            <div className="relative pt-1">
                                <div className="overflow-hidden h-2 mb-2 text-xs flex rounded-full bg-white/10">
                                    <div style={{ width: exportProgress }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-gradient-to-r from-green-500 to-emerald-500 transition-all duration-500 relative">
                                        <div className="absolute inset-0 bg-white/20 animate-pulse"></div>
                                    </div>
                                </div>
                                <p className="text-xs font-bold text-green-300 animate-pulse">{exportProgress} - Memproses...</p>
                            </div>
                        </div>
                    ) : (
                        <Button
                            onClick={handleSubmit}
                            disabled={isSubmitDisabled}
                            title={submitButtonTooltip}
                            className={`
                                w-full sm:w-auto font-bold tracking-wide shadow-lg transition-all duration-300 transform hover:-translate-y-1
                                ${mode === 'delete_subject_grade'
                                    ? 'bg-gradient-to-r from-rose-600 to-red-600 hover:from-rose-500 hover:to-red-500 shadow-rose-900/20'
                                    : 'bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-500 hover:to-emerald-500 shadow-green-900/20'
                                }
                            `}
                        >
                            {isSubmitting || isDeleting ? (
                                <span className="flex items-center gap-2">
                                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                    Memproses...
                                </span>
                            ) : mode === 'delete_subject_grade' ? 'Hapus Nilai Terpilih' : (mode?.includes('print') || mode?.includes('report')) ? 'Cetak Laporan' : 'Simpan Data'}
                        </Button>
                    )}
                </div>
            </div>
        </footer >
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Button } from '../../../ui/Button';
import { Select } from '../../../ui/Select';
import { DownloadIcon, FileTextIcon, FileSpreadsheetIcon, ShieldAlertIcon, UsersIcon, SearchIcon, SparklesIcon } from '../../../Icons';
import { ClassRow, ViolationRow, StudentRow, StudentFilter } from '../types';
import { exportBulkViolationsToExcel } from '../../../../services/violationExport';
import { useToast } from '../../../../hooks/useToast';
import { SemesterSelector } from '../../../ui/SemesterSelector';
import { useUserSettings } from '../../../../hooks/useUserSettings';
import { useSemester } from '../../../../contexts/SemesterContext';
import { Checkbox } from '../../../ui/Checkbox';

interface ViolationExportPanelProps {
    classes: ClassRow[] | undefined;
    selectedClass: string;
    setSelectedClass: (id: string) => void;
    isLoadingClasses: boolean;
    existingViolations: ViolationRow[] | undefined;
    studentsData: StudentRow[] | undefined;
    isLoadingViolations: boolean;
}

const StudentAvatar: React.FC<{ name: string; avatarUrl: string | null | undefined }> = ({ name, avatarUrl }) => {
    const [imgError, setImgError] = useState(false);
    const showFallback = !avatarUrl || imgError;

    return showFallback ? (
        <div className="w-9 h-9 rounded-full bg-gradient-to-br from-purple-400 to-pink-500 flex items-center justify-center text-white font-bold text-sm shrink-0">
            {name.charAt(0).toUpperCase()}
        </div>
    ) : (
        <img src={avatarUrl} alt={name} className="w-9 h-9 rounded-full object-cover shrink-0" onError={() => setImgError(true)} />
    );
};

export const ViolationExportPanel: React.FC<ViolationExportPanelProps> = ({
    classes,
    selectedClass,
    setSelectedClass,
    isLoadingClasses,
    existingViolations,
    studentsData,
    isLoadingViolations
}) => {
    const toast = useToast();
    const { activeSemester } = useSemester();
    const [semesterFilter, setSemesterFilter] = useState<string>(() => activeSemester?.id || 'all');
    const { schoolName } = useUserSettings();

    const effectiveSemesterFilter = semesterFilter === 'all' && activeSemester?.id ? activeSemester.id : semesterFilter;

    const [searchTerm, setSearchTerm] = useState('');
    const [selectedStudentIds, setSelectedStudentIds] = useState<Set<string>>(new Set());
    const [studentFilter, setStudentFilter] = useState<StudentFilter>('all');

    const className = classes?.find(c => c.id === selectedClass)?.name || 'Kelas';

    useEffect(() => {
        setTimeout(() => setSelectedStudentIds(new Set()), 0);
    }, [studentsData, selectedClass]);

    const filteredStudents = useMemo(() => {
        if (!studentsData) return [];
        let result = studentsData;
        if (searchTerm) {
            result = result.filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()));
        }
        if (studentFilter === 'selected') {
            result = result.filter(s => selectedStudentIds.has(s.id));
        } else if (studentFilter === 'unselected') {
            result = result.filter(s => !selectedStudentIds.has(s.id));
        }
        return result;
    }, [studentsData, searchTerm, studentFilter, selectedStudentIds]);

    const isAllSelected = filteredStudents.length > 0 && filteredStudents.every(s => selectedStudentIds.has(s.id));

    const handleSelectAll = (checked: boolean) => {
        setSelectedStudentIds(prev => {
            const next = new Set(prev);
            filteredStudents.forEach(s => {
                if (checked) next.add(s.id);
                else next.delete(s.id);
            });
            return next;
        });
    };

    const handleToggleStudent = (studentId: string) => {
        setSelectedStudentIds(prev => {
            const next = new Set(prev);
            if (next.has(studentId)) next.delete(studentId);
            else next.add(studentId);
            return next;
        });
    };

    const filteredViolations = useMemo(() => {
        let bySemester = existingViolations || [];
        if (effectiveSemesterFilter !== 'all') {
            bySemester = bySemester.filter(v => v.semester_id === effectiveSemesterFilter);
        }
        if (selectedStudentIds.size === 0) return bySemester;
        return bySemester.filter(v => selectedStudentIds.has(v.student_id));
    }, [existingViolations, effectiveSemesterFilter, selectedStudentIds]);

    const violationCount = filteredViolations.length;
    const totalPoints = filteredViolations.reduce((sum, v) => sum + v.points, 0);
    const uniqueStudentsWithViolations = new Set(filteredViolations.map(v => v.student_id)).size;

    const handleExport = async (type: 'pdf' | 'excel') => {
        if (selectedStudentIds.size === 0) {
            toast.warning('Pilih setidaknya satu siswa untuk diekspor.');
            return;
        }
        if (filteredViolations.length === 0 || !studentsData) {
            toast.warning('Tidak ada data pelanggaran untuk diekspor.');
            return;
        }

        const selectedStudents = studentsData.filter(s => selectedStudentIds.has(s.id));

        if (type === 'pdf') {
            // Export each student to a separate PDF file
            const { exportViolationsToPDF } = await import('../../../../services/violationExport');
            
            for (const student of selectedStudents) {
                const studentViolations = filteredViolations.filter(v => v.student_id === student.id);
                
                if (studentViolations.length === 0) continue;
                
                // Type assertion: mass-input ViolationRow is compatible with student ViolationRow
                await exportViolationsToPDF({
                    studentName: student.name,
                    className: className,
                    schoolName: schoolName,
                    violations: studentViolations as any
                });
                
                // Small delay between downloads to prevent browser blocking
                await new Promise(resolve => setTimeout(resolve, 300));
            }
            
            toast.success(`${selectedStudents.length} file PDF rapor pelanggaran berhasil diunduh!`);
        } else {
            // Excel: still use bulk export as one file
            const options = {
                className: className,
                schoolName: schoolName,
                violations: filteredViolations as any,
                students: selectedStudents.map(s => ({
                    id: s.id,
                    name: s.name,
                    gender: s.gender,
                    avatar_url: s.avatar_url
                }))
            };
            
            toast.info('Memproses export Excel...');
            await exportBulkViolationsToExcel(options);
            toast.success('Rekap Pelanggaran (Excel) berhasil diunduh!');
        }
    };

    const filterTabs: { value: StudentFilter; label: string }[] = [
        { value: 'all', label: 'Semua' },
        { value: 'selected', label: 'Terpilih' },
        { value: 'unselected', label: 'Belum Dipilih' },
    ];

    return (
        <div className="lg:col-span-3 animate-fade-in-up">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Left Column: Configuration */}
                <div className="lg:col-span-1 space-y-6">
                    <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-700 p-5 shadow-lg">
                        <h3 className="font-bold text-lg mb-4 text-slate-900 dark:text-white flex items-center gap-2">
                            <SparklesIcon className="w-5 h-5 text-indigo-500" />
                            Konfigurasi
                        </h3>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-semibold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-2">Kelas</label>
                                <Select
                                    value={selectedClass}
                                    onChange={e => setSelectedClass(e.target.value)}
                                    disabled={isLoadingClasses}
                                    className="h-11 bg-slate-100 dark:bg-white/5 border-slate-200 dark:border-white/10 text-slate-900 dark:text-white rounded-xl"
                                >
                                    {classes?.map(c => <option key={c.id} value={c.id} className="text-slate-900">{c.name}</option>)}
                                </Select>
                            </div>

                            <div>
                                <label className="block text-xs font-semibold uppercase tracking-wider text-slate-500 dark:text-slate-400 mb-2">Filter Semester</label>
                                <SemesterSelector value={semesterFilter} onChange={setSemesterFilter} showIcon={true} />
                            </div>
                        </div>
                    </div>

                    {/* Stats Card */}
                    <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-700 p-5 shadow-lg">
                        <h3 className="font-bold text-lg mb-4 text-slate-900 dark:text-white flex items-center gap-2">
                            <ShieldAlertIcon className="w-5 h-5 text-orange-500" />
                            Statistik
                        </h3>
                        <div className="grid grid-cols-2 gap-3">
                            <div className="p-3 rounded-xl bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800/30 text-center">
                                <p className="text-2xl font-bold text-orange-600 dark:text-orange-400">{violationCount}</p>
                                <p className="text-xs text-orange-500">Pelanggaran</p>
                            </div>
                            <div className="p-3 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800/30 text-center">
                                <p className="text-2xl font-bold text-red-600 dark:text-red-400">{totalPoints}</p>
                                <p className="text-xs text-red-500">Total Poin</p>
                            </div>
                            <div className="p-3 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800/30 text-center">
                                <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">{uniqueStudentsWithViolations}</p>
                                <p className="text-xs text-blue-500">Siswa Melanggar</p>
                            </div>
                            <div className="p-3 rounded-xl bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 text-center">
                                <p className="text-2xl font-bold text-slate-600 dark:text-slate-400">{selectedStudentIds.size}</p>
                                <p className="text-xs text-slate-500">Dipilih</p>
                            </div>
                        </div>
                    </div>

                    {/* Export Card */}
                    {selectedStudentIds.size > 0 && (
                        <div className="bg-gradient-to-br from-indigo-600 to-purple-600 rounded-2xl p-5 shadow-lg text-white">
                            <h3 className="font-bold text-lg mb-2 flex items-center gap-2">
                                <DownloadIcon className="w-5 h-5" />
                                Export
                            </h3>
                            <div className="grid grid-cols-2 gap-3 mt-4">
                                <Button onClick={() => handleExport('pdf')} className="h-12 bg-indigo-600 hover:bg-indigo-700 border-none text-white rounded-xl font-bold">
                                    <FileTextIcon className="w-5 h-5 mr-2" /> PDF
                                </Button>
                                <Button onClick={() => handleExport('excel')} className="h-12 bg-blue-600 hover:bg-blue-700 border-none text-white rounded-xl font-bold">
                                    <FileSpreadsheetIcon className="w-5 h-5 mr-2" /> Excel
                                </Button>
                            </div>
                        </div>
                    )}
                </div>

                {/* Right Column: Student List */}
                <div className="lg:col-span-2 bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-lg flex flex-col overflow-hidden">
                    {/* Search & Filter Tabs */}
                    <div className="p-4 border-b border-slate-200 dark:border-slate-800">
                        <div className="relative mb-3">
                            <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                            <input
                                type="text"
                                placeholder="Cari nama siswa..."
                                value={searchTerm}
                                onChange={e => setSearchTerm(e.target.value)}
                                className="w-full h-10 pl-10 pr-4 rounded-lg bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-sm text-slate-900 dark:text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                        </div>
                        <div className="flex gap-2">
                            {filterTabs.map(tab => (
                                <button
                                    key={tab.value}
                                    onClick={() => setStudentFilter(tab.value)}
                                    className={`px-4 py-1.5 rounded-lg text-sm font-medium transition-colors ${studentFilter === tab.value ? 'bg-indigo-600 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
                                >
                                    {tab.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Table Header */}
                    <div className="grid grid-cols-12 gap-4 px-4 py-3 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 text-xs font-semibold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                        <div className="col-span-1 flex items-center">
                            <Checkbox checked={isAllSelected} onChange={e => handleSelectAll(e.target.checked)} />
                        </div>
                        <div className="col-span-7">Nama Siswa</div>
                        <div className="col-span-4 text-right">Status</div>
                    </div>

                    {/* Table Body */}
                    <div className="flex-grow overflow-y-auto divide-y divide-slate-100 dark:divide-slate-800">
                        {isLoadingViolations ? (
                            <div className="p-8 text-center text-sm text-gray-500">Memuat data...</div>
                        ) : filteredStudents.length === 0 ? (
                            <div className="p-8 text-center text-sm text-gray-500">Tidak ada siswa ditemukan.</div>
                        ) : (
                            filteredStudents.map(student => (
                                <div key={student.id} className="grid grid-cols-12 gap-4 items-center px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                    <div className="col-span-1 flex items-center">
                                        <Checkbox checked={selectedStudentIds.has(student.id)} onChange={() => handleToggleStudent(student.id)} />
                                    </div>
                                    <div className="col-span-7 flex items-center gap-3">
                                        <StudentAvatar name={student.name} avatarUrl={student.avatar_url} />
                                        <span className="font-medium text-slate-800 dark:text-white uppercase text-sm">{student.name}</span>
                                    </div>
                                    <div className="col-span-4 text-right">
                                        <span className={`text-xs italic ${selectedStudentIds.has(student.id) ? 'text-emerald-500' : 'text-slate-400'}`}>
                                            {selectedStudentIds.has(student.id) ? 'Dipilih' : 'Belum dipilih'}
                                        </span>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useMemo, useState } from 'react';
import { CardTitle, CardDescription } from '../../ui/Card';
import { Button } from '../../ui/Button';
import { PlusIcon, BookOpenIcon, PencilIcon, TrashIcon, FilterIcon, SearchIcon, TagIcon, CalendarIcon, FileTextIcon, ImageIcon, XIcon } from 'lucide-react';
import { ReportRow } from './types';

// Report Categories
export const REPORT_CATEGORIES = {
    akademik: { label: 'Akademik', color: 'blue', icon: '≡ƒôÜ', description: 'Catatan terkait pembelajaran & nilai' },
    perilaku: { label: 'Perilaku', color: 'orange', icon: '≡ƒæñ', description: 'Catatan sikap & perilaku siswa' },
    kesehatan: { label: 'Kesehatan', color: 'green', icon: '≡ƒÅÑ', description: 'Catatan kondisi kesehatan' },
    prestasi: { label: 'Prestasi', color: 'purple', icon: '≡ƒÅå', description: 'Pencapaian & prestasi siswa' },
    lainnya: { label: 'Lainnya', color: 'gray', icon: '≡ƒô¥', description: 'Catatan umum lainnya' },
} as const;

export type ReportCategory = keyof typeof REPORT_CATEGORIES;

// Common tags for quick selection
export const COMMON_TAGS = [
    'penting', 'mendesak', 'positif', 'perlu-perhatian', 'follow-up',
    'diskusi-ortu', 'bimbingan', 'konseling', 'remedial', 'pengayaan'
];

interface ReportsTabProps {
    reports: ReportRow[];
    onAdd: () => void;
    onEdit: (record: ReportRow) => void;
    onDelete: (id: string) => void;
    isOnline: boolean;
}

// Stats Summary
const ReportsStats: React.FC<{ reports: ReportRow[] }> = ({ reports }) => {
    const stats = useMemo(() => {
        const byCategory = Object.keys(REPORT_CATEGORIES).reduce((acc, cat) => {
            acc[cat] = reports.filter(r => r.category === cat).length;
            return acc;
        }, {} as Record<string, number>);

        const withAttachment = reports.filter(r => r.attachment_url).length;
        const thisMonth = reports.filter(r => {
            const reportDate = new Date(r.date);
            const now = new Date();
            return reportDate.getMonth() === now.getMonth() && reportDate.getFullYear() === now.getFullYear();
        }).length;

        return { total: reports.length, byCategory, withAttachment, thisMonth };
    }, [reports]);

    return (
        <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-6 gap-3 mb-6">
            <div className="p-3 rounded-xl bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800/30">
                <p className="text-2xl font-bold text-indigo-600 dark:text-indigo-400">{stats.total}</p>
                <p className="text-xs text-indigo-500">Total Catatan</p>
            </div>
            <div className="p-3 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800/30">
                <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">{stats.byCategory.akademik || 0}</p>
                <p className="text-xs text-blue-500">≡ƒôÜ Akademik</p>
            </div>
            <div className="p-3 rounded-xl bg-orange-50 dark:bg-orange-900/20 border border-orange-100 dark:border-orange-800/30">
                <p className="text-2xl font-bold text-orange-600 dark:text-orange-400">{stats.byCategory.perilaku || 0}</p>
                <p className="text-xs text-orange-500">≡ƒæñ Perilaku</p>
            </div>
            <div className="p-3 rounded-xl bg-purple-50 dark:bg-purple-900/20 border border-purple-100 dark:border-purple-800/30">
                <p className="text-2xl font-bold text-purple-600 dark:text-purple-400">{stats.byCategory.prestasi || 0}</p>
                <p className="text-xs text-purple-500">≡ƒÅå Prestasi</p>
            </div>
            <div className="p-3 rounded-xl bg-green-50 dark:bg-green-900/20 border border-green-100 dark:border-green-800/30">
                <p className="text-2xl font-bold text-green-600 dark:text-green-400">{stats.thisMonth}</p>
                <p className="text-xs text-green-500">Bulan Ini</p>
            </div>
            <div className="p-3 rounded-xl bg-cyan-50 dark:bg-cyan-900/20 border border-cyan-100 dark:border-cyan-800/30">
                <p className="text-2xl font-bold text-cyan-600 dark:text-cyan-400">{stats.withAttachment}</p>
                <p className="text-xs text-cyan-500">≡ƒôÄ Lampiran</p>
            </div>
        </div>
    );
};

// Timeline View Component
const TimelineView: React.FC<{
    reports: ReportRow[];
    onEdit: (r: ReportRow) => void;
    onDelete: (id: string) => void;
    isOnline: boolean;
}> = ({ reports, onEdit, onDelete, isOnline }) => {
    // Group reports by month/year
    const groupedReports = useMemo(() => {
        const groups: Record<string, ReportRow[]> = {};

        [...reports]
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
            .forEach(report => {
                const date = new Date(report.date);
                const key = `${date.toLocaleString('id-ID', { month: 'long' })} ${date.getFullYear()}`;
                if (!groups[key]) groups[key] = [];
                groups[key].push(report);
            });

        return groups;
    }, [reports]);

    const monthKeys = Object.keys(groupedReports);

    if (reports.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-16 text-center">
                <div className="w-16 h-16 rounded-2xl bg-slate-100 dark:bg-slate-800/50 flex items-center justify-center mb-4">
                    <BookOpenIcon className="w-8 h-8 text-slate-400 dark:text-slate-600" />
                </div>
                <h4 className="text-lg font-semibold text-slate-900 dark:text-white">Tidak Ada Catatan</h4>
                <p className="text-sm text-slate-500 dark:text-slate-400">Belum ada catatan guru untuk siswa ini.</p>
            </div>
        );
    }

    return (
        <div className="relative">
            {/* Timeline line */}
            <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-gradient-to-b from-indigo-500 via-purple-500 to-pink-500" />

            {monthKeys.map((monthKey, groupIndex) => (
                <div key={monthKey} className="mb-8">
                    {/* Month header */}
                    <div className="flex items-center gap-3 mb-4 relative">
                        <div className="w-12 h-12 rounded-full bg-indigo-600 flex items-center justify-center z-10">
                            <CalendarIcon className="w-5 h-5 text-white" />
                        </div>
                        <h3 className="text-lg font-bold text-gray-800 dark:text-white">{monthKey}</h3>
                        <span className="text-sm text-gray-400">({groupedReports[monthKey].length} catatan)</span>
                    </div>

                    {/* Reports in this month */}
                    <div className="ml-6 space-y-4">
                        {groupedReports[monthKey].map((report, index) => {
                            const category = report.category ? REPORT_CATEGORIES[report.category] : null;
                            const categoryColor = category?.color || 'gray';

                            return (
                                <div
                                    key={report.id}
                                    className="group relative pl-8 pb-4 border-l-2 border-gray-200 dark:border-gray-700 last:border-l-0"
                                >
                                    {/* Timeline dot */}
                                    <div className={`absolute left-[-5px] top-0 w-3 h-3 rounded-full bg-${categoryColor}-500 ring-4 ring-white dark:ring-gray-900`} />

                                    {/* Card */}
                                    <div className={`relative p-4 rounded-xl bg-gradient-to-r from-${categoryColor}-50/50 to-transparent dark:from-${categoryColor}-900/10 border border-${categoryColor}-100 dark:border-${categoryColor}-800/30 hover:shadow-lg transition-shadow`}>
                                        {/* Actions */}
                                        <div className="absolute top-3 right-3 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => onEdit(report)} disabled={!isOnline}>
                                                <PencilIcon className="h-4 w-4" />
                                            </Button>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 text-red-600 dark:text-red-400" onClick={() => onDelete(report.id)} disabled={!isOnline}>
                                                <TrashIcon className="h-4 w-4" />
                                            </Button>
                                        </div>

                                        {/* Header */}
                                        <div className="flex items-start gap-3 mb-2">
                                            {category && (
                                                <span className={`px-2 py-1 rounded-full text-xs font-medium bg-${categoryColor}-100 dark:bg-${categoryColor}-900/30 text-${categoryColor}-700 dark:text-${categoryColor}-400`}>
                                                    {category.icon} {category.label}
                                                </span>
                                            )}
                                            <span className="text-xs text-gray-400">
                                                {new Date(report.date).toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'short' })}
                                            </span>
                                        </div>

                                        {/* Title */}
                                        <h4 className="font-bold text-gray-900 dark:text-white text-lg mb-2">{report.title}</h4>

                                        {/* Notes */}
                                        <p className="text-sm text-gray-600 dark:text-gray-300 whitespace-pre-line">{report.notes}</p>

                                        {/* Tags */}
                                        {report.tags && report.tags.length > 0 && (
                                            <div className="flex flex-wrap gap-1 mt-3">
                                                {report.tags.map(tag => (
                                                    <span
                                                        key={tag}
                                                        className="px-2 py-0.5 rounded-full text-xs bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400"
                                                    >
                                                        #{tag}
                                                    </span>
                                                ))}
                                            </div>
                                        )}

                                        {/* Attachment */}
                                        {report.attachment_url && (
                                            <div className="mt-3 pt-3 border-t border-gray-200 dark:border-gray-700">
                                                {report.attachment_url.match(/\.(jpg|jpeg|png|gif|webp)$/i) ? (
                                                    <a
                                                        href={report.attachment_url}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="block"
                                                    >
                                                        <img
                                                            src={report.attachment_url}
                                                            alt="Attachment"
                                                            className="max-h-40 rounded-lg object-cover hover:opacity-90 transition-opacity"
                                                        />
                                                    </a>
                                                ) : (
                                                    <a
                                                        href={report.attachment_url}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="inline-flex items-center gap-2 px-3 py-2 rounded-lg bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700 text-sm transition-colors"
                                                    >
                                                        <FileTextIcon className="w-4 h-4" />
                                                        <span>Lihat Lampiran</span>
                                                    </a>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            ))}
        </div>
    );
};

// Filter Types
type CategoryFilter = ReportCategory | 'all';
type ViewMode = 'timeline' | 'list';

export const ReportsTab: React.FC<ReportsTabProps> = ({ reports, onAdd, onEdit, onDelete, isOnline }) => {
    const [searchQuery, setSearchQuery] = useState('');
    const [categoryFilter, setCategoryFilter] = useState<CategoryFilter>('all');
    const [tagFilter, setTagFilter] = useState<string | null>(null);
    const [viewMode, setViewMode] = useState<ViewMode>('timeline');

    // Get all unique tags from reports
    const allTags = useMemo(() => {
        const tags = new Set<string>();
        reports.forEach(r => r.tags?.forEach(t => tags.add(t)));
        return Array.from(tags);
    }, [reports]);

    // Filter reports
    const filteredReports = useMemo(() => {
        return reports.filter(r => {
            // Category filter
            if (categoryFilter !== 'all' && r.category !== categoryFilter) return false;

            // Tag filter
            if (tagFilter && !r.tags?.includes(tagFilter)) return false;

            // Search filter
            if (searchQuery) {
                const query = searchQuery.toLowerCase();
                const matchesTitle = r.title.toLowerCase().includes(query);
                const matchesNotes = r.notes.toLowerCase().includes(query);
                const matchesTags = r.tags?.some(t => t.toLowerCase().includes(query));
                if (!matchesTitle && !matchesNotes && !matchesTags) return false;
            }

            return true;
        });
    }, [reports, categoryFilter, tagFilter, searchQuery]);

    const clearFilters = () => {
        setSearchQuery('');
        setCategoryFilter('all');
        setTagFilter(null);
    };

    const hasActiveFilters = searchQuery || categoryFilter !== 'all' || tagFilter;

    return (
        <div className="p-4 sm:p-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-4">
                <div>
                    <CardTitle>Catatan Guru</CardTitle>
                    <CardDescription>Catatan perkembangan, laporan, atau insiden khusus.</CardDescription>
                </div>
                <Button onClick={onAdd} disabled={!isOnline}>
                    <PlusIcon className="w-4 h-4 mr-2" />Tambah Catatan
                </Button>
            </div>

            {/* Stats */}
            <ReportsStats reports={reports} />

            {/* Search & Filters */}
            <div className="flex flex-wrap items-center gap-3 mb-6 p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl">
                {/* Search */}
                <div className="relative flex-1 min-w-[200px]">
                    <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                    <input
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Cari catatan..."
                        className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder:text-gray-400 focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    />
                </div>

                {/* Category Filter */}
                <select
                    value={categoryFilter}
                    onChange={(e) => setCategoryFilter(e.target.value as CategoryFilter)}
                    className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 text-sm"
                >
                    <option value="all">Semua Kategori</option>
                    {Object.entries(REPORT_CATEGORIES).map(([key, cat]) => (
                        <option key={key} value={key}>{cat.icon} {cat.label}</option>
                    ))}
                </select>

                {/* Tag Filter */}
                {allTags.length > 0 && (
                    <select
                        value={tagFilter || ''}
                        onChange={(e) => setTagFilter(e.target.value || null)}
                        className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 text-sm"
                    >
                        <option value="">Semua Tag</option>
                        {allTags.map(tag => (
                            <option key={tag} value={tag}>#{tag}</option>
                        ))}
                    </select>
                )}

                {/* View Mode Toggle */}
                <div className="flex rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
                    <button
                        onClick={() => setViewMode('timeline')}
                        className={`px-3 py-2 text-sm ${viewMode === 'timeline' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400'}`}
                    >
                        Timeline
                    </button>
                    <button
                        onClick={() => setViewMode('list')}
                        className={`px-3 py-2 text-sm ${viewMode === 'list' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400'}`}
                    >
                        List
                    </button>
                </div>

                {/* Clear Filters */}
                {hasActiveFilters && (
                    <button
                        onClick={clearFilters}
                        className="px-3 py-2 text-sm text-indigo-600 dark:text-indigo-400 hover:underline flex items-center gap-1"
                    >
                        <XIcon className="w-3 h-3" />
                        Reset
                    </button>
                )}
            </div>

            {/* Filter Info */}
            {hasActiveFilters && (
                <div className="mb-4 p-3 rounded-lg bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800/30">
                    <p className="text-sm text-indigo-700 dark:text-indigo-400">
                        Menampilkan {filteredReports.length} dari {reports.length} catatan
                        {categoryFilter !== 'all' && ` ΓÇó Kategori: ${REPORT_CATEGORIES[categoryFilter].label}`}
                        {tagFilter && ` ΓÇó Tag: #${tagFilter}`}
                        {searchQuery && ` ΓÇó Pencarian: "${searchQuery}"`}
                    </p>
                </div>
            )}

            {/* Content */}
            {viewMode === 'timeline' ? (
                <TimelineView
                    reports={filteredReports}
                    onEdit={onEdit}
                    onDelete={onDelete}
                    isOnline={isOnline}
                />
            ) : (
                /* List View */
                filteredReports.length > 0 ? (
                    <div className="space-y-3">
                        {[...filteredReports]
                            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                            .map(r => {
                                const category = r.category ? REPORT_CATEGORIES[r.category] : null;
                                return (
                                    <div key={r.id} className="group relative p-4 rounded-lg bg-gray-50 dark:bg-black/20 hover:bg-gray-100 dark:hover:bg-black/30 transition-colors">
                                        <div className="absolute top-3 right-3 opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity">
                                            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => onEdit(r)} disabled={!isOnline}>
                                                <PencilIcon className="h-4 w-4" />
                                            </Button>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 text-red-600 dark:text-red-400" onClick={() => onDelete(r.id)} disabled={!isOnline}>
                                                <TrashIcon className="h-4 w-4" />
                                            </Button>
                                        </div>
                                        <div className="flex items-center gap-2 mb-1">
                                            {category && (
                                                <span className="text-sm">{category.icon}</span>
                                            )}
                                            <h4 className="font-bold text-gray-900 dark:text-white">{r.title}</h4>
                                        </div>
                                        <p className="text-xs text-gray-500 dark:text-gray-400 mb-2">
                                            {new Date(r.date).toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                                        </p>
                                        <p className="text-sm text-gray-600 dark:text-gray-300 line-clamp-2">{r.notes}</p>
                                        {r.tags && r.tags.length > 0 && (
                                            <div className="flex flex-wrap gap-1 mt-2">
                                                {r.tags.map(tag => (
                                                    <span key={tag} className="px-2 py-0.5 rounded-full text-xs bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400">
                                                        #{tag}
                                                    </span>
                                                ))}
                                            </div>
                                        )}
                                        {r.attachment_url && (
                                            <div className="mt-2 flex items-center gap-1 text-xs text-indigo-600 dark:text-indigo-400">
                                                <FileTextIcon className="w-3 h-3" />
                                                <span>Ada lampiran</span>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-16 text-center">
                        <div className="w-16 h-16 rounded-2xl bg-slate-100 dark:bg-slate-800/50 flex items-center justify-center mb-4">
                            <BookOpenIcon className="w-8 h-8 text-slate-400 dark:text-slate-600" />
                        </div>
                        <h4 className="text-lg font-semibold text-slate-900 dark:text-white">{reports.length === 0 ? 'Tidak Ada Catatan' : 'Tidak Ada Hasil'}</h4>
                        <p className="text-sm text-slate-500 dark:text-slate-400">{reports.length === 0 ? 'Belum ada catatan untuk siswa ini.' : 'Coba ubah filter pencarian.'}</p>
                    </div>
                )
            )}
        </div>
    );
};

