import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { reportRules, ReportFormValues } from '../schemas';
import { validationResolver } from '../../../../utils/formValidation';
import { Button } from '../../../ui/Button';
import { Input } from '../../../ui/Input';
import { ReportRow } from '../types';
import { REPORT_CATEGORIES, COMMON_TAGS, ReportCategory } from '../ReportsTab';
import { UploadIcon, XIcon, FileTextIcon } from 'lucide-react';

interface ReportFormProps {
    defaultValues: ReportRow | null;
    onSubmit: (data: ReportFormValues & { attachment_file?: File }) => void;
    onClose: () => void;
    isPending: boolean;
}

export const ReportForm: React.FC<ReportFormProps> = ({ defaultValues, onSubmit, onClose, isPending }) => {
    const [attachmentFile, setAttachmentFile] = useState<File | null>(null);
    const [attachmentPreview, setAttachmentPreview] = useState<string | null>(defaultValues?.attachment_url || null);
    const [selectedTags, setSelectedTags] = useState<string[]>(defaultValues?.tags || []);
    const [customTag, setCustomTag] = useState('');

    const { register, handleSubmit, watch, setValue, formState: { errors } } = useForm<ReportFormValues>({
        resolver: validationResolver<ReportFormValues>(reportRules),
        defaultValues: {
            date: defaultValues?.date || new Date().toISOString().slice(0, 10),
            title: defaultValues?.title || '',
            notes: defaultValues?.notes || '',
            // Cast to any because DB type is string but schema is strict enum
            category: (defaultValues?.category as any) || null,
            tags: defaultValues?.tags || [],
        }
    });

    const selectedCategory = watch('category');

    const handleAttachmentChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setAttachmentFile(file);
            if (file.type.startsWith('image/')) {
                setAttachmentPreview(URL.createObjectURL(file));
            } else {
                setAttachmentPreview(null);
            }
        }
    };

    const handleRemoveAttachment = () => {
        setAttachmentFile(null);
        if (attachmentPreview && !defaultValues?.attachment_url) {
            URL.revokeObjectURL(attachmentPreview);
        }
        setAttachmentPreview(null);
    };

    const handleToggleTag = (tag: string) => {
        const newTags = selectedTags.includes(tag)
            ? selectedTags.filter(t => t !== tag)
            : [...selectedTags, tag];
        setSelectedTags(newTags);
        setValue('tags', newTags);
    };

    const handleAddCustomTag = () => {
        if (customTag && !selectedTags.includes(customTag)) {
            const newTags = [...selectedTags, customTag.toLowerCase().replace(/\s+/g, '-')];
            setSelectedTags(newTags);
            setValue('tags', newTags);
            setCustomTag('');
        }
    };

    const handleFormSubmit = (data: ReportFormValues) => {
        onSubmit({
            ...data,
            tags: selectedTags,
            attachment_file: attachmentFile || undefined
        });
    };

    return (
        <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">
            {/* Category Selection */}
            <div>
                <label className="block text-sm font-medium mb-2">Kategori Catatan</label>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                    {(Object.entries(REPORT_CATEGORIES) as [ReportCategory, typeof REPORT_CATEGORIES[ReportCategory]][]).map(([key, cat]) => (
                        <label
                            key={key}
                            className={`flex items-center gap-2 p-3 rounded-lg border-2 cursor-pointer transition-all ${selectedCategory === key
                                ? `border-${cat.color}-500 bg-${cat.color}-50 dark:bg-${cat.color}-900/30`
                                : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600'
                                }`}
                        >
                            <input
                                type="radio"
                                value={key}
                                {...register('category')}
                                className="sr-only"
                            />
                            <span className="text-xl">{cat.icon}</span>
                            <div>
                                <p className="font-medium text-sm text-gray-700 dark:text-gray-300">{cat.label}</p>
                                <p className="text-xs text-gray-400">{cat.description}</p>
                            </div>
                        </label>
                    ))}
                </div>
            </div>

            {/* Date & Title */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium mb-1">Tanggal</label>
                    <Input type="date" {...register('date')} error={errors.date?.message} />
                </div>
                <div>
                    <label className="block text-sm font-medium mb-1">Judul</label>
                    <Input {...register('title')} placeholder="cth. Insiden di kelas" error={errors.title?.message} />
                </div>
            </div>

            {/* Notes */}
            <div>
                <label className="block text-sm font-medium mb-1">Catatan Detail</label>
                <textarea
                    {...register('notes')}
                    rows={4}
                    placeholder="Tuliskan catatan lengkap..."
                    className={`w-full px-3 py-2 rounded-lg border bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder:text-gray-400 ${errors.notes
                        ? 'border-red-500 focus:border-red-500 focus:ring-red-500'
                        : 'border-gray-200 dark:border-gray-700 focus:border-indigo-500 focus:ring-indigo-500'
                        }`}
                />
                {errors.notes && <p className="text-red-500 text-xs mt-1">{errors.notes.message}</p>}
            </div>

            {/* Tags */}
            <div>
                <label className="block text-sm font-medium mb-2">Tag (untuk pencarian)</label>
                <div className="flex flex-wrap gap-2 mb-2">
                    {COMMON_TAGS.map(tag => (
                        <button
                            key={tag}
                            type="button"
                            onClick={() => handleToggleTag(tag)}
                            className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${selectedTags.includes(tag)
                                ? 'bg-indigo-600 text-white'
                                : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'
                                }`}
                        >
                            #{tag}
                        </button>
                    ))}
                </div>

                {/* Custom tag input */}
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={customTag}
                        onChange={(e) => setCustomTag(e.target.value)}
                        placeholder="Tag kustom..."
                        className="flex-1 px-3 py-1.5 text-sm rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-900 dark:text-white"
                        onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddCustomTag())}
                    />
                    <Button type="button" variant="outline" size="sm" onClick={handleAddCustomTag}>
                        Tambah
                    </Button>
                </div>

                {/* Selected tags */}
                {selectedTags.length > 0 && (
                    <div className="flex flex-wrap gap-1 mt-2">
                        {selectedTags.map(tag => (
                            <span
                                key={tag}
                                className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400"
                            >
                                #{tag}
                                <button type="button" onClick={() => handleToggleTag(tag)} className="hover:text-red-500">
                                    <XIcon className="w-3 h-3" />
                                </button>
                            </span>
                        ))}
                    </div>
                )}
            </div>

            {/* Attachment Upload */}
            <div>
                <label className="block text-sm font-medium mb-1">Lampiran (Opsional)</label>
                {!attachmentPreview && !attachmentFile ? (
                    <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-gray-300 dark:border-gray-700 rounded-lg cursor-pointer hover:border-indigo-500 dark:hover:border-indigo-500 transition-colors">
                        <div className="flex flex-col items-center justify-center">
                            <UploadIcon className="w-6 h-6 mb-1 text-gray-400" />
                            <p className="text-sm text-gray-500 dark:text-gray-400">Klik untuk upload foto/dokumen</p>
                        </div>
                        <input
                            type="file"
                            className="hidden"
                            accept="image/*,.pdf,.doc,.docx"
                            onChange={handleAttachmentChange}
                        />
                    </label>
                ) : (
                    <div className="relative">
                        {attachmentPreview && (
                            <img
                                src={attachmentPreview}
                                alt="Attachment preview"
                                className="w-full h-24 object-cover rounded-lg"
                            />
                        )}
                        {attachmentFile && !attachmentPreview && (
                            <div className="flex items-center gap-2 p-3 bg-gray-100 dark:bg-gray-800 rounded-lg">
                                <FileTextIcon className="w-5 h-5 text-gray-500" />
                                <span className="text-sm text-gray-600 dark:text-gray-400">{attachmentFile.name}</span>
                            </div>
                        )}
                        <button
                            type="button"
                            onClick={handleRemoveAttachment}
                            className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full hover:bg-red-600"
                        >
                            <XIcon className="w-3 h-3" />
                        </button>
                    </div>
                )}
            </div>

            {/* Actions */}
            <div className="flex justify-end gap-2 pt-4">
                <Button type="button" variant="ghost" onClick={onClose}>Batal</Button>
                <Button type="submit" disabled={isPending}>{isPending ? 'Menyimpan...' : 'Simpan Catatan'}</Button>
            </div>
        </form>
    );
};

import React, { useMemo, useState } from 'react';
import { useForm } from 'react-hook-form';
import { violationRules, ViolationFormValues } from '../schemas';
import { validationResolver } from '../../../../utils/formValidation';
import { Button } from '../../../ui/Button';
import { Input } from '../../../ui/Input';
import { Select } from '../../../ui/Select';
import { ViolationRow } from '../types';
import { violationList, ViolationItem } from '../../../../services/violations.data';
import { SEVERITY_LEVELS, SeverityLevel } from '../ViolationsTab';
import { AlertTriangleIcon, CameraIcon, UploadIcon } from 'lucide-react';

interface ViolationFormProps {
    defaultValues: ViolationRow | null;
    onSubmit: (data: ViolationFormValues & { evidence_file?: File }) => void;
    onClose: () => void;
    isPending: boolean;
}

// Group violations by category for better UX
const violationsByCategory = {
    Ringan: violationList.filter(v => v.category === 'Ringan'),
    Sedang: violationList.filter(v => v.category === 'Sedang'),
    Berat: violationList.filter(v => v.category === 'Berat'),
};

export const ViolationForm: React.FC<ViolationFormProps> = ({ defaultValues, onSubmit, onClose, isPending }) => {
    const [evidenceFile, setEvidenceFile] = useState<File | null>(null);
    const [evidencePreview, setEvidencePreview] = useState<string | null>(defaultValues?.evidence_url || null);

    const { register, handleSubmit, watch, setValue, formState: { errors } } = useForm<ViolationFormValues>({
        resolver: validationResolver<ViolationFormValues>(violationRules),
        defaultValues: {
            date: defaultValues?.date || new Date().toISOString().slice(0, 10),
            description: defaultValues?.description || '',
            severity: defaultValues?.severity || null,
            follow_up_notes: defaultValues?.follow_up_notes || '',
        }
    });

    const selectedDescription = watch('description');

    // Auto-detect severity based on selected violation
    const detectedSeverity = useMemo(() => {
        if (!selectedDescription) return null;
        const violation = violationList.find(v => v.description === selectedDescription);
        if (!violation) return null;
        return violation.category.toLowerCase() as SeverityLevel;
    }, [selectedDescription]);

    // Update severity when violation is selected
    React.useEffect(() => {
        if (detectedSeverity && !defaultValues?.severity) {
            setValue('severity', detectedSeverity);
        }
    }, [detectedSeverity, setValue, defaultValues?.severity]);

    // Get violation points
    const selectedPoints = useMemo(() => {
        if (!selectedDescription) return null;
        const violation = violationList.find(v => v.description === selectedDescription);
        return violation?.points || null;
    }, [selectedDescription]);

    const handleEvidenceChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setEvidenceFile(file);
            if (file.type.startsWith('image/')) {
                setEvidencePreview(URL.createObjectURL(file));
            } else {
                setEvidencePreview(null);
            }
        }
    };

    const handleRemoveEvidence = () => {
        setEvidenceFile(null);
        if (evidencePreview && !defaultValues?.evidence_url) {
            URL.revokeObjectURL(evidencePreview);
        }
        setEvidencePreview(null);
    };

    const handleFormSubmit = (data: ViolationFormValues) => {
        onSubmit({
            ...data,
            evidence_file: evidenceFile || undefined
        });
    };

    return (
        <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">
            {/* Severity Selection */}
            <div>
                <label className="block text-sm font-medium mb-2">Tingkat Pelanggaran</label>
                <div className="grid grid-cols-3 gap-2">
                    {(Object.entries(SEVERITY_LEVELS) as [SeverityLevel, typeof SEVERITY_LEVELS[SeverityLevel]][]).map(([key, level]) => (
                        <label
                            key={key}
                            className={`flex items-center justify-center gap-2 p-3 rounded-lg border-2 cursor-pointer transition-all ${watch('severity') === key
                                    ? `${level.borderClass} ${level.bgClass}`
                                    : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600'
                                }`}
                        >
                            <input
                                type="radio"
                                value={key}
                                {...register('severity')}
                                className="sr-only"
                            />
                            <span className="text-xl">{level.icon}</span>
                            <div className="text-left">
                                <p className={`font-medium text-sm ${watch('severity') === key ? level.textClass : 'text-gray-700 dark:text-gray-300'}`}>
                                    {level.label}
                                </p>
                                <p className="text-xs text-gray-400">{level.points} poin</p>
                            </div>
                        </label>
                    ))}
                </div>
            </div>

            {/* Date */}
            <div>
                <label className="block text-sm font-medium mb-1">Tanggal Kejadian</label>
                <Input type="date" {...register('date')} error={errors.date?.message} />
            </div>

            {/* Violation Type Selection */}
            <div>
                <label className="block text-sm font-medium mb-1">Jenis Pelanggaran</label>
                <Select {...register('description')} error={errors.description?.message}>
                    <option value="">-- Pilih Pelanggaran --</option>
                    {Object.entries(violationsByCategory).map(([category, violations]) => (
                        <optgroup key={category} label={`${category === 'Ringan' ? 'ΓÜá∩╕Å' : category === 'Sedang' ? '≡ƒö╢' : '≡ƒö┤'} ${category}`}>
                            {violations.map(v => (
                                <option key={v.code} value={v.description}>
                                    {v.description} ({v.points} poin)
                                </option>
                            ))}
                        </optgroup>
                    ))}
                </Select>

                {/* Points Preview */}
                {selectedPoints && (
                    <div className="mt-2 p-2 rounded-lg bg-red-50 dark:bg-red-900/20 flex items-center gap-2">
                        <AlertTriangleIcon className="w-4 h-4 text-red-500" />
                        <span className="text-sm text-red-700 dark:text-red-400">
                            Pelanggaran ini akan menambah <strong>{selectedPoints} poin</strong>
                        </span>
                    </div>
                )}
            </div>

            {/* Evidence Upload */}
            <div>
                <label className="block text-sm font-medium mb-1">Bukti Foto (Opsional)</label>
                {!evidencePreview && !evidenceFile ? (
                    <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-gray-300 dark:border-gray-700 rounded-lg cursor-pointer hover:border-indigo-500 dark:hover:border-indigo-500 transition-colors">
                        <div className="flex flex-col items-center justify-center pt-5 pb-6">
                            <UploadIcon className="w-8 h-8 mb-2 text-gray-400" />
                            <p className="text-sm text-gray-500 dark:text-gray-400">Klik untuk upload bukti foto</p>
                            <p className="text-xs text-gray-400">PNG, JPG (maks. 5MB)</p>
                        </div>
                        <input
                            type="file"
                            className="hidden"
                            accept="image/*"
                            onChange={handleEvidenceChange}
                        />
                    </label>
                ) : (
                    <div className="relative">
                        {evidencePreview && (
                            <img
                                src={evidencePreview}
                                alt="Evidence preview"
                                className="w-full h-32 object-cover rounded-lg"
                            />
                        )}
                        {evidenceFile && !evidencePreview && (
                            <div className="flex items-center gap-2 p-3 bg-gray-100 dark:bg-gray-800 rounded-lg">
                                <CameraIcon className="w-5 h-5 text-gray-500" />
                                <span className="text-sm text-gray-600 dark:text-gray-400">{evidenceFile.name}</span>
                            </div>
                        )}
                        <button
                            type="button"
                            onClick={handleRemoveEvidence}
                            className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full hover:bg-red-600"
                        >
                            Γ£ò
                        </button>
                    </div>
                )}
            </div>

            {/* Follow-up Notes */}
            <div>
                <label className="block text-sm font-medium mb-1">Catatan Tindak Lanjut (Opsional)</label>
                <textarea
                    {...register('follow_up_notes')}
                    placeholder="Catatan tambahan atau rencana tindak lanjut..."
                    className="w-full px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder:text-gray-400 focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    rows={3}
                />
            </div>

            {/* Actions */}
            <div className="flex justify-end gap-2 pt-4">
                <Button type="button" variant="ghost" onClick={onClose}>Batal</Button>
                <Button type="submit" disabled={isPending} className="bg-red-600 hover:bg-red-700">
                    {isPending ? 'Menyimpan...' : 'Simpan Pelanggaran'}
                </Button>
            </div>
        </form>
    );
};

import React, { useState, useRef } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useToast } from '../../hooks/useToast';
import { useOfflineStatus } from '../../hooks/useOfflineStatus';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '../../services/supabase';
import { Database } from '../../services/database.types';
import { CardContent, CardHeader, CardTitle, CardDescription } from '../ui/Card';
import { Switch } from '../ui/Switch';
import { BellIcon, ClockIcon, CheckSquareIcon, CalendarIcon } from '../Icons';
import { PlayCircle, Upload, Volume, Volume2, Smartphone } from 'lucide-react';
import { getPreferences, savePreferences, NotificationPreferences } from '../../services/NotificationService';
import { Select } from '../ui/Select';
import { Button } from '../ui/Button';
import {
    SOUND_OPTIONS,
    getScheduleSound,
    setScheduleSound,
    getCustomSoundUrl,
    setCustomSound,
    clearCustomSound,
    previewSound,
    getSoundVolume,
    setSoundVolume,
    SoundType
} from '../../services/notificationSoundSettings';
import { Capacitor } from '@capacitor/core';
import { SettingsCard } from './SettingsCard';

type ScheduleRow = Database['public']['Tables']['schedules']['Row'];
type ScheduleWithClassName = ScheduleRow & { className?: string };

const loadRingtonePicker = async () => {
    const module = await import('../../plugins/RingtonePicker');
    return module.default;
};

const NotificationsSection: React.FC = () => {
    const { enableScheduleNotifications, disableScheduleNotifications, user, isNotificationsEnabled } = useAuth();
    const toast = useToast();
    const isOnline = useOfflineStatus();
    const [isLoading, setIsLoading] = useState(false);
    const [taskPrefs, setTaskPrefs] = useState<NotificationPreferences>(getPreferences());

    // Sound picker state
    const [selectedSound, setSelectedSound] = useState<SoundType>(getScheduleSound());
    const [volume, setVolume] = useState(getSoundVolume());
    const [hasCustomSound, setHasCustomSound] = useState(!!getCustomSoundUrl());
    const fileInputRef = useRef<HTMLInputElement>(null);

    // System ringtone state (for Android native picker)
    const [systemRingtoneTitle, setSystemRingtoneTitle] = useState<string | null>(
        localStorage.getItem('portal_guru_system_ringtone_title')
    );
    const [systemRingtoneUri, setSystemRingtoneUri] = useState<string | null>(
        localStorage.getItem('portal_guru_system_ringtone_uri')
    );
    const isAndroid = Capacitor.getPlatform() === 'android';

    // Handler for opening native ringtone picker (Android only)
    const handleSystemRingtoneSelect = async () => {
        if (!isAndroid) {
            toast.warning("Fitur ini hanya tersedia di Android");
            return;
        }

        try {
            const ringtonePicker = await loadRingtonePicker();
            const result = await ringtonePicker.openPicker({
                type: 'notification',
                title: 'Pilih Nada Notifikasi',
                currentUri: systemRingtoneUri || undefined,
            });

            if (!result.cancelled) {
                if (result.isSilent) {
                    setSelectedSound('none');
                    setScheduleSound('none');
                    toast.info("Notifikasi diatur ke mode diam");
                } else if (result.uri) {
                    setSystemRingtoneUri(result.uri);
                    setSystemRingtoneTitle(result.title || 'System Sound');
                    localStorage.setItem('portal_guru_system_ringtone_uri', result.uri);
                    localStorage.setItem('portal_guru_system_ringtone_title', result.title || 'System Sound');

                    setSelectedSound('system');
                    setScheduleSound('system');
                    toast.success(`Nada dipilih: ${result.title}`);

                    // Preview the selected ringtone
                    ringtonePicker.previewSound({ uri: result.uri });
                }
            }
        } catch (error) {
            console.error('Error opening ringtone picker:', error);
            toast.error("Gagal membuka pemilih ringtone");
        }
    };

    const { data: scheduleData } = useQuery({
        queryKey: ['scheduleWithClasses', user?.id],
        queryFn: async () => {
            const { data: schedule, error: scheduleError } = await supabase
                .from('schedules')
                .select('*')
                .eq('user_id', user!.id);

            const { data: classes, error: classesError } = await supabase
                .from('classes')
                .select('id, name')
                .eq('user_id', user!.id)
                .is('deleted_at', null);

            if (scheduleError || classesError) {
                throw scheduleError || classesError;
            }

            const classMap = new Map(classes.map(c => [c.id, c.name]));

            return schedule.map(item => ({
                ...item,
                className: item.class_id ? (classMap.get(item.class_id) || item.class_id) : undefined
            }));
        },
        enabled: !!user
    });

    const handleToggle = async (checked: boolean) => {
        setIsLoading(true);
        if (checked) {
            if (!scheduleData || scheduleData.length === 0) {
                toast.warning("Tidak ada data jadwal untuk notifikasi.");
                setIsLoading(false);
                return;
            }
            const success = await enableScheduleNotifications(scheduleData as ScheduleWithClassName[]);
            if (success) {
                toast.success("Notifikasi jadwal diaktifkan!");
            } else {
                toast.error("Gagal mengaktifkan notifikasi.");
            }
        } else {
            await disableScheduleNotifications();
            toast.info("Notifikasi jadwal dinonaktifkan.");
        }
        setIsLoading(false);
    };

    const handleTaskPrefChange = (key: keyof NotificationPreferences, value: any) => {
        const newPrefs = { ...taskPrefs, [key]: value };
        setTaskPrefs(newPrefs);
        savePreferences(newPrefs);
        toast.success("Preferensi notifikasi disimpan.");
    };

    const handleSoundSelect = (soundId: SoundType) => {
        setSelectedSound(soundId);
        setScheduleSound(soundId);
        toast.success(`Nada notifikasi diubah ke "${SOUND_OPTIONS.find(s => s.id === soundId)?.name}"`);
    };

    const handlePreviewSound = (soundId: SoundType) => {
        previewSound(soundId);
    };

    const handleVolumeChange = (newVolume: number) => {
        setVolume(newVolume);
        setSoundVolume(newVolume);
    };

    const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        try {
            await setCustomSound(file);
            setHasCustomSound(true);
            setSelectedSound('custom');
            setScheduleSound('custom');
            toast.success("Nada custom berhasil diupload!");
            // Preview the uploaded sound
            setTimeout(() => previewSound('custom'), 500);
        } catch (error) {
            toast.error(error instanceof Error ? error.message : "Gagal upload file");
        }

        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleClearCustomSound = () => {
        clearCustomSound();
        setHasCustomSound(false);
        if (selectedSound === 'custom') {
            setSelectedSound('default');
            setScheduleSound('default');
        }
        toast.info("Nada custom dihapus");
    };

    return (
        <div className="space-y-6">
            {/* Schedule Notifications */}
            <SettingsCard className="overflow-hidden">
                <CardHeader className="border-b border-slate-200/60 dark:border-slate-700/50 pb-6">
                    <CardTitle className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-green-600 to-emerald-600 dark:from-green-400 dark:to-emerald-400">Preferensi Notifikasi</CardTitle>
                    <CardDescription className="text-base">Kelola bagaimana Anda menerima pemberitahuan penting.</CardDescription>
                </CardHeader>
                <CardContent className="pt-6 sm:pt-8 space-y-3 sm:space-y-4">
                    {/* Schedule Reminder */}
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-4 sm:p-6 bg-slate-50 dark:bg-slate-800/50 rounded-xl sm:rounded-2xl border border-slate-100 dark:border-slate-700 hover:border-green-200 dark:hover:border-green-800 transition-colors">
                        <div className="flex items-center gap-3 sm:gap-4">
                            <div className="p-2 sm:p-3 rounded-xl bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 flex-shrink-0">
                                <CalendarIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                            </div>
                            <div className="min-w-0">
                                <p className="font-bold text-sm sm:text-lg text-slate-900 dark:text-white">Pengingat Jadwal Kelas</p>
                                <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400">Notifikasi 5 menit sebelum kelas.</p>
                            </div>
                        </div>
                        <Switch checked={isNotificationsEnabled} onChange={(e) => handleToggle(e.target.checked)} disabled={isLoading || !isOnline} className="data-[state=checked]:bg-green-600 flex-shrink-0" />
                    </div>

                    {/* Task Reminders */}
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-4 sm:p-6 bg-slate-50 dark:bg-slate-800/50 rounded-xl sm:rounded-2xl border border-slate-100 dark:border-slate-700 hover:border-amber-200 dark:hover:border-amber-800 transition-colors">
                        <div className="flex items-center gap-3 sm:gap-4">
                            <div className="p-2 sm:p-3 rounded-xl bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 flex-shrink-0">
                                <CheckSquareIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                            </div>
                            <div className="min-w-0">
                                <p className="font-bold text-sm sm:text-lg text-slate-900 dark:text-white">Pengingat Tugas</p>
                                <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400">Notifikasi saat tugas mendekati deadline.</p>
                            </div>
                        </div>
                        <Switch
                            checked={taskPrefs.taskReminders}
                            onChange={(e) => handleTaskPrefChange('taskReminders', e.target.checked)}
                            className="data-[state=checked]:bg-amber-600 flex-shrink-0"
                        />
                    </div>

                    {/* Task Reminder Timing */}
                    {taskPrefs.taskReminders && (
                        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-4 sm:p-6 bg-slate-50 dark:bg-slate-800/50 rounded-xl sm:rounded-2xl border border-slate-100 dark:border-slate-700 sm:ml-8 ml-4">
                            <div className="flex items-center gap-3 sm:gap-4">
                                <div className="p-2 sm:p-3 rounded-xl bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-400 flex-shrink-0">
                                    <ClockIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                                </div>
                                <div className="min-w-0">
                                    <p className="font-medium text-sm sm:text-base text-slate-900 dark:text-white">Ingatkan Sebelum Deadline</p>
                                    <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400">Waktu pengingatan sebelum deadline.</p>
                                </div>
                            </div>
                            <Select
                                value={taskPrefs.taskReminderHours.toString()}
                                onChange={(e) => handleTaskPrefChange('taskReminderHours', parseInt(e.target.value))}
                                className="w-full sm:w-32 flex-shrink-0"
                            >
                                <option value="6">6 jam</option>
                                <option value="12">12 jam</option>
                                <option value="24">24 jam</option>
                                <option value="48">48 jam</option>
                                <option value="72">72 jam</option>
                            </Select>
                        </div>
                    )}

                    {/* Attendance Reminders */}
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 p-4 sm:p-6 bg-slate-50 dark:bg-slate-800/50 rounded-xl sm:rounded-2xl border border-slate-100 dark:border-slate-700 hover:border-green-200 dark:hover:border-green-800 transition-colors">
                        <div className="flex items-center gap-3 sm:gap-4">
                            <div className="p-2 sm:p-3 rounded-xl bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 flex-shrink-0">
                                <BellIcon className="w-5 h-5 sm:w-6 sm:h-6" />
                            </div>
                            <div className="min-w-0">
                                <p className="font-bold text-sm sm:text-lg text-slate-900 dark:text-white">Pengingat Absensi</p>
                                <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400">Ingatkan mengisi absensi harian.</p>
                            </div>
                        </div>
                        <Switch
                            checked={taskPrefs.attendanceReminders}
                            onChange={(e) => handleTaskPrefChange('attendanceReminders', e.target.checked)}
                            className="data-[state=checked]:bg-green-600 flex-shrink-0"
                        />
                    </div>
                </CardContent>
            </SettingsCard>

            {/* Notification Sound Picker */}
            <SettingsCard className="overflow-hidden">
                <CardHeader className="border-b border-slate-200/60 dark:border-slate-700/50 pb-6">
                    <CardTitle className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-green-600 to-emerald-600 dark:from-green-400 dark:to-emerald-400">
                        Nada Notifikasi
                    </CardTitle>
                    <CardDescription className="text-base">
                        Pilih nada yang akan diputar saat menerima notifikasi jadwal.
                    </CardDescription>
                </CardHeader>
                <CardContent className="pt-6 sm:pt-8 space-y-6">
                    {/* Volume Control */}
                    <div className="flex items-center gap-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-700">
                        <div className="p-2 rounded-xl bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400">
                            {volume > 0.5 ? <Volume2 className="w-5 h-5" /> : <Volume className="w-5 h-5" />}
                        </div>
                        <div className="flex-1">
                            <p className="font-medium text-sm text-slate-900 dark:text-white mb-2">Volume Notifikasi</p>
                            <input
                                type="range"
                                min="0"
                                max="1"
                                step="0.1"
                                value={volume}
                                onChange={(e) => handleVolumeChange(parseFloat(e.target.value))}
                                className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-green-600"
                            />
                        </div>
                        <span className="text-sm font-bold text-slate-600 dark:text-slate-400 w-12 text-right">
                            {Math.round(volume * 100)}%
                        </span>
                    </div>

                    {/* Sound Options Grid */}
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                        {SOUND_OPTIONS
                            .filter(sound => sound.id !== 'system' || isAndroid) // Only show system on Android
                            .map((sound) => {
                                const isSelected = selectedSound === sound.id;
                                const isCustomDisabled = sound.id === 'custom' && !hasCustomSound;
                                const isSystemSound = sound.id === 'system';

                                const handleClick = () => {
                                    if (isCustomDisabled) return;
                                    if (isSystemSound) {
                                        handleSystemRingtoneSelect();
                                    } else {
                                        handleSoundSelect(sound.id);
                                    }
                                };

                                return (
                                    <div
                                        key={sound.id}
                                        className={`
                                        relative p-4 rounded-xl border-2 transition-all duration-200 cursor-pointer group
                                        ${isSelected
                                                ? 'border-green-500 bg-green-50 dark:bg-green-900/20 shadow-lg shadow-green-500/20'
                                                : 'border-slate-200 dark:border-slate-700 hover:border-green-300 dark:hover:border-green-700 bg-white dark:bg-slate-800'
                                            }
                                        ${isCustomDisabled ? 'opacity-50' : ''}
                                    `}
                                        onClick={handleClick}
                                    >
                                        {/* Selection indicator */}
                                        {isSelected && (
                                            <div className="absolute top-2 right-2 w-5 h-5 bg-green-500 rounded-full flex items-center justify-center">
                                                <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                                                </svg>
                                            </div>
                                        )}

                                        <div className="text-center">
                                            <span className="text-2xl block mb-2">{sound.icon}</span>
                                            <p className="font-bold text-sm text-slate-900 dark:text-white">{sound.name}</p>
                                            {/* Show selected system ringtone name */}
                                            {isSystemSound && systemRingtoneTitle && isSelected ? (
                                                <p className="text-xs text-purple-600 dark:text-purple-400 mt-1 truncate">
                                                    {systemRingtoneTitle}
                                                </p>
                                            ) : (
                                                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">{sound.description}</p>
                                            )}
                                        </div>

                                        {/* Preview button for built-in sounds */}
                                        {sound.id !== 'none' && sound.id !== 'custom' && sound.id !== 'system' && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handlePreviewSound(sound.id);
                                                }}
                                                className="absolute bottom-2 right-2 p-1.5 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-400 hover:bg-green-100 dark:hover:bg-green-900/30 hover:text-green-600 dark:hover:text-green-400 transition-colors opacity-0 group-hover:opacity-100"
                                                title="Preview suara"
                                            >
                                                <PlayCircle className="w-4 h-4" />
                                            </button>
                                        )}

                                        {/* System ringtone picker button */}
                                        {isSystemSound && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleSystemRingtoneSelect();
                                                }}
                                                className="absolute bottom-2 right-2 p-1.5 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-400 hover:bg-green-100 dark:hover:bg-green-900/30 hover:text-green-600 dark:hover:text-green-400 transition-colors"
                                                title="Pilih dari ringtone sistem"
                                            >
                                                <Smartphone className="w-4 h-4" />
                                            </button>
                                        )}

                                        {/* Custom sound upload button */}
                                        {sound.id === 'custom' && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    fileInputRef.current?.click();
                                                }}
                                                className="absolute bottom-2 right-2 p-1.5 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-400 hover:bg-green-100 dark:hover:bg-green-900/30 hover:text-green-600 dark:hover:text-green-400 transition-colors"
                                                title="Upload audio"
                                            >
                                                <Upload className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                );
                            })}
                    </div>

                    {/* Custom sound management */}
                    {hasCustomSound && (
                        <div className="flex items-center justify-between p-4 bg-green-50 dark:bg-green-900/20 rounded-xl border border-green-200 dark:border-green-800">
                            <div className="flex items-center gap-3">
                                <span className="text-2xl">≡ƒÄ╡</span>
                                <div>
                                    <p className="font-medium text-sm text-slate-900 dark:text-white">Custom Sound Aktif</p>
                                    <p className="text-xs text-slate-500 dark:text-slate-400">File audio tersimpan di browser</p>
                                </div>
                            </div>
                            <div className="flex gap-2">
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => handlePreviewSound('custom')}
                                    className="text-green-600 dark:text-green-400"
                                >
                                    <PlayCircle className="w-4 h-4 mr-1" />
                                    Test
                                </Button>
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={handleClearCustomSound}
                                    className="text-red-600 dark:text-red-400"
                                >
                                    Hapus
                                </Button>
                            </div>
                        </div>
                    )}

                    {/* Hidden file input */}
                    <input
                        ref={fileInputRef}
                        type="file"
                        accept="audio/*"
                        onChange={handleFileUpload}
                        className="hidden"
                    />

                    {/* Info note */}
                    <p className="text-xs text-slate-500 dark:text-slate-400 text-center">
                        ≡ƒÆí Tip: Upload file audio MP3, WAV, atau OGG (maks. 1MB) untuk nada custom
                    </p>
                </CardContent>
            </SettingsCard>
        </div>
    );
};

export default NotificationsSection;

