import React, { useState, useEffect } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { useToast } from '../../hooks/useToast';
import { useOfflineStatus } from '../../hooks/useOfflineStatus';
import { CardContent, CardHeader, CardTitle, CardDescription } from '../ui/Card';
import { Input } from '../ui/Input';
import { Button } from '../ui/Button';
import { ImageUploader } from '../ui/ImageUploader';
import { supabase } from '../../services/supabase';
import { SettingsCard } from './SettingsCard';

const getStoragePath = (url: string | undefined | null) => {
    if (!url) return null;
    if (url.includes('pravatar.cc')) return null;
    try {
        const parts = url.split('/teacher_assets/');
        if (parts.length < 2) return null;
        return parts[1];
    } catch (e) {
        console.error('Error parsing storage URL', e);
        return null;
    }
};

const ProfileSection: React.FC = () => {
    const { user, updateUser } = useAuth();
    const toast = useToast();
    const isOnline = useOfflineStatus();
    const [name, setName] = useState(user?.name || '');
    const [schoolName, setSchoolName] = useState(user?.school_name || '');

    useEffect(() => {
        if (user) {
            if (user.name !== name) {
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setName(user.name || '');
            }
            if (user.school_name !== schoolName) {
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setSchoolName(user.school_name || '');
            }
        }
    }, [user, name, schoolName]);

    const handleAvatarUpload = async (file: File) => {
        if (!user) return;

        const filePath = `${user.id}/avatar-${new Date().getTime()}.jpg`;

        const { error: uploadError } = await supabase.storage
            .from('teacher_assets')
            .upload(filePath, file, {
                cacheControl: '3600',
                upsert: true,
            });

        if (uploadError) {
            throw uploadError;
        }

        const { data: publicUrlData } = supabase.storage
            .from('teacher_assets')
            .getPublicUrl(filePath);

        if (publicUrlData.publicUrl) {
            const oldAvatarUrl = user.avatarUrl;

            const { error: updateUserError } = await updateUser({ avatar_url: publicUrlData.publicUrl });
            if (updateUserError) {
                // Determine if we should delete the new file since update failed? 
                // For now, focus on the user request: "potensi file orphan" refers to old files. 
                // But cleaning up the new file if update fails is also good hygiene.
                const newPath = getStoragePath(publicUrlData.publicUrl);
                if (newPath) await supabase.storage.from('teacher_assets').remove([newPath]);
                throw updateUserError;
            }

            // Delete old file if exists
            if (oldAvatarUrl) {
                const oldPath = getStoragePath(oldAvatarUrl);
                if (oldPath) {
                    await supabase.storage.from('teacher_assets').remove([oldPath]);
                }
            }

            toast.success("Foto profil berhasil diperbarui!");
        } else {
            throw new Error("Tidak bisa mendapatkan URL publik untuk foto.");
        }
    };

    const handleAvatarDelete = async () => {
        if (!user) return;

        const oldAvatarUrl = user.avatarUrl;

        // Reset to default avatar
        const { error } = await updateUser({ avatar_url: '' });
        if (error) {
            throw error;
        }

        // Delete file from storage
        if (oldAvatarUrl) {
            const oldPath = getStoragePath(oldAvatarUrl);
            if (oldPath) {
                const { error: storageError } = await supabase.storage.from('teacher_assets').remove([oldPath]);
                if (storageError) {
                    console.error('Failed to remove file from storage:', storageError);
                    // Just log, don't throw, since user profile is already updated logic-wise
                }
            }
        }

        toast.success("Foto profil berhasil dihapus!");
    };

    const handleProfileSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const { error } = await updateUser({ name, school_name: schoolName });
        if (error) {
            toast.error(`Gagal memperbarui profil: ${error.message}`);
        } else {
            toast.success("Profil berhasil diperbarui!");
        }
    };

    return (
        <SettingsCard className="overflow-hidden">
            <CardHeader className="border-b border-slate-200/60 dark:border-slate-700/50 pb-6">
                <CardTitle className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-green-600 to-emerald-600 dark:from-green-400 dark:to-emerald-400">Profil Pengguna</CardTitle>
                <CardDescription className="text-base">Perbarui informasi profil dan foto identitas Anda.</CardDescription>
            </CardHeader>
            <CardContent className="pt-8">
                <form onSubmit={handleProfileSubmit} className="space-y-8">
                    <div className="flex flex-col sm:flex-row items-center gap-8">
                        <div className="relative group">
                            <div className="absolute -inset-1 bg-gradient-to-tr from-green-500 to-emerald-500 rounded-full opacity-70 blur group-hover:opacity-100 transition duration-500"></div>
                            <div className="relative">
                                <ImageUploader
                                    currentImageUrl={user?.avatarUrl || `https://i.pravatar.cc/150?u=${user?.id}`}
                                    onUpload={handleAvatarUpload}
                                    onDelete={handleAvatarDelete}
                                    disabled={!isOnline}
                                    size="lg"
                                    showDeleteButton={!!user?.avatarUrl && !user?.avatarUrl.includes('pravatar.cc')}
                                    config={{
                                        maxFileSize: 5,
                                        maxWidth: 300,
                                        maxHeight: 300,
                                        quality: 0.85,
                                        aspectRatio: 1,
                                        circularCrop: true
                                    }}
                                />
                            </div>
                        </div>
                        <div className="flex-1 text-center sm:text-left space-y-2">
                            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{user?.name}</h3>
                            <p className="text-slate-500 dark:text-slate-400 font-medium flex items-center justify-center sm:justify-start gap-2">
                                <span className="w-2 h-2 rounded-full bg-green-500"></span>
                                {user?.email}
                            </p>
                            <div className="pt-2">
                                <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-300 border border-green-100 dark:border-green-800">
                                    Guru / Pengajar
                                </span>
                            </div>
                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label htmlFor="name" className="block text-sm font-semibold text-slate-700 dark:text-slate-300">Nama Lengkap</label>
                            <Input
                                id="name"
                                type="text"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                className="h-12 rounded-xl border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all"
                                placeholder="Masukkan nama lengkap Anda"
                            />
                        </div>
                        <div className="space-y-2">
                            <label htmlFor="schoolName" className="block text-sm font-semibold text-slate-700 dark:text-slate-300">Nama Sekolah</label>
                            <Input
                                id="schoolName"
                                type="text"
                                value={schoolName}
                                onChange={(e) => setSchoolName(e.target.value)}
                                className="h-12 rounded-xl border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-green-500/20 focus:border-green-500 transition-all"
                                placeholder="Masukkan nama sekolah"
                            />
                        </div>
                    </div>
                    <div className="flex justify-end pt-4 border-t border-gray-100 dark:border-gray-800">
                        <Button type="submit" disabled={!isOnline} className="px-8 rounded-xl bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-700 hover:to-emerald-700 text-white shadow-lg shadow-green-500/20 transition-all hover:scale-[1.02]">
                            Simpan Perubahan
                        </Button>
                    </div>
                </form>
            </CardContent>
        </SettingsCard>
    );
};

export default ProfileSection;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../services/supabase';
import { useToast } from '../../hooks/useToast';
import { useAuth } from '../../hooks/useAuth';
import { Button } from '../ui/Button';
import { CardTitle, CardDescription } from '../ui/Card';
import { PlusIcon, TrashIcon, CheckCircleIcon, LockIcon, CalendarIcon, ChevronDownIcon, ChevronRightIcon, AlertCircleIcon } from 'lucide-react';
import { AcademicYearRow, SemesterRow } from '../../types';
import { SettingsCard } from './SettingsCard';

interface AcademicYearWithSemesters extends AcademicYearRow {
    semesters: SemesterRow[];
}

export const SemesterManagement: React.FC = () => {
    const { user, loading: authLoading } = useAuth();
    const [years, setYears] = useState<AcademicYearWithSemesters[]>([]);
    const [loading, setLoading] = useState(true);
    const [creatingYear, setCreatingYear] = useState(false);
    const [newYearName, setNewYearName] = useState('');
    const [newYearStart, setNewYearStart] = useState('');
    const [newYearEnd, setNewYearEnd] = useState('');

    // Expanded state for accordion
    const [expandedYears, setExpandedYears] = useState<Set<string>>(new Set());

    const toast = useToast();

    const fetchData = React.useCallback(async () => {
        if (!user || !user.id) return;
        setLoading(true);
        console.log('Fetching academic data for user:', user.id);

        // Safety timeout to prevent infinite loading
        const timeoutId = setTimeout(() => {
            setLoading(prev => {
                if (prev) {
                    toast.error('Request timeout. Silakan coba lagi.');
                    return false;
                }
                return prev;
            });
        }, 10000);

        try {
            // Remove explicit .eq('user_id') since RLS handles it. 
            // This simplifies the query and avoids potential redundant filtering issues.
            const { data: yearsData, error: yearsError } = await supabase
                .from('academic_years')
                .select('*')
                .order('start_date', { ascending: false });

            if (yearsError) throw yearsError;

            const { data: semestersData, error: semestersError } = await supabase
                .from('semesters')
                .select('*')
                .order('semester_number', { ascending: true });

            if (semestersError) throw semestersError;

            // Safeguard against null data
            const validYears = yearsData || [];
            const validSemesters = semestersData || [];

            const combined: AcademicYearWithSemesters[] = validYears.map(year => ({
                ...year,
                semesters: validSemesters.filter(s => s.academic_year_id === year.id)
            }));

            setYears(combined);
            // Expand the first one by default if it exists
            if (combined.length > 0) {
                setExpandedYears(new Set([combined[0].id]));
            }
        } catch (error) {
            console.error('Error fetching academic data:', error);
            toast.error('Gagal memuat data akademik.');
        } finally {
            clearTimeout(timeoutId);
            setLoading(false);
        }
    }, [user?.id, toast]); // Depend on user.id string, not user object

    useEffect(() => {
        if (authLoading) return;
        if (!user || !user.id) {
            setLoading(false);
            return;
        }
        fetchData();
    }, [authLoading, user?.id, fetchData]); // Depend on user.id string

    const toggleYearExpand = (yearId: string) => {
        setExpandedYears(prev => {
            const next = new Set(prev);
            if (next.has(yearId)) next.delete(yearId);
            else next.add(yearId);
            return next;
        });
    };

    const handleCreateYear = async () => {
        if (!user) {
            toast.error('Sesi tidak valid.');
            return;
        }

        if (!newYearName || !newYearStart || !newYearEnd) {
            toast.error('Mohon lengkapi semua field.');
            return;
        }

        try {
            const { data, error } = await supabase
                .from('academic_years')
                .insert({
                    name: newYearName,
                    start_date: newYearStart,
                    end_date: newYearEnd,
                    is_active: false,
                    user_id: user.id
                })
                .select()
                .single();

            if (error) throw error;

            toast.success('Tahun ajaran berhasil dibuat.');
            setCreatingYear(false);
            setNewYearName('');
            setNewYearStart('');
            setNewYearEnd('');

            // Should also create semesters strictly? 1 and 2?
            // Let's create default semesters 1 and 2 for convenience
            if (data) {
                await createDefaultSemesters(data.id, newYearStart);
            }

            fetchData();
        } catch (error) {
            console.error('Error creating year:', error);
            toast.error('Gagal membuat tahun ajaran.');
        }
    };

    const createDefaultSemesters = async (yearId: string, yearStart: string) => {
        const startYear = new Date(yearStart).getFullYear();
        // Simple logic: Sem 1 starts July of startYear, Ends Dec
        // Sem 2 starts Jan of startYear+1, Ends June

        const sem1Start = `${startYear}-07-01`;
        const sem1End = `${startYear}-12-31`;
        const sem2Start = `${startYear + 1}-01-01`;
        const sem2End = `${startYear + 1}-06-30`;

        if (!user?.id) {
            toast.error('User required');
            return;
        }

        const semestersToInsert = [
            {
                academic_year_id: yearId,
                name: 'Ganjil',
                semester_number: 1,
                start_date: sem1Start,
                end_date: sem1End,
                is_active: false,
                is_locked: false,
                user_id: user.id
            },
            {
                academic_year_id: yearId,
                name: 'Genap',
                semester_number: 2,
                start_date: sem2Start,
                end_date: sem2End,
                is_active: false,
                is_locked: false,
                user_id: user.id
            }
        ];

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        await supabase.from('semesters').insert(semestersToInsert as any);
    };

    const handleActivateSemester = async (semesterId: string, yearId: string) => {
        try {
            // Use RPC for atomic update
            const { error } = await supabase.rpc('activate_semester', {
                p_semester_id: semesterId,
                p_year_id: yearId
            });

            if (error) throw error;

            toast.success('Semester aktif diperbarui.');
            fetchData();
            // Force reload to update app context state widely
            window.location.reload();
        } catch (error) {
            console.error('Error activating semester:', error);
            toast.error('Gagal mengaktifkan semester.');
        }
    };

    const handleToggleLock = async (semester: SemesterRow) => {
        try {
            const { error } = await supabase
                .from('semesters')
                .update({ is_locked: !semester.is_locked })
                .eq('id', semester.id);

            if (error) throw error;
            toast.success(semester.is_locked ? 'Semester dibuka.' : 'Semester dikunci.');
            fetchData();
        } catch (error) {
            console.error(error);
            toast.error('Gagal mengubah status kunci.');
        }
    };

    const handleDeleteYear = async (yearId: string) => {
        if (!confirm('Apakah Anda yakin ingin menghapus tahun ajaran ini beserta semua semesternya?')) return;

        try {
            const { error } = await supabase
                .from('academic_years')
                .delete()
                .eq('id', yearId);

            if (error) throw error;
            toast.success('Tahun ajaran dihapus.');
            fetchData();
        } catch (error) {
            console.error('Error deleting year:', error);
            toast.error('Gagal menghapus tahun ajaran.');
        }
    };

    return (
        <SettingsCard className="p-6">
            {/* Header with subtle loader */}
            <div className="flex justify-between items-center mb-6">
                <div>
                    <CardTitle className="flex items-center gap-2">
                        Manajemen Semester
                        {loading && <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-indigo-600"></div>}
                    </CardTitle>
                    <CardDescription>Atur Tahun Ajaran dan Semester Aktif</CardDescription>
                </div>
                <Button onClick={() => setCreatingYear(!creatingYear)}>
                    <PlusIcon className="w-4 h-4 mr-2" />
                    Buat Tahun Ajaran
                </Button>
            </div>

            {creatingYear && (
                <div className="mb-6 p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 animate-fade-in">
                    <h4 className="font-semibold mb-3">Tahun Ajaran Baru</h4>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                        <div>
                            <label className="block text-sm font-medium mb-1">Nama (contoh: 2024/2025)</label>
                            <input
                                type="text"
                                className="w-full p-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800"
                                value={newYearName}
                                onChange={e => setNewYearName(e.target.value)}
                                placeholder="2024/2025"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium mb-1">Mulai</label>
                            <input
                                type="date"
                                className="w-full p-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800"
                                value={newYearStart}
                                onChange={e => setNewYearStart(e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium mb-1">Selesai</label>
                            <input
                                type="date"
                                className="w-full p-2 rounded-lg border border-slate-300 dark:border-slate-600 dark:bg-slate-800"
                                value={newYearEnd}
                                onChange={e => setNewYearEnd(e.target.value)}
                            />
                        </div>
                    </div>
                    <div className="flex justify-end gap-2">
                        <Button variant="ghost" onClick={() => setCreatingYear(false)} className="px-6">Batal</Button>
                        <Button onClick={handleCreateYear}>Simpan</Button>
                    </div>
                </div>
            )}

            <div className="space-y-4">
                {years.length === 0 ? (
                    <div className="text-center py-8 text-gray-400">
                        {loading ? 'Sedang sinkronisasi data...' : 'Belum ada data tahun ajaran.'}
                        {!loading && (
                            <div className="mt-2">
                                <Button variant="outline" size="sm" onClick={() => fetchData()}>
                                    Muat Ulang
                                </Button>
                            </div>
                        )}
                    </div>
                ) : (
                    years.map(year => (
                        <div key={year.id} className={`border rounded-xl transition-all ${year.is_active ? 'border-indigo-200 bg-indigo-50/30 dark:border-indigo-900/50 dark:bg-indigo-900/10' : 'border-slate-200 dark:border-slate-700'}`}>
                            <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800/50" onClick={() => toggleYearExpand(year.id)}>
                                <div className="flex items-center gap-3">
                                    {expandedYears.has(year.id) ? <ChevronDownIcon className="w-5 h-5 text-gray-400" /> : <ChevronRightIcon className="w-5 h-5 text-gray-400" />}
                                    <div>
                                        <h3 className="font-bold text-lg flex items-center gap-2">
                                            {year.name}
                                            {year.is_active && <span className="px-2 py-0.5 rounded-full bg-indigo-100 text-indigo-700 text-xs dark:bg-indigo-900 dark:text-indigo-300">Aktif</span>}
                                        </h3>
                                        <p className="text-sm text-gray-500">
                                            {new Date(year.start_date).toLocaleDateString('id-ID')} - {new Date(year.end_date).toLocaleDateString('id-ID')}
                                        </p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2" onClick={e => e.stopPropagation()}>
                                    {!year.is_active && (
                                        <Button variant="ghost" size="sm" onClick={() => handleDeleteYear(year.id)} className="text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20">
                                            <TrashIcon className="w-4 h-4" />
                                        </Button>
                                    )}
                                </div>
                            </div>

                            {expandedYears.has(year.id) && (
                                <div className="p-4 border-t border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900/50 rounded-b-xl">
                                    <div className="grid gap-3">
                                        {year.semesters.map(sem => (
                                            <div key={sem.id} className="flex items-center justify-between p-3 rounded-lg border border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                                                <div className="flex items-center gap-3">
                                                    <CalendarIcon className={`w-5 h-5 ${sem.is_active ? 'text-green-500' : 'text-gray-400'}`} />
                                                    <div>
                                                        <p className="font-medium">Semester {sem.semester_number} ({sem.name})</p>
                                                        <p className="text-xs text-gray-500">
                                                            {new Date(sem.start_date).toLocaleDateString('id-ID')} - {new Date(sem.end_date).toLocaleDateString('id-ID')}
                                                        </p>
                                                    </div>
                                                </div>
                                                <div className="flex items-center gap-2">
                                                    {sem.is_locked ? (
                                                        <div className="flex items-center gap-2 text-amber-600 text-sm mr-2 bg-amber-50 px-2 py-1 rounded">
                                                            <LockIcon className="w-3 h-3" /> Terkunci
                                                        </div>
                                                    ) : null}

                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        onClick={() => handleToggleLock(sem)}
                                                        title={sem.is_locked ? "Buka Kunci" : "Kunci Semester"}
                                                    >
                                                        {sem.is_locked ? <LockIcon className="w-4 h-4 text-amber-500" /> : <LockIcon className="w-4 h-4 text-gray-300" />}
                                                    </Button>

                                                    {sem.is_active ? (
                                                        <span className="flex items-center gap-1 px-3 py-1.5 bg-green-100 text-green-700 rounded-lg text-sm font-medium dark:bg-green-900/30 dark:text-green-400">
                                                            <CheckCircleIcon className="w-4 h-4" /> Aktif
                                                        </span>
                                                    ) : (
                                                        <Button
                                                            variant="outline"
                                                            size="sm"
                                                            onClick={() => handleActivateSemester(sem.id, year.id)}
                                                        >
                                                            Aktifkan
                                                        </Button>
                                                    )}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    ))
                )}
            </div>

            <div className="mt-6 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-sm text-blue-800 dark:text-blue-300 flex gap-2 items-start">
                <AlertCircleIcon className="w-5 h-5 shrink-0 mt-0.5" />
                <p>
                    <strong>Tips:</strong> Mengaktifkan semester akan otomatis mengubah semester aktif di seluruh aplikasi.
                    Data yang ditampilkan secara default akan mengikuti semester aktif ini.
                    Mengunci semester akan mencegah perubahan data pada semester tersebut.
                </p>
            </div>
        </SettingsCard>
    );
};

