// ============================================
// RETRY BUTTON WITH AUTO-RETRY
// ============================================

interface RetryButtonProps {
    onRetry: () => Promise<void>;
    maxRetries?: number;
    retryDelay?: number;
    className?: string;
    children?: React.ReactNode;
}

/**
 * Button with auto-retry logic and exponential backoff
 */
export const RetryButton: React.FC<RetryButtonProps> = ({
    onRetry,
    maxRetries = 3,
    retryDelay = 1000,
    className = '',
    children = 'Coba Lagi',
}) => {
    const [isRetrying, setIsRetrying] = useState(false);
    const [retryCount, setRetryCount] = useState(0);
    const [countdown, setCountdown] = useState(0);

    const handleRetry = useCallback(async () => {
        if (isRetrying) return;

        setIsRetrying(true);
        setRetryCount(prev => prev + 1);

        try {
            await onRetry();
            setRetryCount(0);
        } catch {
            if (retryCount < maxRetries - 1) {
                // Show countdown for next retry
                const delay = retryDelay * Math.pow(2, retryCount);
                let remaining = Math.ceil(delay / 1000);
                setCountdown(remaining);

                const interval = setInterval(() => {
                    remaining -= 1;
                    setCountdown(remaining);
                    if (remaining <= 0) {
                        clearInterval(interval);
                        handleRetry();
                    }
                }, 1000);
            }
        } finally {
            setIsRetrying(false);
        }
    }, [isRetrying, retryCount, maxRetries, retryDelay, onRetry]);

    return (
        <Button
            onClick={handleRetry}
            disabled={isRetrying || countdown > 0}
            className={className}
        >
            {isRetrying ? (
                <>
                    <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
                    Mencoba...
                </>
            ) : countdown > 0 ? (
                <>
                    <Clock className="w-4 h-4 mr-2" />
                    Coba lagi dalam {countdown}s
                </>
            ) : (
                <>
                    <RefreshCw className="w-4 h-4 mr-2" />
                    {children}
                    {retryCount > 0 && ` (${retryCount}/${maxRetries})`}
                </>
            )}
        </Button>
    );
};

