import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { SearchIcon, UsersIcon, GraduationCapIcon, BookOpenIcon, ClipboardListIcon, Loader2Icon, ClockIcon, XIcon } from 'lucide-react';
import { globalSearch, getSearchSuggestions, SearchResult, SearchEntityType } from '../../services/SearchService';

// Search history management
const SEARCH_HISTORY_KEY = 'portal_guru_search_history';
const MAX_HISTORY = 8;

const getSearchHistory = (): string[] => {
    try {
        return JSON.parse(localStorage.getItem(SEARCH_HISTORY_KEY) || '[]');
    } catch {
        return [];
    }
};

const addToSearchHistory = (query: string) => {
    if (!query.trim()) return;
    const history = getSearchHistory().filter(h => h !== query);
    history.unshift(query);
    localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(history.slice(0, MAX_HISTORY)));
};

const clearSearchHistory = () => {
    localStorage.removeItem(SEARCH_HISTORY_KEY);
};

// Entity type icons
const entityIcons: Record<SearchEntityType, React.ElementType> = {
    all: SearchIcon,
    students: UsersIcon,
    classes: GraduationCapIcon,
    tasks: ClipboardListIcon,
    schedules: BookOpenIcon,
    attendance: ClockIcon,
};

const entityLabels: Record<SearchEntityType, string> = {
    all: 'Semua',
    students: 'Siswa',
    classes: 'Kelas',
    tasks: 'Tugas',
    schedules: 'Jadwal',
    attendance: 'Absensi',
};

interface GlobalSearchProps {
    isOpen: boolean;
    setIsOpen: (isOpen: boolean) => void;
}

const GlobalSearch: React.FC<GlobalSearchProps> = ({ isOpen, setIsOpen }) => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchTerm, setSearchTerm] = useState('');
    const [activeIndex, setActiveIndex] = useState(0);
    const [activeTab, setActiveTab] = useState<SearchEntityType>('all');
    const [showHistory, setShowHistory] = useState(true);
    const inputRef = useRef<HTMLInputElement>(null);
    const resultsContainerRef = useRef<HTMLDivElement>(null);

    // Search results query
    const { data: searchResults = [], isLoading } = useQuery({
        queryKey: ['globalSearch', user?.id, searchTerm, activeTab],
        queryFn: () => globalSearch(user!.id, searchTerm, { entityType: activeTab, limit: 15 }),
        enabled: !!user && isOpen && searchTerm.trim().length >= 2,
        staleTime: 1000 * 30,
    });

    // Suggestions query
    const { data: suggestions = [] } = useQuery({
        queryKey: ['searchSuggestions', user?.id, searchTerm],
        queryFn: () => getSearchSuggestions(user!.id, searchTerm),
        enabled: !!user && isOpen && searchTerm.trim().length >= 1 && searchTerm.trim().length < 3,
        staleTime: 1000 * 60,
    });

    const searchHistory = useMemo(() => getSearchHistory(), [isOpen]);

    const handleNavigate = useCallback((result: SearchResult) => {
        addToSearchHistory(searchTerm);
        if (result.link) {
            navigate(result.link);
        }
        setIsOpen(false);
    }, [searchTerm, navigate, setIsOpen]);

    const handleHistoryClick = useCallback((query: string) => {
        setSearchTerm(query);
        setShowHistory(false);
        setActiveIndex(0);
    }, []);

    const handleSuggestionClick = useCallback((suggestion: string) => {
        setSearchTerm(suggestion);
        setActiveIndex(0);
    }, []);

    useEffect(() => {
        if (isOpen) {
            setTimeout(() => {
                inputRef.current?.focus();
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setShowHistory(true);
            }, 0);
        } else {
            setTimeout(() => {
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setSearchTerm('');
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setActiveIndex(0);
                // eslint-disable-next-line react-hooks/set-state-in-effect
                setActiveTab('all');
            }, 0);
        }
    }, [isOpen]);

    useEffect(() => {
        if (resultsContainerRef.current) {
            const activeElement = resultsContainerRef.current.querySelector(`[data-index="${activeIndex}"]`);
            if (activeElement) {
                activeElement.scrollIntoView({ block: 'nearest' });
            }
        }
    }, [activeIndex]);

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            setActiveIndex(prev => (prev + 1) % Math.max(searchResults.length, 1));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            setActiveIndex(prev => (prev - 1 + searchResults.length) % Math.max(searchResults.length, 1));
        } else if (e.key === 'Enter') {
            e.preventDefault();
            if (searchResults[activeIndex]) {
                handleNavigate(searchResults[activeIndex]);
            }
        } else if (e.key === 'Escape') {
            setIsOpen(false);
        }
    };

    const getResultIcon = (type: SearchEntityType) => {
        const Icon = entityIcons[type] || SearchIcon;
        return Icon;
    };

    if (!isOpen) return null;

    const showingSuggestions = searchTerm.length >= 1 && searchTerm.length < 3 && suggestions.length > 0;
    const showingResults = searchTerm.length >= 2 && searchResults.length > 0;
    const showingNoResults = searchTerm.length >= 2 && !isLoading && searchResults.length === 0;
    const showingHistory = showHistory && searchTerm.length === 0 && searchHistory.length > 0;

    return (
        <div
            className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm animate-fade-in"
            onClick={() => setIsOpen(false)}
        >
            <div
                className="bg-white dark:bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl mx-auto mt-[10vh] animate-fade-in-up flex flex-col overflow-hidden"
                onClick={e => e.stopPropagation()}
            >
                {/* Search Input */}
                <div className="relative" onKeyDown={handleKeyDown}>
                    <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-4">
                        {isLoading ? (
                            <Loader2Icon className="h-5 w-5 text-indigo-500 animate-spin" />
                        ) : (
                            <SearchIcon className="h-5 w-5 text-gray-400" />
                        )}
                    </div>
                    <input
                        ref={inputRef}
                        type="text"
                        placeholder="Cari siswa, kelas, tugas, atau jadwal..."
                        value={searchTerm}
                        onChange={(e) => { setSearchTerm(e.target.value); setShowHistory(false); setActiveIndex(0); }}
                        className="w-full h-14 bg-transparent pl-12 pr-12 text-base md:text-lg border-b border-gray-200 dark:border-gray-700 focus:outline-none"
                        aria-label="Kotak Pencarian Global"
                    />
                    {searchTerm && (
                        <button
                            onClick={() => { setSearchTerm(''); setActiveIndex(0); }}
                            className="absolute inset-y-0 right-0 flex items-center pr-4 text-gray-400 hover:text-gray-600"
                        >
                            <XIcon className="h-5 w-5" />
                        </button>
                    )}
                </div>

                {/* Entity Type Tabs */}
                {searchTerm.length >= 2 && (
                    <div className="flex gap-1 px-4 py-2 border-b border-gray-200 dark:border-gray-700 overflow-x-auto scrollbar-hide">
                        {(['all', 'students', 'classes', 'tasks', 'schedules'] as SearchEntityType[]).map(type => (
                            <button
                                key={type}
                                onClick={() => { setActiveTab(type); setActiveIndex(0); }}
                                className={`px-3 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${activeTab === type
                                        ? 'bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300'
                                        : 'text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800'
                                    }`}
                            >
                                {entityLabels[type]}
                            </button>
                        ))}
                    </div>
                )}

                {/* Results Container */}
                <div className="p-2 md:p-4 max-h-[50vh] overflow-y-auto" ref={resultsContainerRef}>
                    {/* Search History */}
                    {showingHistory && (
                        <div className="space-y-2">
                            <div className="flex items-center justify-between px-2">
                                <span className="text-xs font-medium text-gray-500 dark:text-gray-400">Pencarian Terakhir</span>
                                <button
                                    onClick={() => { clearSearchHistory(); setShowHistory(false); }}
                                    className="text-xs text-red-500 hover:text-red-600"
                                >
                                    Hapus Semua
                                </button>
                            </div>
                            <div className="space-y-1">
                                {searchHistory.map((query, index) => (
                                    <button
                                        key={index}
                                        onClick={() => handleHistoryClick(query)}
                                        className="flex items-center gap-3 w-full p-3 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors text-left"
                                    >
                                        <ClockIcon className="w-4 h-4 text-gray-400" />
                                        <span className="text-sm text-gray-700 dark:text-gray-300">{query}</span>
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Suggestions */}
                    {showingSuggestions && (
                        <div className="space-y-1">
                            <span className="text-xs font-medium text-gray-500 dark:text-gray-400 px-2">Saran</span>
                            {suggestions.map((suggestion, index) => (
                                <button
                                    key={index}
                                    onClick={() => handleSuggestionClick(suggestion)}
                                    className="flex items-center gap-3 w-full p-3 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors text-left"
                                >
                                    <SearchIcon className="w-4 h-4 text-gray-400" />
                                    <span className="text-sm text-gray-700 dark:text-gray-300">{suggestion}</span>
                                </button>
                            ))}
                        </div>
                    )}

                    {/* Search Results */}
                    {showingResults && (
                        <div className="space-y-1">
                            {searchResults.map((result, index) => {
                                const isActive = index === activeIndex;
                                const Icon = getResultIcon(result.type);

                                return (
                                    <button
                                        key={`${result.type}-${result.id}`}
                                        onClick={() => handleNavigate(result)}
                                        className={`flex items-center gap-4 w-full p-3 rounded-lg cursor-pointer transition-colors text-left ${isActive ? 'bg-indigo-50 dark:bg-indigo-900/20' : 'hover:bg-gray-100 dark:hover:bg-gray-800'
                                            }`}
                                        data-index={index}
                                    >
                                        <div className={`flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center ${isActive ? 'bg-indigo-100 dark:bg-indigo-900/40' : 'bg-gray-100 dark:bg-gray-700/50'
                                            }`}>
                                            <Icon className={`w-5 h-5 ${isActive ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-500 dark:text-gray-400'}`} />
                                        </div>
                                        <div className="flex-1 overflow-hidden">
                                            <p className={`font-semibold truncate ${isActive ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-800 dark:text-gray-200'}`}>
                                                {result.title}
                                            </p>
                                            <div className="flex items-center gap-2">
                                                <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{result.subtitle}</p>
                                                {result.description && (
                                                    <>
                                                        <span className="text-gray-300 dark:text-gray-600">ΓÇó</span>
                                                        <p className="text-xs text-gray-400 dark:text-gray-500 truncate">{result.description}</p>
                                                    </>
                                                )}
                                            </div>
                                        </div>
                                        <div className="flex-shrink-0">
                                            <span className={`text-xs px-2 py-1 rounded-full ${isActive
                                                    ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 dark:text-indigo-400'
                                                    : 'bg-gray-100 dark:bg-gray-800 text-gray-500'
                                                }`}>
                                                {entityLabels[result.type]}
                                            </span>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    )}

                    {/* No Results */}
                    {showingNoResults && (
                        <div className="text-center py-12 text-gray-500">
                            <SearchIcon className="w-12 h-12 mx-auto text-gray-300 dark:text-gray-600 mb-4" />
                            <p className="font-semibold">Tidak ada hasil ditemukan</p>
                            <p className="text-sm mt-1">Coba kata kunci yang berbeda atau filter lain.</p>
                        </div>
                    )}

                    {/* Loading State */}
                    {isLoading && searchTerm.length >= 2 && (
                        <div className="flex items-center justify-center py-12">
                            <Loader2Icon className="w-8 h-8 text-indigo-500 animate-spin" />
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="px-4 py-2 bg-gray-50 dark:bg-gray-800/50 border-t border-gray-200 dark:border-gray-700 text-xs text-gray-500 dark:text-gray-400 flex items-center justify-between">
                    <div>
                        Gunakan <kbd className="font-sans rounded bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5">Γåæ</kbd> <kbd className="font-sans rounded bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5">Γåô</kbd> untuk navigasi, <kbd className="font-sans rounded bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5">Enter</kbd> untuk memilih.
                    </div>
                    <div className="text-gray-400">
                        <kbd className="font-sans rounded bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5">Esc</kbd> untuk menutup
                    </div>
                </div>
            </div>
        </div>
    );
};

export default GlobalSearch;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { CameraIcon, TrashIcon, XCircleIcon, CheckIcon, AlertCircleIcon } from '../Icons';
import { Button } from './Button';
import { Modal } from './Modal';

// Icons needed but might not exist - using available ones
const RotateCwIcon = ({ className }: { className?: string }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M21 12a9 9 0 1 1-9-9c2.52 0 4.93 1 6.74 2.74L21 8" />
        <path d="M21 3v5h-5" />
    </svg>
);

const CropIcon = ({ className }: { className?: string }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M6 2v14a2 2 0 0 0 2 2h14" />
        <path d="M18 22V8a2 2 0 0 0-2-2H2" />
    </svg>
);

export interface ImageUploadConfig {
    maxFileSize?: number; // in MB, default 5MB
    maxWidth?: number; // default 800px
    maxHeight?: number; // default 800px
    quality?: number; // 0-1, default 0.85
    aspectRatio?: number; // width/height, e.g. 1 for square
    allowedTypes?: string[]; // default ['image/jpeg', 'image/png', 'image/webp']
    circularCrop?: boolean; // default false
}

interface ImageUploaderProps {
    currentImageUrl?: string;
    onUpload: (file: File) => Promise<void>;
    onDelete?: () => Promise<void>;
    config?: ImageUploadConfig;
    disabled?: boolean;
    size?: 'sm' | 'md' | 'lg';
    className?: string;
    label?: string;
    showDeleteButton?: boolean;
}

interface CropArea {
    x: number;
    y: number;
    width: number;
    height: number;
}

const DEFAULT_CONFIG: Required<ImageUploadConfig> = {
    maxFileSize: 5, // 5MB
    maxWidth: 800,
    maxHeight: 800,
    quality: 0.85,
    aspectRatio: 1,
    allowedTypes: ['image/jpeg', 'image/png', 'image/webp'],
    circularCrop: false
};

const SIZE_CLASSES = {
    sm: 'w-20 h-20',
    md: 'w-32 h-32',
    lg: 'w-40 h-40'
};

/**
 * ImageUploader Component
 * 
 * A comprehensive image upload component with:
 * - Preview before upload
 * - Crop/resize functionality
 * - File size validation
 * - Loading indicators
 * - Delete option
 */
export const ImageUploader: React.FC<ImageUploaderProps> = ({
    currentImageUrl,
    onUpload,
    onDelete,
    config = {},
    disabled = false,
    size = 'md',
    className = '',
    label = 'Upload Foto',
    showDeleteButton = true
}) => {
    const mergedConfig = { ...DEFAULT_CONFIG, ...config };
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [showCropModal, setShowCropModal] = useState(false);
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);

    // Crop state
    const [zoom, setZoom] = useState(1);
    const [rotation, setRotation] = useState(0);
    const [cropArea, setCropArea] = useState<CropArea>({ x: 0, y: 0, width: 100, height: 100 });
    const [isDragging, setIsDragging] = useState(false);
    const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
    const [position, setPosition] = useState({ x: 0, y: 0 });

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const imageRef = useRef<HTMLImageElement | null>(null);
    const cropContainerRef = useRef<HTMLDivElement>(null);

    // Cleanup preview URL on unmount
    useEffect(() => {
        return () => {
            if (previewUrl) {
                URL.revokeObjectURL(previewUrl);
            }
        };
    }, [previewUrl]);

    const validateFile = (file: File): string | null => {
        // Check file type
        if (!mergedConfig.allowedTypes.includes(file.type)) {
            return `Tipe file tidak didukung. Gunakan: ${mergedConfig.allowedTypes.map(t => t.split('/')[1].toUpperCase()).join(', ')}`;
        }

        // Check file size
        const fileSizeMB = file.size / (1024 * 1024);
        if (fileSizeMB > mergedConfig.maxFileSize) {
            return `Ukuran file terlalu besar. Maksimal ${mergedConfig.maxFileSize}MB (file Anda: ${fileSizeMB.toFixed(2)}MB)`;
        }

        return null;
    };

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setError(null);

        // Validate file
        const validationError = validateFile(file);
        if (validationError) {
            setError(validationError);
            return;
        }

        // Create preview and open crop modal
        const url = URL.createObjectURL(file);
        setPreviewUrl(url);
        setSelectedFile(file);
        setShowCropModal(true);
        setZoom(1);
        setRotation(0);
        setPosition({ x: 0, y: 0 });

        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();

        const file = e.dataTransfer.files[0];
        if (file && file.type.startsWith('image/')) {
            const validationError = validateFile(file);
            if (validationError) {
                setError(validationError);
                return;
            }

            const url = URL.createObjectURL(file);
            setPreviewUrl(url);
            setSelectedFile(file);
            setShowCropModal(true);
            setZoom(1);
            setRotation(0);
            setPosition({ x: 0, y: 0 });
        }
    };

    // Mouse/touch handlers for crop dragging
    const handleMouseDown = (e: React.MouseEvent) => {
        setIsDragging(true);
        setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
    };

    const handleMouseMove = useCallback((e: MouseEvent) => {
        if (!isDragging) return;
        setPosition({
            x: e.clientX - dragStart.x,
            y: e.clientY - dragStart.y
        });
    }, [isDragging, dragStart]);

    const handleMouseUp = useCallback(() => {
        setIsDragging(false);
    }, []);

    useEffect(() => {
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
            return () => {
                window.removeEventListener('mousemove', handleMouseMove);
                window.removeEventListener('mouseup', handleMouseUp);
            };
        }
    }, [isDragging, handleMouseMove, handleMouseUp]);

    const processAndUpload = async () => {
        if (!selectedFile || !previewUrl) return;

        setIsLoading(true);
        setError(null);

        try {
            // Create canvas for processing
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (!ctx) throw new Error('Could not get canvas context');

            const img = new Image();
            img.crossOrigin = 'anonymous';

            await new Promise<void>((resolve, reject) => {
                img.onload = () => resolve();
                img.onerror = reject;
                img.src = previewUrl;
            });

            // Calculate output dimensions
            const outputSize = Math.min(mergedConfig.maxWidth, mergedConfig.maxHeight);
            canvas.width = outputSize;
            canvas.height = outputSize / mergedConfig.aspectRatio;

            // Apply transformations
            ctx.save();
            ctx.translate(canvas.width / 2, canvas.height / 2);
            ctx.rotate((rotation * Math.PI) / 180);
            ctx.scale(zoom, zoom);
            ctx.translate(-canvas.width / 2, -canvas.height / 2);

            // Calculate source area based on position
            const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * zoom;
            const scaledWidth = img.width * scale;
            const scaledHeight = img.height * scale;
            const offsetX = (canvas.width - scaledWidth) / 2 + position.x;
            const offsetY = (canvas.height - scaledHeight) / 2 + position.y;

            ctx.drawImage(img, offsetX, offsetY, scaledWidth, scaledHeight);
            ctx.restore();

            // Convert to blob
            const blob = await new Promise<Blob>((resolve, reject) => {
                canvas.toBlob(
                    (blob) => {
                        if (blob) resolve(blob);
                        else reject(new Error('Failed to create blob'));
                    },
                    'image/jpeg',
                    mergedConfig.quality
                );
            });

            // Create file from blob
            const processedFile = new File([blob], selectedFile.name.replace(/\.[^/.]+$/, '.jpg'), {
                type: 'image/jpeg'
            });

            await onUpload(processedFile);
            setShowCropModal(false);
            setSelectedFile(null);
            if (previewUrl) {
                URL.revokeObjectURL(previewUrl);
                setPreviewUrl(null);
            }
        } catch (err: any) {
            setError(err.message || 'Gagal memproses gambar');
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async () => {
        if (!onDelete) return;

        setIsLoading(true);
        setError(null);

        try {
            await onDelete();
        } catch (err: any) {
            setError(err.message || 'Gagal menghapus foto');
        } finally {
            setIsLoading(false);
        }
    };

    const handleCancelCrop = () => {
        setShowCropModal(false);
        setSelectedFile(null);
        if (previewUrl) {
            URL.revokeObjectURL(previewUrl);
            setPreviewUrl(null);
        }
    };

    return (
        <>
            <div className={`relative ${className}`}>
                {/* Main Upload Area */}
                <div
                    className={`
                        relative group ${SIZE_CLASSES[size]} 
                        rounded-full overflow-hidden
                        border-4 border-white dark:border-slate-800
                        shadow-lg transition-all duration-300
                        ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer hover:shadow-xl'}
                    `}
                    onClick={() => !disabled && fileInputRef.current?.click()}
                    onDragOver={handleDragOver}
                    onDrop={handleDrop}
                >
                    {/* Current Image or Placeholder */}
                    {currentImageUrl ? (
                        <img
                            src={currentImageUrl}
                            alt="Avatar"
                            className="w-full h-full object-cover"
                        />
                    ) : (
                        <div className="w-full h-full bg-gradient-to-br from-slate-200 to-slate-300 dark:from-slate-700 dark:to-slate-800 flex items-center justify-center">
                            <CameraIcon className="w-8 h-8 text-slate-400 dark:text-slate-500" />
                        </div>
                    )}

                    {/* Hover Overlay */}
                    <div className={`
                        absolute inset-0 bg-black/50 flex flex-col items-center justify-center
                        transition-opacity duration-300
                        ${disabled ? 'hidden' : 'opacity-0 group-hover:opacity-100'}
                    `}>
                        <CameraIcon className="w-6 h-6 text-white mb-1" />
                        <span className="text-xs text-white font-medium">{label}</span>
                    </div>

                    {/* Loading Overlay */}
                    {isLoading && (
                        <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center">
                            <div className="w-8 h-8 border-3 border-white border-t-transparent rounded-full animate-spin mb-2" />
                            <span className="text-xs text-white">Mengunggah...</span>
                        </div>
                    )}
                </div>

                {/* Hidden File Input */}
                <input
                    ref={fileInputRef}
                    type="file"
                    accept={mergedConfig.allowedTypes.join(',')}
                    onChange={handleFileSelect}
                    className="hidden"
                    disabled={disabled || isLoading}
                />

                {/* Delete Button */}
                {showDeleteButton && currentImageUrl && onDelete && !isLoading && (
                    <button
                        onClick={(e) => {
                            e.stopPropagation();
                            handleDelete();
                        }}
                        disabled={disabled}
                        className="absolute -top-1 -right-1 p-1.5 bg-red-500 text-white rounded-full shadow-lg hover:bg-red-600 transition-colors"
                        title="Hapus foto"
                    >
                        <TrashIcon className="w-3.5 h-3.5" />
                    </button>
                )}

                {/* Error Message */}
                {error && (
                    <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 whitespace-nowrap">
                        <div className="flex items-center gap-1 text-xs text-red-500 bg-red-50 dark:bg-red-900/20 px-2 py-1 rounded-full">
                            <AlertCircleIcon className="w-3 h-3" />
                            <span className="max-w-[200px] truncate">{error}</span>
                        </div>
                    </div>
                )}

                {/* File Size Info */}
                <div className="text-center mt-2 text-xs text-slate-400 dark:text-slate-500">
                    Maks. {mergedConfig.maxFileSize}MB
                </div>
            </div>

            {/* Crop Modal */}
            <Modal
                isOpen={showCropModal}
                onClose={handleCancelCrop}
                title="Edit Foto"
            >
                <div className="space-y-6">
                    {/* Preview Area */}
                    <div
                        ref={cropContainerRef}
                        className="relative w-full h-80 bg-slate-900 rounded-2xl overflow-hidden cursor-move"
                        onMouseDown={handleMouseDown}
                    >
                        {previewUrl && (
                            <div
                                className="absolute inset-0 flex items-center justify-center"
                                style={{
                                    transform: `translate(${position.x}px, ${position.y}px) scale(${zoom}) rotate(${rotation}deg)`
                                }}
                            >
                                <img
                                    src={previewUrl}
                                    alt="Preview"
                                    className="max-w-full max-h-full object-contain pointer-events-none"
                                    draggable={false}
                                />
                            </div>
                        )}

                        {/* Crop Overlay */}
                        <div className="absolute inset-0 pointer-events-none">
                            {/* Dark overlay with circular cutout */}
                            <div className="absolute inset-0 flex items-center justify-center">
                                <div
                                    className={`
                                        w-64 h-64 border-2 border-white/80 shadow-[0_0_0_9999px_rgba(0,0,0,0.6)]
                                        ${mergedConfig.circularCrop ? 'rounded-full' : 'rounded-lg'}
                                    `}
                                />
                            </div>
                        </div>

                        {/* Drag instruction */}
                        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/50 text-white text-xs px-3 py-1.5 rounded-full">
                            Seret untuk mengatur posisi
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="flex flex-wrap items-center justify-center gap-4">
                        {/* Zoom Control */}
                        <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 rounded-xl p-2">
                            <button
                                onClick={() => setZoom(Math.max(0.5, zoom - 0.1))}
                                className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                                title="Perkecil"
                            >
                                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                                </svg>
                            </button>
                            <span className="text-sm font-medium w-12 text-center">{Math.round(zoom * 100)}%</span>
                            <button
                                onClick={() => setZoom(Math.min(3, zoom + 0.1))}
                                className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                                title="Perbesar"
                            >
                                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                                </svg>
                            </button>
                        </div>

                        {/* Rotation Control */}
                        <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 rounded-xl p-2">
                            <button
                                onClick={() => setRotation(rotation - 90)}
                                className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                                title="Putar kiri"
                            >
                                <RotateCwIcon className="w-4 h-4 transform -scale-x-100" />
                            </button>
                            <span className="text-sm font-medium w-10 text-center">{rotation}┬░</span>
                            <button
                                onClick={() => setRotation(rotation + 90)}
                                className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                                title="Putar kanan"
                            >
                                <RotateCwIcon className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Reset Button */}
                        <button
                            onClick={() => {
                                setZoom(1);
                                setRotation(0);
                                setPosition({ x: 0, y: 0 });
                            }}
                            className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors"
                        >
                            Reset
                        </button>
                    </div>

                    {/* Selected File Info */}
                    {selectedFile && (
                        <div className="flex items-center justify-center gap-4 text-sm text-slate-500 dark:text-slate-400">
                            <span>{selectedFile.name}</span>
                            <span>ΓÇó</span>
                            <span>{(selectedFile.size / (1024 * 1024)).toFixed(2)} MB</span>
                        </div>
                    )}

                    {/* Action Buttons */}
                    <div className="flex justify-end gap-3 pt-4 border-t border-slate-200 dark:border-slate-700">
                        <Button
                            variant="outline"
                            onClick={handleCancelCrop}
                            disabled={isLoading}
                        >
                            <XCircleIcon className="w-4 h-4 mr-2" />
                            Batal
                        </Button>
                        <Button
                            onClick={processAndUpload}
                            disabled={isLoading}
                            className="bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700"
                        >
                            {isLoading ? (
                                <>
                                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2" />
                                    Mengunggah...
                                </>
                            ) : (
                                <>
                                    <CheckIcon className="w-4 h-4 mr-2" />
                                    Simpan & Unggah
                                </>
                            )}
                        </Button>
                    </div>
                </div>
            </Modal>
        </>
    );
};

export default ImageUploader;

import React, { useState, useRef, useMemo } from 'react';
import { Modal } from './Modal';
import { Button } from './Button';
import {
    FileSpreadsheetIcon,
    AlertTriangleIcon,
    CheckCircleIcon,
    XCircleIcon,
    DownloadIcon,
    RefreshCwIcon,
    ArrowRightIcon
} from 'lucide-react';
import {
    parseFile,
    autoDetectMappings,
    parseAndValidate,
    downloadTemplate,
    ColumnMapping,
    ParsedRow,
    STUDENT_FIELDS
} from '../../services/ImportService';
import { Select } from './Select';

interface ImportModalProps {
    isOpen: boolean;
    onClose: () => void;
    onImport: (validRows: ParsedRow[]) => Promise<void>;
    title?: string;
}

type ImportStep = 'upload' | 'mapping' | 'preview' | 'importing' | 'complete';

export const ImportModal: React.FC<ImportModalProps> = ({
    isOpen,
    onClose,
    onImport,
    title = 'Import Data Siswa'
}) => {
    const [step, setStep] = useState<ImportStep>('upload');
    const [file, setFile] = useState<File | null>(null);
    const [headers, setHeaders] = useState<string[]>([]);
    const [rows, setRows] = useState<any[][]>([]);
    const [mappings, setMappings] = useState<ColumnMapping[]>([]);
    const [parsedRows, setParsedRows] = useState<ParsedRow[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [importResult, setImportResult] = useState<{ success: number; failed: number } | null>(null);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const resetState = () => {
        setStep('upload');
        setFile(null);
        setHeaders([]);
        setRows([]);
        setMappings([]);
        setParsedRows([]);
        setIsProcessing(false);
        setImportResult(null);
        setError(null);
    };

    const handleClose = () => {
        resetState();
        onClose();
    };

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        setIsProcessing(true);
        setError(null);

        try {
            const { headers: parsedHeaders, rows: parsedRows } = await parseFile(selectedFile);
            setFile(selectedFile);
            setHeaders(parsedHeaders);
            setRows(parsedRows);

            // Auto-detect mappings
            const detectedMappings = autoDetectMappings(parsedHeaders);
            setMappings(detectedMappings);

            setStep('mapping');
        } catch (err: any) {
            setError(err.message);
        } finally {
            setIsProcessing(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const handleMappingChange = (targetField: string, sourceColumn: string) => {
        setMappings(prev => {
            // Remove existing mapping for this target
            const filtered = prev.filter(m => m.targetField !== targetField);

            if (sourceColumn) {
                const fieldInfo = STUDENT_FIELDS.find(f => f.key === targetField);
                filtered.push({
                    sourceColumn,
                    targetField,
                    required: fieldInfo?.required || false,
                });
            }

            return filtered;
        });
    };

    const handlePreview = () => {
        const validated = parseAndValidate(headers, rows, mappings);
        setParsedRows(validated);
        setStep('preview');
    };

    const handleImport = async () => {
        const validRows = parsedRows.filter(r => r.isValid);
        if (validRows.length === 0) return;

        setStep('importing');
        setIsProcessing(true);

        try {
            await onImport(validRows);
            setImportResult({
                success: validRows.length,
                failed: parsedRows.length - validRows.length
            });
            setStep('complete');
        } catch (err: any) {
            setError(err.message);
            setStep('preview');
        } finally {
            setIsProcessing(false);
        }
    };

    const validCount = useMemo(() => parsedRows.filter(r => r.isValid).length, [parsedRows]);
    const invalidCount = useMemo(() => parsedRows.filter(r => !r.isValid).length, [parsedRows]);

    const renderUploadStep = () => (
        <div className="space-y-6">
            {/* Drop Zone */}
            <div
                className="border-2 border-dashed border-slate-300 dark:border-slate-700 rounded-2xl p-8 text-center hover:border-emerald-400 dark:hover:border-emerald-600 transition-all cursor-pointer bg-slate-50 dark:bg-slate-900/50 focus-within:ring-2 focus-within:ring-emerald-500/60 focus-within:ring-offset-2 focus-within:ring-offset-white dark:focus-within:ring-offset-slate-900 active:scale-[0.99]"
                onClick={() => fileInputRef.current?.click()}
            >
                <FileSpreadsheetIcon className="w-16 h-16 mx-auto text-slate-400 dark:text-slate-600 mb-4" />
                <p className="text-lg font-medium text-slate-700 dark:text-slate-300 mb-2">
                    Klik untuk memilih file
                </p>
                <p className="text-sm text-slate-500 dark:text-slate-400">
                    Format yang didukung: .xlsx, .xls, .csv
                </p>
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileSelect}
                    accept=".xlsx,.xls,.csv"
                    className="hidden"
                />
            </div>

            {error && (
                <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl flex items-start gap-3">
                    <AlertTriangleIcon className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                    <p className="text-sm text-red-700 dark:text-red-300">{error}</p>
                </div>
            )}

            {/* Template Download */}
            <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 rounded-xl">
                <div className="flex items-start gap-3">
                    <DownloadIcon className="w-5 h-5 text-indigo-600 dark:text-indigo-400 flex-shrink-0 mt-0.5" />
                    <div className="flex-1">
                        <p className="text-sm font-medium text-indigo-800 dark:text-indigo-300 mb-2">
                            Butuh template?
                        </p>
                        <div className="flex gap-2">
                            <Button
                                size="sm"
                                variant="outline"
                                onClick={() => downloadTemplate('xlsx')}
