    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
} from 'recharts';
import { TrendingUpIcon, TrendingDownIcon, MinusIcon, DownloadIcon } from 'lucide-react';
import { getHtml2Canvas, getJsPDF } from '../../utils/dynamicImports';

interface AttendanceTrendData {
