                    >
                        <DownloadIcon className="w-4 h-4 text-slate-600 dark:text-slate-400" />
                    </button>
                    <button
                        onClick={() => exportToPDF(chartDomId, 'attendance-trend')}
                        className="px-3 py-1.5 rounded-lg bg-indigo-100 dark:bg-indigo-900/30 hover:bg-indigo-200 dark:hover:bg-indigo-900/50 text-indigo-700 dark:text-indigo-300 text-xs font-medium transition-colors"
                        aria-label="Export chart to PDF"
                    >
                        PDF
                    </button>
                </div>
            </div>

            {/* Interactive Chart */}
            <ResponsiveContainer width="100%" height={250}>
                <LineChart
                    data={data}
                    margin={{ top: 5, right: 30, left: 0, bottom: 5 }}
                    onMouseMove={(state) => {
                        if (state.activeTooltipIndex !== undefined && typeof state.activeTooltipIndex === 'number') {
                            setHoveredPoint(state.activeTooltipIndex);
                        }
                    }}
                    onMouseLeave={() => setHoveredPoint(null)}
                >
                    <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" opacity={0.3} />
                    <XAxis
                        dataKey="label"
                        stroke="#94a3b8"
                        style={{ fontSize: '12px' }}
                    />
                    <YAxis
                        stroke="#94a3b8"
                        style={{ fontSize: '12px' }}
                        domain={[0, 100]}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend />
                    <Line
                        type="monotone"
                        dataKey="percentage"
                        name="Kehadiran"
                        stroke="#6366f1"
                        strokeWidth={3}
                        dot={{
                            fill: '#6366f1',
                            strokeWidth: 2,
                            r: 5,
                            cursor: 'pointer',
                        }}
                        activeDot={{
                            r: 8,
                            fill: '#6366f1',
                            stroke: '#fff',
                            strokeWidth: 2,
                        }}
                    />
                </LineChart>
            </ResponsiveContainer>
        </div>
    );
};

