interface LazyImageProps extends Omit<React.ImgHTMLAttributes<HTMLImageElement>, 'src'> {
    src: string;
    fallback?: string;
    placeholder?: React.ReactNode;
    threshold?: number;
    onLoad?: () => void;
    onError?: () => void;
}

/**
 * Lazy loading image with intersection observer
 */
export const LazyImage = memo<LazyImageProps>(({
    src,
    fallback = '/placeholder.png',
    placeholder,
    threshold = 0.1,
    onLoad,
    onError,
    className = '',
    alt = '',
    ...props
}) => {
    const [isLoaded, setIsLoaded] = useState(false);
    const [hasError, setHasError] = useState(false);
    const [isInView, setIsInView] = useState(false);
    const imgRef = useRef<HTMLImageElement>(null);

    useEffect(() => {
        if (!imgRef.current) return;

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsInView(true);
                    observer.disconnect();
                }
            },
            { threshold }
        );

        observer.observe(imgRef.current);

        return () => observer.disconnect();
    }, [threshold]);

    const handleLoad = () => {
        setIsLoaded(true);
        onLoad?.();
    };

    const handleError = () => {
        setHasError(true);
        onError?.();
    };

    const imageSrc = hasError ? fallback : (isInView ? src : '');

    return (
        <div className={`relative overflow-hidden ${className}`} ref={imgRef as React.RefObject<HTMLDivElement>}>
            {/* Placeholder */}
            {!isLoaded && (
                <div className="absolute inset-0 flex items-center justify-center bg-slate-100 dark:bg-slate-800">
                    {placeholder || (
                        <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 animate-pulse" />
                    )}
                </div>
            )}

            {/* Image */}
            {isInView && (
                <img
                    src={imageSrc}
                    alt={alt}
                    className={`w-full h-full object-cover transition-opacity duration-300 ${isLoaded ? 'opacity-100' : 'opacity-0'
                        }`}
                    onLoad={handleLoad}
                    onError={handleError}
                    loading="lazy"
                    {...props}
                />
            )}
        </div>
    );
});

LazyImage.displayName = 'LazyImage';

// ============================================
// INTERSECTION OBSERVER HOOK
// ============================================

interface UseIntersectionOptions {
    threshold?: number | number[];
    rootMargin?: string;
    triggerOnce?: boolean;
}

/**
 * Hook for intersection observer
 */
export function useIntersection<T extends Element>(
    options: UseIntersectionOptions = {}
): [React.RefObject<T>, boolean] {
    const { threshold = 0, rootMargin = '0px', triggerOnce = false } = options;
    const ref = useRef<T>(null);
    const [isIntersecting, setIsIntersecting] = useState(false);

    useEffect(() => {
        const element = ref.current;
        if (!element) return;

        const observer = new IntersectionObserver(
            ([entry]) => {
                const isVisible = entry.isIntersecting;
                setIsIntersecting(isVisible);

                if (isVisible && triggerOnce) {
                    observer.disconnect();
                }
            },
            { threshold, rootMargin }
        );

        observer.observe(element);

        return () => observer.disconnect();
    }, [threshold, rootMargin, triggerOnce]);

    return [ref, isIntersecting];
}

// ============================================
// DEBOUNCE & THROTTLE HOOKS
// ============================================

/**
 * Debounced value hook
 */
export function useDebounce<T>(value: T, delay: number): T {
    const [debouncedValue, setDebouncedValue] = useState(value);

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);

        return () => clearTimeout(timer);
    }, [value, delay]);

    return debouncedValue;
}

/**
 * Debounced callback hook
 */
export function useDebouncedCallback<T extends (...args: Parameters<T>) => ReturnType<T>>(
    callback: T,
    delay: number
): T {
    const timeoutRef = useRef<ReturnType<typeof setTimeout>>();

    const debouncedCallback = useCallback(
        (...args: Parameters<T>) => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }

            timeoutRef.current = setTimeout(() => {
                callback(...args);
            }, delay);
        },
        [callback, delay]
    ) as T;

    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    return debouncedCallback;
}

/**
 * Throttled callback hook
 */
export function useThrottledCallback<T extends (...args: Parameters<T>) => ReturnType<T>>(
    callback: T,
    delay: number
): T {
    const lastRan = useRef(0);
    const timeoutRef = useRef<ReturnType<typeof setTimeout>>();

    const throttledCallback = useCallback(
        (...args: Parameters<T>) => {
            const now = Date.now();
            const remaining = delay - (now - lastRan.current);

            if (remaining <= 0) {
                lastRan.current = now;
                callback(...args);
            } else if (!timeoutRef.current) {
                timeoutRef.current = setTimeout(() => {
                    lastRan.current = Date.now();
                    timeoutRef.current = undefined;
                    callback(...args);
                }, remaining);
            }
        },
        [callback, delay]
    ) as T;

    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    return throttledCallback;
}

// ============================================
// INFINITE SCROLL
// ============================================

interface UseInfiniteScrollOptions {
    threshold?: number;
    rootMargin?: string;
    enabled?: boolean;
}

/**
 * Infinite scroll hook
 */
export function useInfiniteScroll(
    onLoadMore: () => void,
    options: UseInfiniteScrollOptions = {}
): React.RefObject<HTMLDivElement> {
    const { threshold = 0, rootMargin = '100px', enabled = true } = options;
    const sentinelRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!enabled || !sentinelRef.current) return;

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    onLoadMore();
                }
            },
            { threshold, rootMargin }
        );

        observer.observe(sentinelRef.current);

        return () => observer.disconnect();
    }, [onLoadMore, threshold, rootMargin, enabled]);

    return sentinelRef;
}

