// ============================================
// NETWORK STATUS HOOK
// ============================================

interface NetworkStatus {
    online: boolean;
    effectiveType: 'slow-2g' | '2g' | '3g' | '4g' | 'unknown';
    downlink: number;
    rtt: number;
    quality: 'poor' | 'fair' | 'good' | 'excellent';
}

export const useNetworkStatus = (): NetworkStatus => {
    const [status, setStatus] = useState<NetworkStatus>({
        online: typeof navigator !== 'undefined' ? navigator.onLine : true,
        effectiveType: 'unknown',
        downlink: 10,
        rtt: 50,
        quality: 'good',
    });

    useEffect(() => {
        const updateNetworkStatus = () => {
            const connection = (navigator as any).connection ||
                (navigator as any).mozConnection ||
                (navigator as any).webkitConnection;

            let effectiveType: NetworkStatus['effectiveType'] = 'unknown';
            let downlink = 10;
            let rtt = 50;

            if (connection) {
                effectiveType = connection.effectiveType || 'unknown';
                downlink = connection.downlink || 10;
                rtt = connection.rtt || 50;
            }

            // Calculate quality
            let quality: NetworkStatus['quality'] = 'good';
            if (!navigator.onLine) {
                quality = 'poor';
            } else if (effectiveType === 'slow-2g' || effectiveType === '2g' || rtt > 500) {
                quality = 'poor';
            } else if (effectiveType === '3g' || rtt > 200) {
                quality = 'fair';
            } else if (downlink >= 10 && rtt < 100) {
                quality = 'excellent';
            }

            setStatus({
                online: navigator.onLine,
                effectiveType,
                downlink,
                rtt,
                quality,
            });
        };

        updateNetworkStatus();

        window.addEventListener('online', updateNetworkStatus);
        window.addEventListener('offline', updateNetworkStatus);

        const connection = (navigator as any).connection;
        if (connection) {
            connection.addEventListener('change', updateNetworkStatus);
        }

        // Periodic check
        const interval = setInterval(updateNetworkStatus, 30000);

        return () => {
            window.removeEventListener('online', updateNetworkStatus);
            window.removeEventListener('offline', updateNetworkStatus);
            if (connection) {
                connection.removeEventListener('change', updateNetworkStatus);
            }
            clearInterval(interval);
        };
    }, []);

    return status;
};

