                    {!error && hint && (
                        <p className="text-xs text-slate-500">{hint}</p>
                    )}
                </div>
                {showCharCount && props.maxLength && (
                    <CharacterCounter
                        current={value.length}
                        max={props.maxLength}
                        min={minLength}
                    />
                )}
            </div>
        </div>
    );
};

