        }
    };

    const handleMouseLeave = () => {
        context?.setTooltip(null);
    };

    return (
        <div
            ref={barRef}
            className={`group ${onClick ? 'cursor-pointer' : ''}`}
            onClick={onClick}
            onMouseEnter={handleMouseEnter}
