// ============================================
// SESSION TIMEOUT PROVIDER
// ============================================

interface SessionTimeoutProviderProps {
    children: React.ReactNode;
    timeoutMs?: number;
    warningMs?: number;
    onTimeout: () => void;
    enabled?: boolean;
}

/**
 * Provider component that monitors session timeout
 */
export const SessionTimeoutProvider: React.FC<SessionTimeoutProviderProps> = ({
    children,
    timeoutMs = DEFAULT_CONFIG.timeoutMs,
    warningMs = DEFAULT_CONFIG.warningMs,
    onTimeout,
    enabled = true,
}) => {
    const [showWarning, setShowWarning] = useState(false);
    const [remainingSeconds, setRemainingSeconds] = useState(0);

    // Initialize session timeout
    useEffect(() => {
        if (!enabled) return;

        const cleanup = initSessionTimeout({
            timeoutMs,
            warningMs,
            onWarning: (remainingMs) => {
                setRemainingSeconds(Math.ceil(remainingMs / 1000));
                setShowWarning(true);
            },
            onTimeout: () => {
                setShowWarning(false);
                onTimeout();
            },
            onActivity: () => {
                // User is active, hide warning if visible
                if (showWarning) {
                    setShowWarning(false);
                }
            },
        });

        return cleanup;
    }, [enabled, timeoutMs, warningMs, onTimeout, showWarning]);

    // Countdown timer when warning is shown
    useEffect(() => {
        if (!showWarning || remainingSeconds <= 0) return;

        const timer = setInterval(() => {
            setRemainingSeconds((prev) => {
                if (prev <= 1) {
                    clearInterval(timer);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);

        return () => clearInterval(timer);
    }, [showWarning, remainingSeconds]);

    const handleExtend = useCallback(() => {
        extendSession();
        setShowWarning(false);
    }, []);

    const handleLogout = useCallback(() => {
        setShowWarning(false);
        onTimeout();
    }, [onTimeout]);

    return (
        <>
            {children}
            <SessionTimeoutWarning
                isOpen={showWarning}
                remainingSeconds={remainingSeconds}
                onExtend={handleExtend}
                onLogout={handleLogout}
            />
        </>
    );
};

// ============================================
// USE SESSION TIMEOUT HOOK
// ============================================

interface UseSessionTimeoutOptions {
    timeoutMs?: number;
    warningMs?: number;
    onWarning?: (remainingMs: number) => void;
    onTimeout?: () => void;
    enabled?: boolean;
}

/**
 * Hook for custom session timeout handling
 */
export function useSessionTimeout(options: UseSessionTimeoutOptions = {}) {
    const {
        timeoutMs = DEFAULT_CONFIG.timeoutMs,
        warningMs = DEFAULT_CONFIG.warningMs,
        onWarning,
        onTimeout,
        enabled = true,
    } = options;

    const [isWarningShown, setIsWarningShown] = useState(false);
    const [remainingMs, setRemainingMs] = useState(0);

    useEffect(() => {
        if (!enabled) return;

        const cleanup = initSessionTimeout({
            timeoutMs,
            warningMs,
            onWarning: (remaining) => {
                setIsWarningShown(true);
                setRemainingMs(remaining);
                onWarning?.(remaining);
            },
            onTimeout: () => {
                setIsWarningShown(false);
                setRemainingMs(0);
                onTimeout?.();
            },
            onActivity: () => {
                setIsWarningShown(false);
            },
        });

        return cleanup;
    }, [enabled, timeoutMs, warningMs, onWarning, onTimeout]);

    const extend = useCallback(() => {
        extendSession();
        setIsWarningShown(false);
    }, []);

    return {
        isWarningShown,
        remainingMs,
        extend,
    };
}

export default {
    SessionTimeoutWarning,
    SessionTimeoutProvider,
    useSessionTimeout,
};

import React, { useState, useRef, useEffect } from 'react';
import { ArrowUpIcon, ArrowDownIcon, ChevronDownIcon } from 'lucide-react';

interface SortOption {
