                }
                ${className}
            `}
        >
            {checked && <CheckIcon className={iconSizes[size]} />}
            {indeterminate && !checked && (
                <div className={`${iconSizes[size]} flex items-center justify-center`}>
                    <div className="w-2/3 h-0.5 bg-white rounded-full" />
