                        />
                    </svg>
                ) : (
                    <svg
                        className="w-6 h-6 text-indigo-600 dark:text-indigo-400 transition-transform"
                        style={{ transform: `rotate(${rotation}deg)` }}
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                    >
                        <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
