                        />
                    </svg>
                )}
            </div>
            {progress >= 1 && !isRefreshing && (
                <p className="text-xs text-center text-slate-600 dark:text-slate-400 mt-2 animate-pulse">
                    Lepaskan untuk refresh
                </p>
            )}
        </div>
    );
};

