import { useState, useEffect, useCallback, useRef } from 'react';
import {
    offlineQueue,
    QueueItem,
    SyncResult,
    cacheData,
    getCachedData,
    invalidateCache,
    registerBackgroundSync,
    resolveConflict,
    detectConflict,
    ConflictResolution
} from '../services/offlineQueueEnhanced';
import { supabase } from '../services/supabase';
import { logger } from '../services/logger';
import { useToast } from './useToast';

// ============================================
// OFFLINE SYNC HOOK
// ============================================

interface UseOfflineSyncOptions {
    autoSync?: boolean;
    conflictStrategy?: ConflictResolution;
    onConflict?: (itemId: string, local: any, server: any) => Promise<any>;
    onSyncComplete?: (results: SyncResult[]) => void;
    onError?: (error: Error) => void;
}

export function useOfflineSync(options: UseOfflineSyncOptions = {}) {
    const {
        autoSync = true,
        conflictStrategy = 'server_wins',
        onConflict,
        onSyncComplete,
        onError
    } = options;

    const toast = useToast();

    const [queue, setQueue] = useState<QueueItem[]>([]);
    const [isSyncing, setIsSyncing] = useState(false);
    const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
    const [conflicts, setConflicts] = useState<{ itemId: string; local: any; server: any }[]>([]);

    const syncInProgressRef = useRef(false);

    // Subscribe to queue changes
    useEffect(() => {
        const unsubscribe = offlineQueue.subscribe(setQueue);
        return unsubscribe;
    }, []);

    // Auto-sync when online
    // Wait for sync definition below


    // Sync function
    const sync = useCallback(async (): Promise<SyncResult[]> => {
        if (syncInProgressRef.current || !navigator.onLine) {
            return [];
        }

        syncInProgressRef.current = true;
        setIsSyncing(true);
        const results: SyncResult[] = [];

        try {
            await offlineQueue.processQueue(async (item): Promise<SyncResult> => {
                try {
                    const result = await syncItem(item, conflictStrategy, onConflict);
                    results.push(result);

                    if (result.conflict) {
                        setConflicts(prev => [...prev, {
                            itemId: item.id,
                            local: item.data,
                            server: result.serverData
                        }]);
                    }

                    return result;
                } catch (error) {
                    const errorResult: SyncResult = {
                        success: false,
                        item,
                        error: error instanceof Error ? error.message : 'Unknown error'
                    };
                    results.push(errorResult);
                    return errorResult;
                }
            });

            setLastSyncTime(new Date());
            onSyncComplete?.(results);

            if (results.length > 0) {
                const successCount = results.filter(r => r.success).length;
                if (successCount > 0) {
                    toast.success(`Berhasil menyinkronkan ${successCount} data offline.`);
                }
            }

            return results;
        } catch (error) {
            const err = error instanceof Error ? error : new Error('Sync failed');
            onError?.(err);
            logger.error('Sync failed', err);
            return results;
        } finally {
            syncInProgressRef.current = false;
            setIsSyncing(false);
        }
    }, [conflictStrategy, onConflict, onSyncComplete, onError, toast]);

    // Auto-sync when online
    useEffect(() => {
        if (!autoSync) return;

        const handleOnline = () => {
            logger.info('Connection restored, triggering sync', 'useOfflineSync');
            sync();
        };

        window.addEventListener('online', handleOnline);
        return () => window.removeEventListener('online', handleOnline);
    }, [autoSync, sync]);

    // Register background sync
    useEffect(() => {
        registerBackgroundSync();
    }, []);

    // Add to queue
    const addToQueue = useCallback(async (
        type: 'CREATE' | 'UPDATE' | 'DELETE',
        table: string,
        data: any,
        priority?: number
    ): Promise<string> => {
        const id = await offlineQueue.add(type, table, data, priority);

        // Invalidate cache for this table
        await invalidateCache(table);

        return id;
    }, []);

    // Resolve conflict manually
    const resolveConflictManually = useCallback(async (
        itemId: string,
        resolution: 'local' | 'server' | 'merge'
    ): Promise<void> => {
        const conflict = conflicts.find(c => c.itemId === itemId);
        if (!conflict) return;

        const strategy: ConflictResolution =
            resolution === 'local' ? 'local_wins' :
                resolution === 'server' ? 'server_wins' : 'merge';

        const resolved = resolveConflict(conflict.local, conflict.server, strategy);

        // Update the queue item with resolved data
        const item = queue.find(i => i.id === itemId);
        if (item) {
            item.data = resolved;
            item.status = 'pending';
            await offlineQueue.processQueue();
        }

        setConflicts(prev => prev.filter(c => c.itemId !== itemId));
    }, [conflicts, queue]);

    // Get pending count
    const pendingCount = queue.filter(i => i.status === 'pending').length;
    const failedCount = queue.filter(i => i.status === 'failed').length;

    return {
        queue,
        isSyncing,
        lastSyncTime,
        conflicts,
        pendingCount,
        failedCount,
        sync,
        addToQueue,
        resolveConflictManually,
        clearQueue: () => offlineQueue.clear(),
        retryFailed: () => offlineQueue.retryFailed()
    };
}

// ============================================
// SYNC ITEM HELPER
// ============================================

async function syncItem(
    item: QueueItem,
    conflictStrategy: ConflictResolution,
    onConflict?: (itemId: string, local: any, server: any) => Promise<any>
): Promise<SyncResult> {
    const { type, table, data } = item;

    // Check for conflicts (for UPDATE operations)
    if (type === 'UPDATE' && data.id) {
        const { data: serverData, error: fetchError } = await (supabase
            .from(table as any) as any)
            .select('*')
            .eq('id', data.id)
            .single();

        if (fetchError) {
            throw new Error(`Failed to fetch server data: ${fetchError.message}`);
        }

        if (serverData && detectConflict(data, serverData)) {
            if (onConflict) {
                // Let the caller handle the conflict
                const resolved = await onConflict(item.id, data, serverData);
                if (resolved.needsManualResolution) {
                    return {
                        success: false,
                        item,
                        serverData,
                        conflict: true
                    };
                }
                // Use resolved data
                item.data = resolved;
            } else {
                // Auto-resolve using strategy
                item.data = resolveConflict(data, serverData, conflictStrategy);
            }
        }
    }

    // Perform the operation
    let result: any;
    let error: any;

    switch (type) {
        case 'CREATE': {
            const { id: _, ...createData } = data;
            ({ data: result, error } = await (supabase
                .from(table as any) as any)
                .insert(createData)
                .select()
                .single());
            break;
        }

        case 'UPDATE': {
            const { _localTimestamp, ...updateData } = data;
            ({ data: result, error } = await (supabase
                .from(table as any) as any)
                .update({ ...updateData, updated_at: new Date().toISOString() })
                .eq('id', data.id)
                .select()
                .single());
            break;
        }

        case 'DELETE': {
            ({ error } = await (supabase
                .from(table as any) as any)
                .delete()
                .eq('id', data.id));
            result = { deleted: true };
            break;
        }
    }
    if (error) {
        throw new Error(error.message);
    }

    // Invalidate cache after successful sync
    await invalidateCache(table);

    return {
        success: true,
        item,
        serverData: result
    };
}

// ============================================
// CACHED DATA HOOK
// ============================================

interface UseCachedDataOptions<T> {
    key: string;
    table: string;
    fetchFn: () => Promise<T>;
    ttl?: number;
    enabled?: boolean;
}

export function useCachedData<T>({
    key,
    table,
    fetchFn,
    ttl = 3600000,
    enabled = true
}: UseCachedDataOptions<T>) {
    const [data, setData] = useState<T | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<Error | null>(null);
    const [isFromCache, setIsFromCache] = useState(false);

    const refresh = useCallback(async (forceRefresh = false): Promise<void> => {
        if (!enabled) return;

        setLoading(true);
        setError(null);

        try {
            // Try cache first if not forcing refresh
            if (!forceRefresh) {
                const cached = await getCachedData<T>(key);
                if (cached) {
                    setData(cached);
                    setIsFromCache(true);
                    setLoading(false);

                    // Refresh in background if online
                    if (navigator.onLine) {
                        fetchFn().then(freshData => {
                            setData(freshData);
                            setIsFromCache(false);
                            cacheData(key, table, freshData, ttl);
                        }).catch(() => {
                            // Keep cached data if refresh fails
                        });
                    }
                    return;
                }
            }

            // Fetch fresh data
            if (navigator.onLine) {
                const freshData = await fetchFn();
                setData(freshData);
                setIsFromCache(false);
                await cacheData(key, table, freshData, ttl);
            } else {
                throw new Error('Tidak ada koneksi internet');
            }
        } catch (err) {
            setError(err instanceof Error ? err : new Error('Unknown error'));
        } finally {
            setLoading(false);
        }
    }, [enabled, key, table, fetchFn, ttl]);

    useEffect(() => {
        refresh();
    }, [refresh]);

    // Refresh when coming online
    useEffect(() => {
        const handleOnline = () => refresh(true);
        window.addEventListener('online', handleOnline);
        return () => window.removeEventListener('online', handleOnline);
    }, [refresh]);

    return {
        data,
        loading,
        error,
        isFromCache,
        refresh: () => refresh(true),
        invalidate: () => invalidateCache(table)
    };
}

// ============================================
// ONLINE STATUS HOOK
// ============================================

export function useOnlineStatus() {
    const [isOnline, setIsOnline] = useState(navigator.onLine);
    const [wasOffline, setWasOffline] = useState(false);

    useEffect(() => {
        const handleOnline = () => {
            setIsOnline(true);
            if (!isOnline) setWasOffline(true);
        };

        const handleOffline = () => {
            setIsOnline(false);
        };

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, [isOnline]);

    // Reset wasOffline after a delay
    useEffect(() => {
        if (wasOffline) {
            const timer = setTimeout(() => setWasOffline(false), 5000);
            return () => clearTimeout(timer);
        }
    }, [wasOffline]);

    return { isOnline, wasOffline };
}

// ============================================
// OFFLINE-FIRST DATA HOOK
// ============================================

interface UseOfflineFirstOptions<T> {
    table: string;
    fetchFn: () => Promise<T[]>;
    cacheKey?: string;
}

export function useOfflineFirst<T extends { id: string }>({
    table,
    fetchFn,
    cacheKey
}: UseOfflineFirstOptions<T>) {
    const key = cacheKey || `${table}_list`;
    const { addToQueue, sync, pendingCount } = useOfflineSync();

    const {
        data,
        loading,
        error,
        isFromCache,
        refresh,
        invalidate
    } = useCachedData<T[]>({
        key,
        table,
        fetchFn
    });

    const create = useCallback(async (newData: Omit<T, 'id'>): Promise<string> => {
        const tempId = crypto.randomUUID();
        const itemWithId = { ...newData, id: tempId } as T;

        // Optimistic update
        // setData(prev => prev ? [...prev, itemWithId] : [itemWithId]);

        const queueId = await addToQueue('CREATE', table, itemWithId);
        await invalidate();

        return queueId;
    }, [addToQueue, table, invalidate]);

    const update = useCallback(async (id: string, updates: Partial<T>): Promise<string> => {
        const queueId = await addToQueue('UPDATE', table, { id, ...updates });
        await invalidate();
        return queueId;
    }, [addToQueue, table, invalidate]);

    const remove = useCallback(async (id: string): Promise<string> => {
        const queueId = await addToQueue('DELETE', table, { id });
        await invalidate();
        return queueId;
    }, [addToQueue, table, invalidate]);

    return {
        data: data || [],
        loading,
        error,
        isFromCache,
        pendingCount,
        refresh,
        create,
        update,
        remove,
        sync
    };
}

export default useOfflineSync;

import { useState, useCallback, useRef } from 'react';

interface RetryOptions {
    maxRetries?: number;
    retryDelay?: number; // ms
    backoffMultiplier?: number;
    onRetry?: (attempt: number, error: Error) => void;
}

interface RetryState<T> {
    data: T | null;
    error: Error | null;
    isLoading: boolean;
    attempt: number;
    canRetry: boolean;
}

// User-friendly error messages
const ERROR_MESSAGES: Record<string, string> = {
    // Network errors
    'Failed to fetch': 'Tidak dapat terhubung ke server. Periksa koneksi internet Anda.',
    'Network Error': 'Tidak dapat terhubung ke server. Periksa koneksi internet Anda.',
    'NetworkError': 'Tidak dapat terhubung ke server. Periksa koneksi internet Anda.',
    'ERR_NETWORK': 'Tidak dapat terhubung ke server. Periksa koneksi internet Anda.',
    'ERR_INTERNET_DISCONNECTED': 'Tidak ada koneksi internet.',

    // Timeout
    'timeout': 'Waktu permintaan habis. Coba lagi.',
    'AbortError': 'Permintaan dibatalkan.',

    // Auth errors
    'Unauthorized': 'Sesi Anda telah berakhir. Silakan login kembali.',
    '401': 'Sesi Anda telah berakhir. Silakan login kembali.',
    'JWT expired': 'Sesi Anda telah berakhir. Silakan login kembali.',

    // Permission errors
    'Forbidden': 'Anda tidak memiliki izin untuk melakukan tindakan ini.',
    '403': 'Anda tidak memiliki izin untuk melakukan tindakan ini.',

    // Not found
    '404': 'Data yang diminta tidak ditemukan.',
    'Not Found': 'Data yang diminta tidak ditemukan.',

    // Server errors
    '500': 'Terjadi kesalahan pada server. Coba lagi nanti.',
    '502': 'Server sedang tidak tersedia. Coba lagi nanti.',
    '503': 'Layanan sedang tidak tersedia. Coba lagi nanti.',
    'Internal Server Error': 'Terjadi kesalahan pada server. Coba lagi nanti.',

    // Supabase specific
    'row not found': 'Data tidak ditemukan.',
    'duplicate key': 'Data sudah ada. Gunakan data yang berbeda.',
    'violates foreign key': 'Data terkait dengan data lain dan tidak dapat dihapus.',
    'violates check constraint': 'Data tidak valid sesuai dengan ketentuan.',

    // Storage errors
    'Payload too large': 'Ukuran file terlalu besar.',
    'Invalid image': 'Format gambar tidak valid.',
    'storage error': 'Gagal menyimpan file.',

    // Default
    'default': 'Terjadi kesalahan. Silakan coba lagi.',
};

// Convert technical error to user-friendly message
export const getUserFriendlyError = (error: any): string => {
    if (!error) return ERROR_MESSAGES.default;

    const errorString = error.message || error.toString() || '';
    const errorCode = error.code || error.status || '';

    // Check for known error patterns
    for (const [pattern, message] of Object.entries(ERROR_MESSAGES)) {
        if (
            errorString.toLowerCase().includes(pattern.toLowerCase()) ||
            errorCode.toString() === pattern
        ) {
            return message;
        }
    }

    return ERROR_MESSAGES.default;
};

// Retry hook
export const useRetry = <T,>(
    asyncFn: () => Promise<T>,
    options: RetryOptions = {}
): RetryState<T> & { execute: () => Promise<T | null>; retry: () => Promise<T | null>; reset: () => void } => {
    const {
        maxRetries = 3,
        retryDelay = 1000,
        backoffMultiplier = 2,
        onRetry,
    } = options;

    const [state, setState] = useState<RetryState<T>>({
        data: null,
        error: null,
        isLoading: false,
        attempt: 0,
        canRetry: true,
    });

    const attemptRef = useRef(0);

    const execute = useCallback(async (): Promise<T | null> => {
        setState(prev => ({ ...prev, isLoading: true, error: null }));
        attemptRef.current = 0;

        const tryExecute = async (): Promise<T | null> => {
            try {
                const result = await asyncFn();
                setState({
                    data: result,
                    error: null,
                    isLoading: false,
                    attempt: attemptRef.current,
                    canRetry: true,
                });
                return result;
            } catch (error: any) {
                attemptRef.current++;

                if (attemptRef.current <= maxRetries) {
                    onRetry?.(attemptRef.current, error);

                    // Wait before retry with exponential backoff
                    const delay = retryDelay * Math.pow(backoffMultiplier, attemptRef.current - 1);
                    await new Promise(resolve => setTimeout(resolve, delay));

                    return tryExecute();
                }

                setState({
                    data: null,
                    error,
                    isLoading: false,
                    attempt: attemptRef.current,
                    canRetry: true,
                });
                return null;
            }
        };

        return tryExecute();
    }, [asyncFn, maxRetries, retryDelay, backoffMultiplier, onRetry]);

    const retry = useCallback(async (): Promise<T | null> => {
        return execute();
    }, [execute]);

    const reset = useCallback(() => {
        setState({
            data: null,
            error: null,
            isLoading: false,
            attempt: 0,
            canRetry: true,
        });
        attemptRef.current = 0;
    }, []);

    return { ...state, execute, retry, reset };
};

// Upload with retry
export const useUploadWithRetry = (options: RetryOptions = {}) => {
    const [progress, setProgress] = useState(0);
    const [status, setStatus] = useState<'idle' | 'uploading' | 'retrying' | 'success' | 'error'>('idle');
    const [error, setError] = useState<string | null>(null);
    const [attempt, setAttempt] = useState(0);

    const { maxRetries = 3, retryDelay = 2000 } = options;

    const upload = useCallback(async (
        uploadFn: (onProgress?: (progress: number) => void) => Promise<any>
    ) => {
        setStatus('uploading');
        setProgress(0);
        setError(null);
        let currentAttempt = 0;

        const tryUpload = async (): Promise<any> => {
            try {
                const result = await uploadFn((p) => setProgress(p));
                setStatus('success');
                setProgress(100);
                return result;
            } catch (err: any) {
                currentAttempt++;
                setAttempt(currentAttempt);

                if (currentAttempt <= maxRetries) {
                    setStatus('retrying');
                    setProgress(0);
                    await new Promise(resolve => setTimeout(resolve, retryDelay));
                    return tryUpload();
                }

                setStatus('error');
                setError(getUserFriendlyError(err));
                throw err;
            }
        };

        return tryUpload();
    }, [maxRetries, retryDelay]);

    const reset = useCallback(() => {
        setProgress(0);
        setStatus('idle');
        setError(null);
        setAttempt(0);
    }, []);

    return { upload, progress, status, error, attempt, reset };
};

export default useRetry;

/**
 * useSoftDelete Hook
 * 
 * Hook for integrating soft delete with undo functionality across all pages.
 */

import { useCallback } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useToast } from './useToast';
import { useUndoToastContext } from '../components/ui/UndoToast';
import { softDelete, softDeleteBulk, SoftDeleteEntity } from '../services/SoftDeleteService';
import { recordAction, ActionType } from '../services/UndoManager';
import { useAuth } from './useAuth';

interface UseSoftDeleteOptions {
    entity: SoftDeleteEntity;
    queryKey: string[];
    entityLabel?: string;
    onSuccess?: () => void;
    onError?: (error: Error) => void;
}

interface DeleteResult {
    success: boolean;
    actionId?: string;
    error?: string;
}

export function useSoftDelete(options: UseSoftDeleteOptions) {
    const { entity, queryKey, entityLabel, onSuccess, onError } = options;
    const { user } = useAuth();
    const toast = useToast();
    const queryClient = useQueryClient();
    const { showUndoToast } = useUndoToastContext();

    const entityLabels: Record<SoftDeleteEntity, string> = {
        students: 'siswa',
        classes: 'kelas',
        attendance: 'absensi',
        tasks: 'tugas',
    };

    const label = entityLabel || entityLabels[entity];

    // Single delete mutation
    const deleteMutation = useMutation({
        mutationFn: async (id: string): Promise<DeleteResult> => {
            if (!user) throw new Error('User not authenticated');

            // Perform soft delete
            const result = await softDelete(entity, id);
            if (!result.success) {
                throw new Error(result.error);
            }

            // Record action for undo
            const action = await recordAction(
                user.id,
                'delete',
                entity,
                [id],
                undefined,
                `Menghapus 1 ${label}`
            );

            return { success: true, actionId: action.id };
        },
        onSuccess: (result) => {
            queryClient.invalidateQueries({ queryKey });

            if (result.actionId) {
                showUndoToast(
                    result.actionId,
                    `1 ${label} dihapus`,
                    'delete',
                    10000,
                    () => {
                        queryClient.invalidateQueries({ queryKey });
                        toast.success(`${label} dipulihkan`);
                    }
                );
            }

            onSuccess?.();
        },
        onError: (error: Error) => {
            toast.error(`Gagal menghapus ${label}: ${error.message}`);
            onError?.(error);
        },
    });

    // Bulk delete mutation
    const bulkDeleteMutation = useMutation({
        mutationFn: async (ids: string[]): Promise<DeleteResult> => {
            if (!user) throw new Error('User not authenticated');
            if (ids.length === 0) throw new Error('No items to delete');

            // Perform bulk soft delete
            const result = await softDeleteBulk(entity, ids);
            if (!result.success) {
                throw new Error(result.error);
            }

            // Record action for undo
            const action = await recordAction(
                user.id,
                'bulk_delete',
                entity,
                ids,
                undefined,
                `Menghapus ${ids.length} ${label}`
            );

            return { success: true, actionId: action.id };
        },
        onSuccess: (result, ids) => {
            queryClient.invalidateQueries({ queryKey });

            if (result.actionId) {
                showUndoToast(
                    result.actionId,
                    `${ids.length} ${label} dihapus`,
                    'delete',
                    10000,
                    () => {
                        queryClient.invalidateQueries({ queryKey });
                        toast.success(`${ids.length} ${label} dipulihkan`);
                    }
                );
            }

            onSuccess?.();
        },
        onError: (error: Error) => {
            toast.error(`Gagal menghapus ${label}: ${error.message}`);
            onError?.(error);
        },
    });

    // Delete function
    const deleteItem = useCallback((id: string) => {
        return deleteMutation.mutateAsync(id);
    }, [deleteMutation]);

    // Bulk delete function
    const deleteItems = useCallback((ids: string[]) => {
        return bulkDeleteMutation.mutateAsync(ids);
    }, [bulkDeleteMutation]);

    return {
        deleteItem,
        deleteItems,
        isDeleting: deleteMutation.isPending,
        isBulkDeleting: bulkDeleteMutation.isPending,
    };
}

export default useSoftDelete;

import { useCallback } from 'react';
import { hapticLight, hapticMedium, hapticHeavy, hapticSuccess, hapticError } from '../services/haptics';
import {
    playNotificationSound,
    playSuccessSound,
    playErrorSound,
    playMessageSound,
    playReminderSound,
} from '../utils/notificationSound';

// Short "pop" / "click" sound using AudioContext

export const useSound = () => {
    const playAudioClick = useCallback(() => {
        try {
            const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
            if (!AudioContext) return;

            const ctx = new AudioContext();
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.connect(gain);
            gain.connect(ctx.destination);

            // Very short, high pitch "tick"
            osc.type = 'sine';
            osc.frequency.setValueAtTime(800, ctx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.05);

            gain.gain.setValueAtTime(0.1, ctx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.05);

            osc.start(ctx.currentTime);
            osc.stop(ctx.currentTime + 0.05);
        } catch (e) {
            // Silent fail for audio
        }
    }, []);

    // Combined audio + haptic feedback
    const playClick = useCallback(() => {
        playAudioClick();
        hapticLight();
    }, [playAudioClick]);

    // Medium haptic for toggles and confirms
    const playToggle = useCallback(() => {
        playAudioClick();
        hapticMedium();
    }, [playAudioClick]);

    // Heavy haptic for important actions
    const playAction = useCallback(() => {
        playAudioClick();
        hapticHeavy();
    }, [playAudioClick]);

    // Success feedback with sound and haptic
    const playSuccess = useCallback(() => {
        playSuccessSound();
        hapticSuccess();
    }, []);

    // Error feedback with sound and haptic
    const playError = useCallback(() => {
        playErrorSound();
        hapticError();
    }, []);

    // Notification sound (ding-dong) with haptic
    const playNotification = useCallback(() => {
        playNotificationSound();
        hapticMedium();
    }, []);

    // Message received sound with haptic
    const playMessage = useCallback(() => {
        playMessageSound();
        hapticLight();
    }, []);

    // Reminder sound with haptic
    const playReminder = useCallback(() => {
        playReminderSound();
        hapticHeavy();
    }, []);

    return {
        playClick,
        playToggle,
        playAction,
        playSuccess,
        playError,
        // New notification sounds
        playNotification,
        playMessage,
        playReminder,
        // Also expose individual haptics
        hapticLight,
        hapticMedium,
        hapticHeavy,
        // Expose raw sound functions for direct use
        sounds: {
            notification: playNotificationSound,
            success: playSuccessSound,
            error: playErrorSound,
            message: playMessageSound,
            reminder: playReminderSound,
        },
    };
};

import { useState, useRef, useCallback, TouchEvent } from 'react';

interface SwipeConfig {
    onSwipeDown?: () => void;
    onSwipeUp?: () => void;
    onSwipeLeft?: () => void;
    onSwipeRight?: () => void;
    threshold?: number;
    preventScrollOnSwipe?: boolean;
}

interface SwipeHandlers {
    onTouchStart: (e: TouchEvent) => void;
    onTouchMove: (e: TouchEvent) => void;
    onTouchEnd: (e: TouchEvent) => void;
}

interface SwipeState {
    isSwiping: boolean;
    direction: 'up' | 'down' | 'left' | 'right' | null;
    deltaX: number;
    deltaY: number;
}

/**
 * Hook for detecting swipe gestures on touch devices
 * @param config - Configuration for swipe detection
 * @returns Handlers to attach to the element and current swipe state
 */
export function useSwipeGesture(config: SwipeConfig): [SwipeHandlers, SwipeState] {
    const {
        onSwipeDown,
        onSwipeUp,
        onSwipeLeft,
        onSwipeRight,
        threshold = 50,
        preventScrollOnSwipe = false,
    } = config;

    const [state, setState] = useState<SwipeState>({
        isSwiping: false,
        direction: null,
        deltaX: 0,
        deltaY: 0,
    });

    const touchStart = useRef<{ x: number; y: number } | null>(null);
    const isSwiping = useRef(false);

    const onTouchStart = useCallback((e: TouchEvent) => {
        const touch = e.touches[0];
        touchStart.current = { x: touch.clientX, y: touch.clientY };
        isSwiping.current = false;
        setState(prev => ({ ...prev, isSwiping: false, direction: null, deltaX: 0, deltaY: 0 }));
    }, []);

    const onTouchMove = useCallback((e: TouchEvent) => {
        if (!touchStart.current) return;

        const touch = e.touches[0];
        const deltaX = touch.clientX - touchStart.current.x;
        const deltaY = touch.clientY - touchStart.current.y;
        const absDeltaX = Math.abs(deltaX);
        const absDeltaY = Math.abs(deltaY);

        // Determine direction based on which axis has more movement
        let direction: 'up' | 'down' | 'left' | 'right' | null = null;
        if (absDeltaX > absDeltaY && absDeltaX > 10) {
            direction = deltaX > 0 ? 'right' : 'left';
        } else if (absDeltaY > absDeltaX && absDeltaY > 10) {
            direction = deltaY > 0 ? 'down' : 'up';
        }

        if (direction) {
            isSwiping.current = true;
            if (preventScrollOnSwipe) {
                e.preventDefault();
            }
        }

        setState({
            isSwiping: isSwiping.current,
            direction,
            deltaX,
            deltaY,
        });
    }, [preventScrollOnSwipe]);

    const onTouchEnd = useCallback((e: TouchEvent) => {
        if (!touchStart.current) return;

        const { deltaX, deltaY } = state;
        const absDeltaX = Math.abs(deltaX);
        const absDeltaY = Math.abs(deltaY);

        // Trigger callbacks if threshold is met
        if (absDeltaY > threshold && absDeltaY > absDeltaX) {
            if (deltaY > 0 && onSwipeDown) {
                onSwipeDown();
            } else if (deltaY < 0 && onSwipeUp) {
                onSwipeUp();
            }
        } else if (absDeltaX > threshold && absDeltaX > absDeltaY) {
            if (deltaX > 0 && onSwipeRight) {
                onSwipeRight();
            } else if (deltaX < 0 && onSwipeLeft) {
                onSwipeLeft();
            }
        }

        // Reset
        touchStart.current = null;
        isSwiping.current = false;
        setState({
            isSwiping: false,
            direction: null,
            deltaX: 0,
            deltaY: 0,
        });
    }, [state, threshold, onSwipeDown, onSwipeUp, onSwipeLeft, onSwipeRight]);

    return [
        { onTouchStart, onTouchMove, onTouchEnd },
        state,
    ];
}

export default useSwipeGesture;

import { useState, useEffect, useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useOfflineStatus } from './useOfflineStatus';
import { supabase } from '../services/supabase';
import { getQueue, clearQueue, QueuedMutation } from '../services/offlineQueue';
import { useToast } from './useToast';

/**
 * Custom hook for managing offline data synchronization queue
 * 
 * Manages a queue of database mutations that were made while offline and automatically
 * synchronizes them with the server when the connection is restored. This enables
 * offline-first functionality where users can continue working without an internet
 * connection, and their changes will be synced when they come back online.
 * 
 * The hook:
 * - Tracks the number of pending mutations in the queue
 * - Automatically processes the queue when the device comes online
 * - Provides manual sync capability via processQueue function
 * - Shows toast notifications for sync status
 * - Invalidates React Query cache after successful sync
 * - Listens to localStorage changes to update count across tabs
 * 
 * @returns Object containing sync queue state and operations
 * @returns pendingCount - Number of mutations waiting to be synced
 * @returns isSyncing - Boolean indicating if sync is currently in progress
 * @returns processQueue - Function to manually trigger queue processing
 * 
 * @example
 * ```typescript
 * import { useSyncQueue } from './hooks/useSyncQueue';
 * 
 * function SyncStatus() {
 *   const { pendingCount, isSyncing, processQueue } = useSyncQueue();
 * 
 *   return (
 *     <div>
 *       {pendingCount > 0 && (
 *         <div>
 *           <p>{pendingCount} changes pending sync</p>
 *           <button onClick={processQueue} disabled={isSyncing}>
 *             {isSyncing ? 'Syncing...' : 'Sync Now'}
 *           </button>
 *         </div>
 *       )}
 *     </div>
 *   );
 * }
 * ```
 * 
 * @example
 * ```typescript
 * // Display sync indicator in header
 * function Header() {
 *   const { pendingCount, isSyncing } = useSyncQueue();
 * 
 *   return (
 *     <header>
 *       {isSyncing && <Spinner />}
 *       {pendingCount > 0 && !isSyncing && (
 *         <Badge>{pendingCount} pending</Badge>
 *       )}
 *     </header>
 *   );
 * }
 * ```
 * 
 * @since 1.0.0
 */
export const useSyncQueue = () => {
    const queryClient = useQueryClient();
    const isOnline = useOfflineStatus();
    const toast = useToast();
    const [pendingCount, setPendingCount] = useState(0);
    const [isSyncing, setIsSyncing] = useState(false);

    const updatePendingCount = useCallback(async () => {
        const queue = await getQueue();
        setPendingCount(queue.length);
    }, []);

    // Initialize pending count
    useEffect(() => {
        updatePendingCount();
    }, [updatePendingCount]);

    // Listen for changes in localStorage to update count across components/tabs
    useEffect(() => {
        const handleStorageChange = () => {
            updatePendingCount();
        };
        window.addEventListener('storage', handleStorageChange);
        return () => window.removeEventListener('storage', handleStorageChange);
    }, [updatePendingCount]);

    const processQueue = useCallback(async () => {
        if (!isOnline || isSyncing) return;

        const queue = await getQueue();
        if (queue.length === 0) return;

        setIsSyncing(true);
        toast.info(`Menyinkronkan ${queue.length} perubahan offline...`);

        const promises = queue.map(async (mutation: QueuedMutation) => {
            const { table, operation, payload, onConflict } = mutation;
            // Use type assertion for dynamic table name from queue
            const query = (supabase.from as any)(table);

            switch (operation) {
                case 'insert':
                    return query.insert(payload);
                case 'update':
                    // Assume payload is an array for multiple updates or an object for single update
                    {
                        const updates = Array.isArray(payload) ? payload : [payload];
                        return Promise.all(updates.map((item: any) => query.update(item).eq('id', item.id)));
                    }
                case 'upsert':
                    return query.upsert(payload, onConflict ? { onConflict } : {});
                case 'delete':
                    // Assume payload is an object with an id
                    return query.delete().eq('id', payload.id);
                default:
                    console.error(`Unknown operation in queue: ${operation}`);
                    return Promise.reject(new Error(`Unknown operation: ${operation}`));
            }
        });

        try {
            const results = await Promise.all(promises);
            // Flatten results in case of multiple updates in a single operation
            const allResults = results.flat();
            const errors = allResults.filter((res: any) => res && res.error);

            if (errors.length > 0) {
                throw new Error(errors.map((e: any) => e.error?.message).join(', '));
            }

            await clearQueue();
            toast.success("Semua data offline berhasil disinkronkan!");
            // Invalidate all queries to refetch fresh data from the server
            await queryClient.invalidateQueries();

        } catch (error: any) {
            toast.error(`Gagal sinkronisasi: ${error.message}`);
            console.error("Sync failed:", error);
        } finally {
            setIsSyncing(false);
            updatePendingCount(); // Should update count to 0
        }
    }, [isOnline, isSyncing, queryClient, toast, updatePendingCount]);

    useEffect(() => {
        // When app comes online, process the queue
        if (isOnline) {
            processQueue();
        }
    }, [isOnline, processQueue]);

    return { pendingCount, isSyncing, processQueue };
};

import { useEffect, useCallback, useState } from 'react';
import { Database } from '../services/database.types';
import {
    checkAndNotify,
    getDueTasks,
    getPreferences,
    DueTask,
    getUnreadCount
} from '../services/NotificationService';
import { useAuth } from './useAuth';

type Task = Database['public']['Tables']['tasks']['Row'];

interface UseTaskNotificationsReturn {
    dueTasks: DueTask[];
    overdueCount: number;
    upcomingCount: number;
    unreadCount: number;
    checkNow: () => Promise<void>;
    isLoading: boolean;
}

/**
 * Hook for managing task notifications
 * 
 * Combines service worker push notifications with in-app notification tracking.
 * Automatically checks for due tasks and provides counts for UI badges.
 */
export const useTaskNotifications = (tasks?: Task[]): UseTaskNotificationsReturn => {
    const { user } = useAuth();
    const [dueTasks, setDueTasks] = useState<DueTask[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isLoading, setIsLoading] = useState(false);

    // Push notification sync with service worker (original functionality)
    useEffect(() => {
        if (!tasks || tasks.length === 0) return;
        if (!('serviceWorker' in navigator) || !('Notification' in window)) return;

        const requestPermissionAndSync = async () => {
            try {
                const permission = await Notification.requestPermission();
                if (permission === 'granted' && navigator.serviceWorker.controller) {
                    navigator.serviceWorker.controller.postMessage({
                        type: 'TASKS_UPDATED',
                        payload: tasks
                    });
                }
            } catch (error) {
                console.error('Error requesting notification permission:', error);
            }
        };

        requestPermissionAndSync();
    }, [tasks]);

    // In-app notification check
    const checkNow = useCallback(async () => {
        if (!user) return;

        setIsLoading(true);
        try {
            const count = await checkAndNotify(user.id);
            const tasksData = await getDueTasks(user.id);
            setDueTasks(tasksData);
            setUnreadCount(count);
        } catch (error) {
            console.error('Error checking task notifications:', error);
        } finally {
            setIsLoading(false);
        }
    }, [user]);

    // Check on mount and periodically
    useEffect(() => {
        if (user) {
            checkNow();
            // Check every 15 minutes
            const interval = setInterval(checkNow, 15 * 60 * 1000);
            return () => clearInterval(interval);
        }
    }, [user, checkNow]);

    // Update unread count when storage changes
    useEffect(() => {
        const handleStorageChange = (e: StorageEvent) => {
            if (e.key === 'portal_guru_notifications') {
                setUnreadCount(getUnreadCount());
            }
        };
        window.addEventListener('storage', handleStorageChange);
        return () => window.removeEventListener('storage', handleStorageChange);
    }, []);

    const overdueCount = dueTasks.filter(t => t.isOverdue).length;
    const upcomingCount = dueTasks.filter(t => !t.isOverdue).length;

    return {
        dueTasks,
        overdueCount,
        upcomingCount,
        unreadCount,
        checkNow,
        isLoading,
    };
};

export default useTaskNotifications;

import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react';

/**
 * Available theme options for the application
 * - 'light': Light theme
 * - 'dark': Dark theme
 * - 'system': Follow system preference
 */
type ThemePreference = 'light' | 'dark' | 'system';
type ResolvedTheme = 'light' | 'dark';

/**
 * Theme context type providing theme state and operations
 */
interface ThemeContextType {
  /** Current theme preference (user selection) */
  themePreference: ThemePreference;
  /** Current resolved theme (actual applied theme) */
  theme: ResolvedTheme;
  /** Toggles between light, dark, and system themes */
  toggleTheme: () => void;
  /** Sets a specific theme preference */
  setTheme: (theme: ThemePreference) => void;
  /** Whether the theme is following system preference */
  isSystemTheme: boolean;
}

/**
 * React context for theme state and operations
 * @internal
 */
const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

/**
 * Gets the system color scheme preference
 */
const getSystemTheme = (): ResolvedTheme => {
  if (typeof window === 'undefined') return 'light';
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
};

/**
 * Theme provider component that manages application theme state
 * 
 * This component provides theme context to all child components, enabling:
 * - Light, dark, and system (auto) theme switching
 * - Theme persistence in localStorage
 * - Automatic DOM class updates for Tailwind dark mode
 * - Smooth theme transition animations
 * - System preference change detection
 * 
 * @param props - Component props
 * @param props.children - Child components that will have access to theme context
 * 
 * @since 2.0.0 - Added system preference support
 */
export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [themePreference, setThemePreference] = useState<ThemePreference>(() => {
    if (typeof window === 'undefined') return 'system';
    const stored = localStorage.getItem('theme');
    if (stored === 'light' || stored === 'dark' || stored === 'system') {
      return stored;
    }
    // Default to system preference
    return 'system';
  });

  const [resolvedTheme, setResolvedTheme] = useState<ResolvedTheme>(() => {
    if (typeof window !== 'undefined' && document.documentElement.classList.contains('dark')) {
      return 'dark';
    }
    return 'light';
  });

  // Listen for system theme changes when in 'system' mode
  useEffect(() => {
    if (themePreference !== 'system') return;

    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      setResolvedTheme(e.matches ? 'dark' : 'light');
    };

    // Set initial system theme (defer to avoid cascading renders)
    Promise.resolve().then(() => {
      setResolvedTheme(mediaQuery.matches ? 'dark' : 'light');
    });

    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, [themePreference]);

  // Update resolved theme when preference changes
  useEffect(() => {
    Promise.resolve().then(() => {
      if (themePreference === 'system') {
        setResolvedTheme(getSystemTheme());
      } else {
        setResolvedTheme(themePreference);
      }
    });
  }, [themePreference]);

  // Apply theme to DOM with transition animation
  useEffect(() => {
    const root = window.document.documentElement;

    // Add transition class for smooth color changes
    root.classList.add('theme-transitioning');

    // Apply theme
    if (resolvedTheme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }

    // Remove transition class after animation completes
    const timeout = setTimeout(() => {
      root.classList.remove('theme-transitioning');
    }, 300);

    // Store preference
    localStorage.setItem('theme', themePreference);

    return () => clearTimeout(timeout);
  }, [resolvedTheme, themePreference]);

  const toggleTheme = useCallback(() => {
    setThemePreference(prev => {
      // Cycle: light -> dark -> system -> light
      if (prev === 'light') return 'dark';
      if (prev === 'dark') return 'system';
      return 'light';
    });
  }, []);

  const setTheme = useCallback((theme: ThemePreference) => {
    setThemePreference(theme);
  }, []);

  const value = useMemo(() => ({
    themePreference,
    theme: resolvedTheme,
    toggleTheme,
    setTheme,
    isSystemTheme: themePreference === 'system',
  }), [themePreference, resolvedTheme, toggleTheme, setTheme]);

  return (
    <ThemeContext.Provider value={value}>
      {children}
    </ThemeContext.Provider>
  );
};

/**
 * Custom hook for accessing and controlling application theme
 * 
 * Provides access to the current theme state and functions to change the theme.
 * The theme is persisted in localStorage and automatically applied to the DOM
 * via Tailwind's dark mode class on the html element.
 * 
 * Now supports 'system' mode which follows the OS color scheme preference.
 * 
 * Must be used within a ThemeProvider component.
 * 
 * @returns Theme context with current theme and control functions
 * @throws {Error} If used outside of ThemeProvider
 * 
 * @example
 * ```typescript
 * import { useTheme } from './hooks/useTheme';
 * 
 * function ThemeToggleButton() {
 *   const { theme, themePreference, toggleTheme, isSystemTheme } = useTheme();
 * 
 *   return (
 *     <button onClick={toggleTheme}>
 *       {isSystemTheme ? '≡ƒûÑ∩╕Å Auto' : theme === 'light' ? 'ΓÿÇ∩╕Å Light' : '≡ƒîÖ Dark'}
 *     </button>
 *   );
 * }
 * ```
 * 
 * @since 2.0.0
 */
export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import ReactDOM from 'react-dom';
import { CheckCircleIcon, XCircleIcon, AlertCircleIcon, FileTextIcon } from '../components/Icons';

/**
 * Available toast notification types
 */
type ToastType = 'success' | 'error' | 'info' | 'warning';

/**
 * Represents a single toast notification
 */
interface Toast {
  /** Unique identifier for the toast */
  id: number;
  /** Message text to display */
  message: string;
  /** Visual style and icon type */
  type: ToastType;
  /** Duration in milliseconds before auto-dismiss (default: 5000) */
  duration?: number;
}

/**
 * Toast context type providing notification operations
 * @internal
 */
interface ToastContextType {
  /** Adds a new toast notification to the queue */
  addToast: (message: string, options?: { type?: ToastType; duration?: number }) => void;
}

/**
 * React context for toast notifications
 * @internal
 */
const ToastContext = createContext<ToastContextType | undefined>(undefined);

const ICONS: Record<ToastType, React.FC<React.SVGProps<SVGSVGElement>>> = {
  success: CheckCircleIcon,
  error: XCircleIcon,
  warning: AlertCircleIcon,
  info: FileTextIcon,
};

const COLORS: Record<ToastType, string> = {
  success: 'bg-green-500',
  error: 'bg-red-500',
  warning: 'bg-yellow-500',
  info: 'bg-blue-500',
};

const ToastItem: React.FC<{ toast: Toast; onDismiss: (id: number) => void }> = ({ toast, onDismiss }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onDismiss(toast.id);
    }, toast.duration || 5000);

    return () => clearTimeout(timer);
  }, [toast, onDismiss]);

  const Icon = ICONS[toast.type];

  return (
    <div
      className="flex items-center w-full max-w-sm p-4 text-white bg-gray-800 rounded-lg shadow-2xl backdrop-blur-sm bg-opacity-80 border border-gray-700/50 transform transition-all duration-300 animate-fade-in-up"
      role="alert"
    >
      <div className={`inline-flex items-center justify-center flex-shrink-0 w-8 h-8 ${COLORS[toast.type]} rounded-lg`}>
        <Icon className="w-5 h-5" />
      </div>
      <div className="ml-3 text-sm font-normal flex-1">{toast.message}</div>
      <button
        type="button"
        className="ml-auto -mx-1.5 -my-1.5 bg-white/10 text-gray-300 hover:text-white rounded-lg focus:ring-2 focus:ring-gray-300 p-1.5 hover:bg-white/20 inline-flex h-8 w-8"
        onClick={() => onDismiss(toast.id)}
        aria-label="Close"
      >
        <span className="sr-only">Close</span>
        <svg aria-hidden="true" className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
          <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd"></path>
        </svg>
      </button>
    </div>
  );
};

const ToastContainer: React.FC<{ toasts: Toast[]; onDismiss: (id: number) => void }> = ({ toasts, onDismiss }) => {
    const [portalNode, setPortalNode] = useState<HTMLElement | null>(null);

    useEffect(() => {
        const node = document.createElement('div');
        node.className = 'fixed top-5 right-5 z-[100] space-y-3';
        document.body.appendChild(node);
        // Defer setState to prevent cascading renders
        Promise.resolve().then(() => setPortalNode(node));
        return () => {
            document.body.removeChild(node);
        };
    }, []);

    if (!portalNode) return null;

    return ReactDOM.createPortal(
        <>
            {toasts.map((toast) => (
                <ToastItem key={toast.id} toast={toast} onDismiss={onDismiss} />
            ))}
        </>,
        portalNode
    );
};

/**
 * Toast notification provider component that manages toast notifications
 * 
 * This component provides toast notification functionality to all child components, including:
 * - Success, error, info, and warning notifications
 * - Automatic dismissal after configurable duration
 * - Manual dismissal via close button
 * - Portal-based rendering for proper z-index stacking
 * - Animated entrance and exit transitions
 * - Multiple simultaneous toasts with stacking
 * 
 * Toasts are rendered in a fixed position at the top-right of the viewport and
 * automatically dismiss after 5 seconds by default.
 * 
 * @param props - Component props
 * @param props.children - Child components that will have access to toast context
 * 
 * @example
 * ```typescript
 * import { ToastProvider } from './hooks/useToast';
 * 
 * function App() {
 *   return (
 *     <ToastProvider>
 *       <YourApp />
 *     </ToastProvider>
 *   );
 * }
 * ```
 * 
 * @since 1.0.0
 */
export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const addToast = useCallback((message: string, options?: { type?: ToastType; duration?: number }) => {
    setToasts((prevToasts) => [
      ...prevToasts,
      {
        id: Date.now(),
        message,
        type: options?.type || 'info',
        duration: options?.duration,
      },
    ]);
  }, []);

  const removeToast = useCallback((id: number) => {
    setToasts((prevToasts) => prevToasts.filter((toast) => toast.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ addToast }}>
      {children}
      <ToastContainer toasts={toasts} onDismiss={removeToast} />
    </ToastContext.Provider>
  );
};

/**
 * Custom hook for displaying toast notifications
 * 
 * Provides convenient methods for showing success, error, info, and warning toast notifications.
 * Each toast automatically dismisses after 5 seconds by default, but can be configured with
 * a custom duration or dismissed manually by the user.
 * 
 * Must be used within a ToastProvider component.
 * 
 * @returns Object with methods for each toast type
 * @returns success - Shows a success toast with green styling
 * @returns error - Shows an error toast with red styling
 * @returns info - Shows an info toast with blue styling
 * @returns warning - Shows a warning toast with yellow styling
 * @throws {Error} If used outside of ToastProvider
 * 
 * @example
 * ```typescript
 * import { useToast } from './hooks/useToast';
 * 
 * function MyComponent() {
 *   const toast = useToast();
 * 
 *   const handleSave = async () => {
 *     try {
 *       await saveData();
 *       toast.success('Data saved successfully!');
 *     } catch (error) {
 *       toast.error('Failed to save data');
 *     }
 *   };
 * 
 *   return <button onClick={handleSave}>Save</button>;
 * }
 * ```
 * 
 * @example
 * ```typescript
 * // Custom duration (10 seconds)
 * function LongNotification() {
 *   const toast = useToast();
 * 
 *   const showLongToast = () => {
 *     toast.info('This message will stay for 10 seconds', { duration: 10000 });
 *   };
 * 
 *   return <button onClick={showLongToast}>Show Long Toast</button>;
 * }
 * ```
 * 
 * @example
 * ```typescript
 * // Different toast types
 * function ToastExamples() {
 *   const toast = useToast();
 * 
 *   return (
 *     <div>
 *       <button onClick={() => toast.success('Operation completed')}>Success</button>
 *       <button onClick={() => toast.error('Something went wrong')}>Error</button>
 *       <button onClick={() => toast.warning('Please review your input')}>Warning</button>
 *       <button onClick={() => toast.info('New update available')}>Info</button>
 *     </div>
 *   );
 * }
 * ```
 * 
 * @since 1.0.0
 */
export const useToast = () => {
  const context = useContext(ToastContext);
  if (context === undefined) {
    throw new Error('useToast must be used within a ToastProvider');
  }

  return {
    success: (message: string, options?: { duration?: number }) => context.addToast(message, { ...options, type: 'success' }),
    error: (message: string, options?: { duration?: number }) => context.addToast(message, { ...options, type: 'error' }),
    info: (message: string, options?: { duration?: number }) => context.addToast(message, { ...options, type: 'info' }),
    warning: (message: string, options?: { duration?: number }) => context.addToast(message, { ...options, type: 'warning' }),
  };
};

/**
 * useTouchGestures Hook
 * Handle touch gestures for mobile UX
 */

import { useEffect, useRef, useState } from 'react';

interface TouchGestureOptions {
  onSwipeLeft?: () => void;
  onSwipeRight?: () => void;
  onSwipeUp?: () => void;
  onSwipeDown?: () => void;
  onLongPress?: () => void;
  onDoubleTap?: () => void;
  threshold?: number;
  longPressDelay?: number;
}

export function useTouchGestures(options: TouchGestureOptions) {
  const {
    onSwipeLeft,
    onSwipeRight,
    onSwipeUp,
    onSwipeDown,
    onLongPress,
    onDoubleTap,
    threshold = 50,
    longPressDelay = 500,
  } = options;

  const touchStart = useRef<{ x: number; y: number; time: number } | null>(null);
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);
  const lastTap = useRef<number>(0);

  const handleTouchStart = (e: TouchEvent) => {
    const touch = e.touches[0];
    touchStart.current = {
      x: touch.clientX,
      y: touch.clientY,
      time: Date.now(),
    };

    // Long press detection
    if (onLongPress) {
      longPressTimer.current = setTimeout(() => {
        onLongPress();
      }, longPressDelay);
    }
  };

  const handleTouchMove = () => {
    // Cancel long press on move
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const handleTouchEnd = (e: TouchEvent) => {
    // Cancel long press
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }

    if (!touchStart.current) return;

    const touch = e.changedTouches[0];
    const deltaX = touch.clientX - touchStart.current.x;
    const deltaY = touch.clientY - touchStart.current.y;
    const deltaTime = Date.now() - touchStart.current.time;

    // Double tap detection
    if (onDoubleTap && deltaTime < 300 && Math.abs(deltaX) < 10 && Math.abs(deltaY) < 10) {
      const now = Date.now();
      if (now - lastTap.current < 300) {
        onDoubleTap();
      }
      lastTap.current = now;
    }

    // Swipe detection
    if (Math.abs(deltaX) > threshold || Math.abs(deltaY) > threshold) {
      if (Math.abs(deltaX) > Math.abs(deltaY)) {
        // Horizontal swipe
        if (deltaX > 0 && onSwipeRight) {
          onSwipeRight();
        } else if (deltaX < 0 && onSwipeLeft) {
          onSwipeLeft();
        }
      } else {
        // Vertical swipe
        if (deltaY > 0 && onSwipeDown) {
          onSwipeDown();
        } else if (deltaY < 0 && onSwipeUp) {
          onSwipeUp();
        }
      }
    }

    touchStart.current = null;
  };

  return {
    handleTouchStart,
    handleTouchMove,
    handleTouchEnd,
  };
}

/**
 * usePullToRefresh Hook
 * Implement pull-to-refresh pattern
 */
export function usePullToRefresh(onRefresh: () => Promise<void>, threshold = 100) {
  const [isPulling, setIsPulling] = useState(false);
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const startY = useRef<number>(0);

  const handleTouchStart = (e: TouchEvent) => {
    if (window.scrollY === 0) {
      startY.current = e.touches[0].clientY;
    }
  };

  const handleTouchMove = (e: TouchEvent) => {
    if (startY.current === 0 || window.scrollY > 0 || isRefreshing) return;

    const currentY = e.touches[0].clientY;
    const distance = currentY - startY.current;

    if (distance > 0) {
      setIsPulling(true);
      setPullDistance(Math.min(distance, threshold * 1.5));
    }
  };

  const handleTouchEnd = async () => {
    if (pullDistance >= threshold && !isRefreshing) {
      setIsRefreshing(true);
      try {
        await onRefresh();
      } finally {
        setIsRefreshing(false);
      }
    }

    setIsPulling(false);
    setPullDistance(0);
    startY.current = 0;
  };

  return {
    isPulling,
    pullDistance,
    isRefreshing,
    handleTouchStart,
    handleTouchMove,
    handleTouchEnd,
  };
}

/**
 * User Experience Enhancements
 * Features: Onboarding, tutorials, undo/redo, bulk operations
 */

import { useState, useCallback, useEffect, useRef } from 'react';

// ============================================
// UNDO/REDO SYSTEM
// ============================================

interface UndoRedoState<T> {
    past: T[];
    present: T;
    future: T[];
}

export function useUndoRedo<T>(initialState: T, maxHistory: number = 50) {
    const [state, setState] = useState<UndoRedoState<T>>({
        past: [],
        present: initialState,
        future: []
    });

    const set = useCallback((newState: T | ((prev: T) => T)) => {
        setState(current => {
            const nextState = typeof newState === 'function'
                ? (newState as (prev: T) => T)(current.present)
                : newState;

            return {
                past: [...current.past.slice(-maxHistory), current.present],
                present: nextState,
                future: []
            };
        });
    }, [maxHistory]);

    const undo = useCallback(() => {
        setState(current => {
            if (current.past.length === 0) return current;

            const previous = current.past[current.past.length - 1];
            const newPast = current.past.slice(0, -1);

            return {
                past: newPast,
                present: previous,
                future: [current.present, ...current.future]
            };
        });
    }, []);

    const redo = useCallback(() => {
        setState(current => {
            if (current.future.length === 0) return current;

            const next = current.future[0];
            const newFuture = current.future.slice(1);

            return {
                past: [...current.past, current.present],
                present: next,
                future: newFuture
            };
        });
    }, []);

    const reset = useCallback((newState: T) => {
        setState({
            past: [],
            present: newState,
            future: []
        });
    }, []);

    const canUndo = state.past.length > 0;
    const canRedo = state.future.length > 0;

    return {
        state: state.present,
        set,
        undo,
        redo,
        reset,
        canUndo,
        canRedo,
        history: {
            past: state.past.length,
            future: state.future.length
        }
    };
}

// ============================================
// BULK OPERATIONS
// ============================================

export interface BulkSelection<T> {
    selectedIds: Set<string>;
    allItems: T[];
}

export function useBulkSelection<T extends { id: string }>() {
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [lastSelectedIndex, setLastSelectedIndex] = useState<number | null>(null);

    const toggle = useCallback((id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
            }
            return next;
        });
    }, []);

    const select = useCallback((id: string) => {
        setSelectedIds(prev => new Set([...prev, id]));
    }, []);

    const deselect = useCallback((id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            next.delete(id);
            return next;
        });
    }, []);

    const selectAll = useCallback((items: T[]) => {
        setSelectedIds(new Set(items.map(item => item.id)));
    }, []);

    const deselectAll = useCallback(() => {
        setSelectedIds(new Set());
    }, []);

    const toggleAll = useCallback((items: T[]) => {
        setSelectedIds(prev => {
            if (prev.size === items.length) {
                return new Set();
            }
            return new Set(items.map(item => item.id));
        });
    }, []);

    // Shift+Click range selection
    const selectRange = useCallback((items: T[], currentIndex: number) => {
        if (lastSelectedIndex === null) {
            toggle(items[currentIndex].id);
            setLastSelectedIndex(currentIndex);
            return;
        }

        const start = Math.min(lastSelectedIndex, currentIndex);
        const end = Math.max(lastSelectedIndex, currentIndex);

        setSelectedIds(prev => {
            const next = new Set(prev);
            for (let i = start; i <= end; i++) {
                next.add(items[i].id);
            }
            return next;
        });
    }, [lastSelectedIndex, toggle]);

    const handleSelect = useCallback((items: T[], index: number, event: { shiftKey?: boolean; ctrlKey?: boolean }) => {
        if (event.shiftKey) {
            selectRange(items, index);
        } else if (event.ctrlKey) {
            toggle(items[index].id);
        } else {
            setSelectedIds(new Set([items[index].id]));
        }
        setLastSelectedIndex(index);
    }, [selectRange, toggle]);

    const isSelected = useCallback((id: string) => selectedIds.has(id), [selectedIds]);
    const isAllSelected = useCallback((items: T[]) => items.length > 0 && selectedIds.size === items.length, [selectedIds]);
    const isSomeSelected = selectedIds.size > 0;

    return {
        selectedIds,
        selectedCount: selectedIds.size,
        toggle,
        select,
        deselect,
        selectAll,
        deselectAll,
        toggleAll,
        selectRange,
        handleSelect,
        isSelected,
        isAllSelected,
        isSomeSelected
    };
}

// Bulk operation executor
export interface BulkOperationResult {
    success: number;
    failed: number;
    errors: { id: string; message: string }[];
}

export async function executeBulkOperation<T>(
    ids: string[],
    operation: (id: string) => Promise<void>,
    options: {
        onProgress?: (progress: number) => void;
        continueOnError?: boolean;
    } = {}
): Promise<BulkOperationResult> {
    const { onProgress, continueOnError = true } = options;
    const result: BulkOperationResult = { success: 0, failed: 0, errors: [] };

    for (let i = 0; i < ids.length; i++) {
        try {
            await operation(ids[i]);
            result.success++;
        } catch (e: any) {
            result.failed++;
            result.errors.push({ id: ids[i], message: e.message });
            if (!continueOnError) break;
        }
        onProgress?.((i + 1) / ids.length);
    }

    return result;
}

// ============================================
// ADVANCED FILTERING & SORTING
// ============================================

export type FilterOperator =
    | 'equals'
    | 'not_equals'
    | 'contains'
    | 'not_contains'
    | 'starts_with'
    | 'ends_with'
    | 'greater_than'
    | 'less_than'
    | 'between'
    | 'in'
    | 'is_empty'
    | 'is_not_empty';

export interface FilterCondition {
    field: string;
    operator: FilterOperator;
    value: any;
    value2?: any; // For 'between' operator
}

export interface FilterGroup {
    logic: 'and' | 'or';
    conditions: (FilterCondition | FilterGroup)[];
}

export interface SortConfig {
    field: string;
    direction: 'asc' | 'desc';
}

function evaluateCondition(item: any, condition: FilterCondition): boolean {
    const value = item[condition.field];
    const filterValue = condition.value;

    switch (condition.operator) {
        case 'equals':
            return value === filterValue;
        case 'not_equals':
            return value !== filterValue;
        case 'contains':
            return String(value).toLowerCase().includes(String(filterValue).toLowerCase());
        case 'not_contains':
            return !String(value).toLowerCase().includes(String(filterValue).toLowerCase());
        case 'starts_with':
            return String(value).toLowerCase().startsWith(String(filterValue).toLowerCase());
        case 'ends_with':
            return String(value).toLowerCase().endsWith(String(filterValue).toLowerCase());
        case 'greater_than':
            return value > filterValue;
        case 'less_than':
            return value < filterValue;
        case 'between':
            return value >= filterValue && value <= condition.value2;
        case 'in':
            return Array.isArray(filterValue) && filterValue.includes(value);
        case 'is_empty':
            return value === null || value === undefined || value === '';
        case 'is_not_empty':
            return value !== null && value !== undefined && value !== '';
        default:
            return true;
    }
}

function evaluateFilter(item: any, filter: FilterCondition | FilterGroup): boolean {
    if ('logic' in filter) {
        const results = filter.conditions.map(c => evaluateFilter(item, c));
        return filter.logic === 'and'
            ? results.every(Boolean)
            : results.some(Boolean);
    }
    return evaluateCondition(item, filter);
}

export function useAdvancedFilter<T>() {
    const [filters, setFilters] = useState<FilterGroup>({ logic: 'and', conditions: [] });
    const [sorts, setSorts] = useState<SortConfig[]>([]);

    const addFilter = useCallback((condition: FilterCondition) => {
        setFilters(prev => ({
            ...prev,
            conditions: [...prev.conditions, condition]
        }));
    }, []);

    const removeFilter = useCallback((index: number) => {
        setFilters(prev => ({
            ...prev,
            conditions: prev.conditions.filter((_, i) => i !== index)
        }));
    }, []);

    const updateFilter = useCallback((index: number, condition: FilterCondition) => {
        setFilters(prev => ({
            ...prev,
            conditions: prev.conditions.map((c, i) => i === index ? condition : c)
        }));
    }, []);

    const clearFilters = useCallback(() => {
        setFilters({ logic: 'and', conditions: [] });
    }, []);

    const setLogic = useCallback((logic: 'and' | 'or') => {
        setFilters(prev => ({ ...prev, logic }));
    }, []);

    const addSort = useCallback((sort: SortConfig) => {
        setSorts(prev => {
            const existing = prev.findIndex(s => s.field === sort.field);
            if (existing >= 0) {
                return prev.map((s, i) => i === existing ? sort : s);
            }
            return [...prev, sort];
        });
    }, []);

    const removeSort = useCallback((field: string) => {
        setSorts(prev => prev.filter(s => s.field !== field));
    }, []);

    const clearSorts = useCallback(() => {
        setSorts([]);
    }, []);

    const toggleSort = useCallback((field: string) => {
        setSorts(prev => {
            const existing = prev.find(s => s.field === field);
            if (existing) {
                if (existing.direction === 'asc') {
                    return prev.map(s => s.field === field ? { ...s, direction: 'desc' as const } : s);
                }
                return prev.filter(s => s.field !== field);
            }
            return [...prev, { field, direction: 'asc' as const }];
        });
    }, []);

    const apply = useCallback((items: T[]): T[] => {
        // Apply filters
        let result = items.filter(item => {
            if (filters.conditions.length === 0) return true;
            return evaluateFilter(item, filters);
        });

        // Apply sorts
        if (sorts.length > 0) {
            result = [...result].sort((a, b) => {
                for (const sort of sorts) {
                    const aVal = (a as any)[sort.field];
                    const bVal = (b as any)[sort.field];

                    if (aVal === bVal) continue;

                    const comparison = aVal < bVal ? -1 : 1;
                    return sort.direction === 'asc' ? comparison : -comparison;
                }
                return 0;
            });
        }

        return result;
    }, [filters, sorts]);

    return {
        filters,
        sorts,
        addFilter,
        removeFilter,
        updateFilter,
        clearFilters,
        setLogic,
        addSort,
        removeSort,
        clearSorts,
        toggleSort,
        apply,
        hasFilters: filters.conditions.length > 0,
        hasSorts: sorts.length > 0
    };
}

// ============================================
// ONBOARDING SYSTEM
// ============================================

export interface OnboardingStep {
    id: string;
    title: string;
    description: string;
    target?: string; // CSS selector
    position?: 'top' | 'bottom' | 'left' | 'right' | 'center';
    action?: string;
    skippable?: boolean;
}

export interface OnboardingFlow {
    id: string;
    name: string;
    steps: OnboardingStep[];
}

const ONBOARDING_KEY = 'portal_guru_onboarding';

export function useOnboarding(flowId: string, steps: OnboardingStep[]) {
    const [currentStep, setCurrentStep] = useState(0);
    const [isActive, setIsActive] = useState(false);
    const [completed, setCompleted] = useState<Set<string>>(() => {
        if (typeof window === 'undefined') return new Set();
        const stored = localStorage.getItem(ONBOARDING_KEY);
        if (!stored) return new Set();
        try {
            const parsed = JSON.parse(stored);
            return new Set(parsed.completed || []);
        } catch {
            return new Set();
        }
    });

    // Check if this flow is already completed
    const isFlowCompleted = completed.has(flowId);

    const start = useCallback(() => {
        if (!isFlowCompleted) {
            setCurrentStep(0);
            setIsActive(true);
        }
    }, [isFlowCompleted]);

    // Define complete first since it's referenced by next and skip
    const complete = useCallback(() => {
        setIsActive(false);
        setCompleted(prev => {
            const next = new Set([...prev, flowId]);
            localStorage.setItem(ONBOARDING_KEY, JSON.stringify({
                completed: Array.from(next)
            }));
            return next;
        });
    }, [flowId]);

    const next = useCallback(() => {
        if (currentStep < steps.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            complete();
        }
    }, [currentStep, steps.length, complete]);

    const previous = useCallback(() => {
        if (currentStep > 0) {
            setCurrentStep(prev => prev - 1);
        }
    }, [currentStep]);

    const skip = useCallback(() => {
        complete();
    }, [complete]);

    const reset = useCallback(() => {
        setCompleted(prev => {
            const next = new Set(prev);
            next.delete(flowId);
            localStorage.setItem(ONBOARDING_KEY, JSON.stringify({
                completed: Array.from(next)
            }));
            return next;
        });
        setCurrentStep(0);
    }, [flowId]);

    const goToStep = useCallback((stepIndex: number) => {
        if (stepIndex >= 0 && stepIndex < steps.length) {
            setCurrentStep(stepIndex);
        }
    }, [steps.length]);

    return {
        isActive,
        currentStep,
        currentStepData: steps[currentStep],
        totalSteps: steps.length,
        isFirstStep: currentStep === 0,
        isLastStep: currentStep === steps.length - 1,
        isFlowCompleted,
        progress: ((currentStep + 1) / steps.length) * 100,
        start,
        next,
        previous,
        skip,
        complete,
        reset,
        goToStep
    };
}

