/**
 * Performance Optimization Utilities
 * 
 * This file provides utilities for optimizing React component performance
 * including memoization helpers and render tracking in development.
 */

import { useRef, useEffect, useCallback, DependencyList, useState } from 'react';

/**
 * Custom hook that returns a stable callback reference
 * Unlike useCallback, this doesn't require dependencies
 * The callback always has access to the latest closure values
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useStableCallback<T extends (...args: any[]) => any>(callback: T): T {
    const callbackRef = useRef(callback);

    // Update the ref every render
    useEffect(() => {
        callbackRef.current = callback;
    });

    // Return a stable callback that uses the ref
    // Return a stable callback that uses the ref
    return useCallback(
        (...args: any[]) => {
            return callbackRef.current(...args);
        },
        []
    ) as T;
}

/**
 * Hook to detect unnecessary re-renders in development
 * Logs when a component re-renders and what props changed
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useWhyDidUpdate<T extends Record<string, any>>(
    name: string,
    props: T
) {
    const prevProps = useRef<T>();

    useEffect(() => {
        if (process.env.NODE_ENV === 'development') {
            if (prevProps.current) {
                const allKeys = Object.keys({ ...prevProps.current, ...props });
                const changedProps: Record<string, { from: unknown; to: unknown }> = {};

                allKeys.forEach((key) => {
                    if (prevProps.current![key] !== props[key]) {
                        changedProps[key] = {
                            from: prevProps.current![key],
                            to: props[key],
                        };
                    }
                });

                if (Object.keys(changedProps).length > 0) {
                    console.log(`[${name}] Why did update:`, changedProps);
                }
            }
        }
        prevProps.current = props;
    });
}

/**
 * Hook to debounce a value
 * Returns the debounced value after the specified delay
 */
export function useDebouncedValue<T>(value: T, delay: number): T {
    const [debouncedValue, setDebouncedValue] = useState(value);

    useEffect(() => {
        const timer = setTimeout(() => setDebouncedValue(value), delay);
        return () => clearTimeout(timer);
    }, [value, delay]);

    return debouncedValue;
}

/**
 * Hook to throttle a callback
 * Limits how often the callback can be invoked
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useThrottledCallback<T extends (...args: any[]) => any>(
    callback: T,
    delay: number,
    deps: DependencyList = []
): T {
    const lastCall = useRef<number>(0);
    const timeout = useRef<NodeJS.Timeout>();

    const throttled = useCallback(
        (...args: any[]) => {
            const now = Date.now();
            const timeSinceLastCall = now - lastCall.current;

            if (timeSinceLastCall >= delay) {
                lastCall.current = now;
                callback(...args);
            } else {
                // Schedule for later
                if (timeout.current) clearTimeout(timeout.current);
                timeout.current = setTimeout(() => {
                    lastCall.current = Date.now();
                    callback(...args);
                }, delay - timeSinceLastCall);
            }
        },
        // eslint-disable-next-line react-hooks/exhaustive-deps
        [delay, ...deps]
    ) as T;

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (timeout.current) clearTimeout(timeout.current);
        };
    }, []);

    return throttled;
}

/**
 * Hook to track render count in development
 */
export function useRenderCount(componentName: string): number {
    const count = useRef(0);

    useEffect(() => {
        count.current++;
        if (process.env.NODE_ENV === 'development') {
            console.log(`[${componentName}] Render count: ${count.current}`);
        }
    });

    // eslint-disable-next-line react-hooks/refs
    return count.current;
}

/**
 * Utility to create a fast comparison for arrays
 * Useful for memoization when array references change but content doesn't
 */
export function areArraysEqual<T>(a: T[], b: T[], compare?: (x: T, y: T) => boolean): boolean {
    if (a.length !== b.length) return false;
    if (compare) {
        return a.every((item, index) => compare(item, b[index]));
    }
    return a.every((item, index) => item === b[index]);
}

/**
 * Web fallback implementation for RingtonePicker
 * 
 * Provides a graceful degradation on web/non-Android platforms.
 * Uses the existing built-in sounds from notificationSoundSettings.
 */

import { WebPlugin } from '@capacitor/core';
import type { RingtonePickerPlugin, GetSoundsResult, PickerResult, PickerOptions } from './RingtonePicker';
import { SOUND_OPTIONS, previewSound } from '../services/notificationSoundSettings';

export class RingtonePickerWeb extends WebPlugin implements RingtonePickerPlugin {

    /**
     * On web, return the built-in app sounds as "notification sounds"
     */
    async getNotificationSounds(): Promise<GetSoundsResult> {
        const sounds = SOUND_OPTIONS
            .filter(s => s.id !== 'custom' && s.id !== 'none')
            .map((s, index) => ({
                id: index,
                title: s.name,
                uri: `app://sound/${s.id}`,
                type: 'notification' as const,
                isDefault: s.id === 'default',
            }));

        return {
            sounds,
            defaultSound: sounds.find(s => s.isDefault),
        };
    }

    /**
     * Same as notification sounds for web
     */
    async getRingtones(): Promise<GetSoundsResult> {
        return this.getNotificationSounds();
    }

    /**
     * Preview using the existing web audio implementation
     */
    async previewSound(options: { uri: string }): Promise<void> {
        // Parse the app:// URI to get the sound ID
        const match = options.uri.match(/app:\/\/sound\/(.+)/);
        if (match) {
            const soundId = match[1] as any;
            previewSound(soundId);
        }
    }

    /**
     * No-op on web
     */
    async stopPreview(): Promise<void> {
        // Web audio stops automatically
    }

    /**
     * On web, show a simple alert since we can't use system picker
     */
    async openPicker(_options?: PickerOptions): Promise<PickerResult> {
        // Return cancelled since web doesn't have a picker
        console.warn('RingtonePicker: System picker not available on web. Use the in-app sound picker instead.');
        return {
            uri: null,
            cancelled: true,
        };
    }

    /**
     * Return the default app sound
     */
    async getDefaultSound(): Promise<{ uri: string; title?: string }> {
        return {
            uri: 'app://sound/default',
            title: 'Ding Dong',
        };
    }
}

/**
 * Export Service
 * 
 * Handles data export to PDF, Excel, and CSV formats.
 * Includes progress tracking and error handling.
 */

import { getJsPDF, getAutoTable, getXLSX } from '../utils/dynamicImports';

export type ExportFormat = 'pdf' | 'excel' | 'csv';

export interface ColumnDefinition {
    key: string;
    label: string;
    type?: 'string' | 'number' | 'date' | 'boolean';
    width?: number;
}

export interface ExportOptions {
    format: ExportFormat;
    filename: string;
    title?: string;
    columns: ColumnDefinition[];
    data: Record<string, unknown>[];
    onProgress?: (progress: number) => void;
    includeHeader?: boolean;
    includeFooter?: boolean;
    dateFormat?: string;
}

export interface ExportResult {
    success: boolean;
    filename?: string;
    error?: string;
}

/**
 * Format value based on column type
 */
function formatValue(value: unknown, type?: string, dateFormat?: string): string {
    if (value === null || value === undefined) return '';

    switch (type) {
        case 'date': {
            const date = new Date(value as string | number | Date);
            if (isNaN(date.getTime())) return String(value);
            return date.toLocaleDateString('id-ID', {
                day: '2-digit',
                month: 'long',
                year: 'numeric',
            });
        }
        case 'boolean':
            return value ? 'Ya' : 'Tidak';
        case 'number':
            return typeof value === 'number' ? value.toLocaleString('id-ID') : String(value);
        default:
            return String(value);
    }
}

/**
 * Export to PDF using jsPDF and autoTable
 */
export async function exportToPDF(options: ExportOptions): Promise<ExportResult> {
    try {
        const {
            filename,
            title,
            columns,
            data,
            onProgress,
            includeHeader = true,
            includeFooter = true,
        } = options;

        onProgress?.(10);

        // Dynamically import jsPDF
        const { default: jsPDF } = await getJsPDF();
        const { default: autoTable } = await getAutoTable();

        // Create PDF document
        const doc = new jsPDF({
            orientation: data.length > 100 ? 'landscape' : 'portrait',
            unit: 'mm',
            format: 'a4',
        });

        onProgress?.(20);

        // Add header
        if (includeHeader && title) {
            doc.setFontSize(18);
            doc.setFont('helvetica', 'bold');
            doc.text(title, 14, 20);

            doc.setFontSize(10);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(100);
            doc.text(`Diekspor pada: ${new Date().toLocaleDateString('id-ID', {
                day: 'numeric',
                month: 'long',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit',
            })}`, 14, 28);
            doc.text(`Total: ${data.length} data`, 14, 34);
        }

        onProgress?.(40);

        // Prepare table data
        const headers = columns.map(col => col.label);
        const rows = data.map(row =>
            columns.map(col => formatValue(row[col.key], col.type))
        );

        onProgress?.(60);

        // Add table
        autoTable(doc, {
            head: [headers],
            body: rows,
            startY: includeHeader && title ? 40 : 14,
            styles: {
                fontSize: 9,
                cellPadding: 3,
            },
            headStyles: {
                fillColor: [99, 102, 241], // Indigo
                textColor: 255,
                fontStyle: 'bold',
            },
            alternateRowStyles: {
                fillColor: [248, 250, 252], // Slate-50
            },
            didDrawPage: (data) => {
                // Add footer on each page
                if (includeFooter) {
                    const pageCount = doc.getNumberOfPages();
                    const currentPage = data.pageNumber;

                    doc.setFontSize(8);
                    doc.setTextColor(128);
                    doc.text(
                        `Halaman ${currentPage} dari ${pageCount}`,
                        doc.internal.pageSize.width / 2,
                        doc.internal.pageSize.height - 10,
                        { align: 'center' }
                    );
                }
            },
        });

        onProgress?.(90);

        // Save file
        const fullFilename = `${filename}.pdf`;
        doc.save(fullFilename);

        onProgress?.(100);

        return { success: true, filename: fullFilename };
    } catch (error) {
        console.error('PDF export failed:', error);
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to export PDF'
        };
    }
}

/**
 * Export to Excel using xlsx library
 */
export async function exportToExcel(options: ExportOptions): Promise<ExportResult> {
    try {
        const {
            filename,
            title,
            columns,
            data,
            onProgress,
        } = options;

        onProgress?.(10);

        // Dynamically import XLSX
        const XLSX = await getXLSX();

        // Create workbook
        const wb = XLSX.utils.book_new();

        onProgress?.(20);

        // Prepare data with headers
        const headers = columns.map(col => col.label);
        const rows = data.map(row =>
            columns.map(col => {
                const value = row[col.key];
                // Keep numbers and dates as their original types for Excel
                if (col.type === 'number' && typeof value === 'number') {
                    return value;
                }
                if (col.type === 'date' && value) {
                    return new Date(value as string | number | Date);
                }
                if (col.type === 'boolean') {
                    return value ? 'Ya' : 'Tidak';
                }
                return value ?? '';
            })
        );

        onProgress?.(40);

        // Create worksheet
        const wsData = [headers, ...rows];
        const ws = XLSX.utils.aoa_to_sheet(wsData);

        // Set column widths
        const colWidths = columns.map(col => ({
            wch: col.width || Math.max(col.label.length, 15)
        }));
        ws['!cols'] = colWidths;

        onProgress?.(60);

        // Add worksheet to workbook
        const sheetName = (title || 'Data').substring(0, 31); // Excel sheet name limit
        XLSX.utils.book_append_sheet(wb, ws, sheetName);

        onProgress?.(80);

        // Generate file
        const fullFilename = `${filename}.xlsx`;
        XLSX.writeFile(wb, fullFilename);

        onProgress?.(100);

        return { success: true, filename: fullFilename };
    } catch (error) {
        console.error('Excel export failed:', error);
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to export Excel'
        };
    }
}

/**
 * Export to CSV with UTF-8 BOM for Excel compatibility
 */
export async function exportToCSV(options: ExportOptions): Promise<ExportResult> {
    try {
        const {
            filename,
            columns,
            data,
            onProgress,
        } = options;

        onProgress?.(10);

        // Prepare headers
        const headers = columns.map(col => escapeCSVField(col.label));

        onProgress?.(30);

        // Prepare rows
        const rows = data.map(row =>
            columns.map(col => escapeCSVField(formatValue(row[col.key], col.type)))
        );

        onProgress?.(60);

        // Create CSV content with BOM for Excel UTF-8 compatibility
        const BOM = '\uFEFF';
        const csvContent = BOM + [
            headers.join(','),
            ...rows.map(row => row.join(','))
        ].join('\r\n');

        onProgress?.(80);

        // Create and download file
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${filename}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        onProgress?.(100);

        return { success: true, filename: `${filename}.csv` };
    } catch (error) {
        console.error('CSV export failed:', error);
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to export CSV'
        };
    }
}

/**
 * Escape CSV field to handle special characters
 */
function escapeCSVField(field: string): string {
    if (field === null || field === undefined) return '';

    const stringField = String(field);

    // If field contains comma, newline, or quote, wrap in quotes and escape quotes
    if (stringField.includes(',') || stringField.includes('\n') || stringField.includes('"')) {
        return `"${stringField.replace(/"/g, '""')}"`;
    }

    return stringField;
}

/**
 * Main export function that routes to appropriate format handler
 */
export async function exportData(options: ExportOptions): Promise<ExportResult> {
    const { format } = options;

    switch (format) {
        case 'pdf':
            return exportToPDF(options);
        case 'excel':
            return exportToExcel(options);
        case 'csv':
            return exportToCSV(options);
        default:
            return { success: false, error: `Unsupported format: ${format}` };
    }
}

/**
 * Export with Web Worker for large datasets (optional enhancement)
 */
export async function exportDataAsync(
    options: ExportOptions,
    onProgress?: (progress: number) => void
): Promise<ExportResult> {
    return new Promise((resolve) => {
        // For large datasets, we could use a Web Worker here
        // For now, we use the synchronous version with progress callbacks
        exportData({ ...options, onProgress })
            .then(resolve)
            .catch(error => resolve({
                success: false,
                error: error instanceof Error ? error.message : 'Export failed'
            }));
    });
}

export default {
    exportData,
    exportToPDF,
    exportToExcel,
    exportToCSV,
    exportDataAsync,
};

