    { key: 'gender', label: 'Jenis Kelamin', required: true },
    { key: 'class_name', label: 'Nama Kelas', required: false },
    { key: 'access_code', label: 'Kode Akses', required: false },
] as const;

/**
 * Gender value mappings for normalization
 */
const GENDER_MAPPINGS: Record<string, 'Laki-laki' | 'Perempuan'> = {
    'l': 'Laki-laki',
    'laki-laki': 'Laki-laki',
    'laki': 'Laki-laki',
    'male': 'Laki-laki',
    'm': 'Laki-laki',
    'pria': 'Laki-laki',
    'p': 'Perempuan',
    'perempuan': 'Perempuan',
    'female': 'Perempuan',
    'f': 'Perempuan',
    'wanita': 'Perempuan',
};

/**
 * Parse Excel or CSV file and extract data
 */
export const parseFile = async (file: File): Promise<{ headers: string[]; rows: unknown[][] }> => {
    const XLSX = await getXLSX();
    return new Promise((resolve, reject) => {
        const reader = new FileReader();

        reader.onload = (e) => {
            try {
                const data = e.target?.result;
                const workbook = XLSX.read(data, { type: 'array' });

                // Get first sheet
                const firstSheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[firstSheetName];

                // Convert to JSON with header option
                const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as unknown[][];

                if (jsonData.length === 0) {
                    reject(new Error('File kosong'));
                    return;
                }

                const headers = (jsonData[0] || []).map(h => String(h || '').trim());
                const rows = jsonData.slice(1).filter(row => row.some(cell => cell !== null && cell !== undefined && cell !== ''));

                resolve({ headers, rows });
            } catch (error) {
                reject(new Error('Gagal membaca file. Pastikan format file benar.'));
            }
        };

        reader.onerror = () => reject(new Error('Gagal membaca file'));
        reader.readAsArrayBuffer(file);
    });
};

/**
 * Auto-detect column mappings based on header names
 */
export const autoDetectMappings = (headers: string[]): ColumnMapping[] => {
    const mappings: ColumnMapping[] = [];

    const namePatterns = ['nama', 'name', 'nama siswa', 'nama lengkap', 'student name'];
    const genderPatterns = ['gender', 'jenis kelamin', 'kelamin', 'jk', 'l/p'];
    const classPatterns = ['kelas', 'class', 'nama kelas', 'class name'];
    const codePatterns = ['kode', 'code', 'kode akses', 'access code', 'nis', 'nisn'];

    headers.forEach(header => {
        const lowerHeader = header.toLowerCase().trim();

        if (namePatterns.some(p => lowerHeader.includes(p))) {
            mappings.push({ sourceColumn: header, targetField: 'name', required: true });
        } else if (genderPatterns.some(p => lowerHeader.includes(p))) {
            mappings.push({
                sourceColumn: header,
                targetField: 'gender',
                required: true,
                transform: normalizeGender,
            });
        } else if (classPatterns.some(p => lowerHeader.includes(p))) {
            mappings.push({ sourceColumn: header, targetField: 'class_name', required: false });
        } else if (codePatterns.some(p => lowerHeader.includes(p))) {
            mappings.push({ sourceColumn: header, targetField: 'access_code', required: false });
        }
    });

    return mappings;
};

/**
 * Normalize gender value
 */
export const normalizeGender = (value: unknown): 'Laki-laki' | 'Perempuan' | null => {
    if (!value) return null;
    const normalized = String(value).toLowerCase().trim();
    return GENDER_MAPPINGS[normalized] || null;
};

/**
 * Validate a single row of data
 */
export const validateRow = (
    rowData: Record<string, unknown>,
    rowNumber: number,
    mappings: ColumnMapping[]
): ParsedRow => {
    const errors: ImportError[] = [];
    const data: Record<string, unknown> = {};

    // Check required fields
    for (const mapping of mappings) {
        const value = rowData[mapping.sourceColumn];
        const transformedValue = mapping.transform ? mapping.transform(value) : value;

        if (mapping.required && (!transformedValue || String(transformedValue).trim() === '')) {
            errors.push({
                row: rowNumber,
                column: mapping.sourceColumn,
                value: value,
                message: `${mapping.targetField} wajib diisi`,
            });
        } else {
            data[mapping.targetField] = transformedValue;
        }
    }

    // Validate specific fields
    if (typeof data.name === 'string' && data.name.length < 2) {
        errors.push({
            row: rowNumber,
            column: 'name',
            value: data.name,
            message: 'Nama minimal 2 karakter',
        });
    }

    if (typeof data.gender === 'string' && !['Laki-laki', 'Perempuan'].includes(data.gender)) {
        errors.push({
            row: rowNumber,
            column: 'gender',
            value: data.gender,
            message: 'Jenis kelamin harus "Laki-laki" atau "Perempuan"',
        });
    }

    return {
        rowNumber,
        data,
        isValid: errors.length === 0,
        errors,
    };
};

/**
 * Parse and validate all rows
 */
export const parseAndValidate = (
    headers: string[],
    rows: unknown[][],
    mappings: ColumnMapping[]
): ParsedRow[] => {
    return rows.map((row, index) => {
        // Convert row array to object using headers
        const rowData: Record<string, any> = {};
        headers.forEach((header, colIndex) => {
            rowData[header] = row[colIndex];
        });

        return validateRow(rowData, index + 2, mappings); // +2 because row 1 is header
    });
};

/**
 * Generate import template with professional styling
 */
export const generateTemplate = async (format: 'xlsx' | 'csv' = 'xlsx'): Promise<Blob> => {
    const TOTAL_ROWS = 30; // Pre-formatted rows for teachers

    if (format === 'csv') {
        const XLSX = await getXLSX();
        // Simple CSV for compatibility
        const templateData = [['Nama Siswa', 'Jenis Kelamin', 'Kelas']];
        for (let i = 1; i <= TOTAL_ROWS; i++) {
            templateData.push(['', '', '']);
        }
        const worksheet = XLSX.utils.aoa_to_sheet(templateData);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, 'Template');
        const excelBuffer = XLSX.write(workbook, { bookType: 'csv', type: 'array' });
        return new Blob([excelBuffer], { type: 'text/csv' });
    }

    // Use ExcelJS for styled XLSX
    const ExcelJS = await import('exceljs');
    const workbook = new ExcelJS.Workbook();
    workbook.creator = 'Portal Guru';
    workbook.created = new Date();

    const worksheet = workbook.addWorksheet('Data Siswa', {
        properties: { tabColor: { argb: '4F46E5' } },
        views: [{ state: 'frozen', ySplit: 1 }] // Freeze header row
    });

    // Column widths
    worksheet.columns = [
        { width: 8 },   // A - No
        { width: 35 },  // B - Nama Siswa
        { width: 18 },  // C - Jenis Kelamin
        { width: 12 },  // D - Kelas
    ];

    // === ROW 1: Header (MUST be row 1 for parser compatibility) ===
    const headerRow = worksheet.getRow(1);
    headerRow.values = ['No', 'Nama Siswa', 'Jenis Kelamin', 'Kelas'];
    headerRow.height = 28;
    headerRow.eachCell((cell, colNumber) => {
        if (colNumber <= 4) {
            cell.font = { bold: true, color: { argb: 'FFFFFF' }, size: 11 };
            cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: '4F46E5' } };
            cell.alignment = { horizontal: 'center', vertical: 'middle' };
            cell.border = {
                top: { style: 'thin', color: { argb: '4338CA' } },
                left: { style: 'thin', color: { argb: '4338CA' } },
                bottom: { style: 'thin', color: { argb: '4338CA' } },
                right: { style: 'thin', color: { argb: '4338CA' } }
            };
        }
    });

    // === DATA ROWS (30 empty rows with formatting) ===
    for (let i = 0; i < TOTAL_ROWS; i++) {
        const dataRow = worksheet.getRow(2 + i); // Start from row 2
        dataRow.values = [i + 1, '', '', ''];
        dataRow.height = 22;

        const isEven = i % 2 === 0;
        dataRow.eachCell((cell, colNumber) => {
            if (colNumber <= 4) {
                cell.fill = {
                    type: 'pattern',
                    pattern: 'solid',
                    fgColor: { argb: isEven ? 'F8FAFC' : 'FFFFFF' }
                };
                cell.border = {
                    top: { style: 'thin', color: { argb: 'E2E8F0' } },
                    left: { style: 'thin', color: { argb: 'E2E8F0' } },
                    bottom: { style: 'thin', color: { argb: 'E2E8F0' } },
                    right: { style: 'thin', color: { argb: 'E2E8F0' } }
                };
                cell.alignment = { vertical: 'middle' };
            }
        });

        // Style row number column
        const noCell = dataRow.getCell(1);
        noCell.alignment = { horizontal: 'center', vertical: 'middle' };
        noCell.font = { color: { argb: '94A3B8' } };

        // Center align for gender and class
        dataRow.getCell(3).alignment = { horizontal: 'center', vertical: 'middle' };
        dataRow.getCell(4).alignment = { horizontal: 'center', vertical: 'middle' };
    }

    // === NOTES SECTION (after data rows) ===
    const notesStartRow = 2 + TOTAL_ROWS + 1; // After data rows + 1 empty row

    worksheet.mergeCells(`A${notesStartRow}:D${notesStartRow}`);
    const notesHeaderCell = worksheet.getCell(`A${notesStartRow}`);
    notesHeaderCell.value = '≡ƒôî PETUNJUK PENGISIAN:';
    notesHeaderCell.font = { bold: true, size: 10, color: { argb: '4F46E5' } };
    notesHeaderCell.alignment = { horizontal: 'left', vertical: 'middle' };

    const notes = [
        'ΓÇó Kolom "Nama Siswa" dan "Jenis Kelamin" WAJIB diisi',
        'ΓÇó Jenis Kelamin: ketik "L" atau "Laki-laki" untuk laki-laki, "P" atau "Perempuan" untuk perempuan',
        'ΓÇó Kolom "No" akan diabaikan saat import (hanya untuk penomoran)',
        'ΓÇó Baris yang kosong (tanpa nama) akan otomatis diabaikan',
    ];

    notes.forEach((note, idx) => {
        worksheet.mergeCells(`A${notesStartRow + 1 + idx}:D${notesStartRow + 1 + idx}`);
        const noteCell = worksheet.getCell(`A${notesStartRow + 1 + idx}`);
        noteCell.value = note;
        noteCell.font = { size: 9, color: { argb: '64748B' } };
        noteCell.alignment = { horizontal: 'left', vertical: 'middle' };
    });

    // Download file
    const buffer = await workbook.xlsx.writeBuffer();
    return new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
};

/**
 * Download template file
 */
export const downloadTemplate = async (format: 'xlsx' | 'csv' = 'xlsx'): Promise<void> => {
    const blob = await generateTemplate(format);
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `template_import_siswa.${format}`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
};

export default {
    parseFile,
    autoDetectMappings,
    normalizeGender,
    validateRow,
    parseAndValidate,
    generateTemplate,
    downloadTemplate,
    STUDENT_FIELDS,
};

/**
 * Notification Service
 * 
 * Provides task notification functionality including due task detection,
 * notification preferences, and reminder management.
 * 
 * @module services/NotificationService
 * @since 1.0.0
 */

import { supabase } from './supabase';

/**
 * Notification types
 */
export type NotificationType = 'task_due' | 'task_overdue' | 'attendance_reminder' | 'message' | 'system';

export interface Notification {
    id: string;
    type: NotificationType;
    title: string;
    message: string;
    timestamp: Date;
    read: boolean;
    metadata?: Record<string, any>;
    link?: string;
}

export interface NotificationPreferences {
    taskReminders: boolean;
    taskReminderHours: number; // hours before due date
    dailyDigest: boolean;
    attendanceReminders: boolean;
    messageNotifications: boolean;
}

export interface DueTask {
    id: string;
    title: string;
    description?: string;
    due_date: string;
    status: string;
    isOverdue: boolean;
    hoursUntilDue: number;
}

// Storage keys
const NOTIFICATIONS_KEY = 'portal_guru_notifications';
const PREFERENCES_KEY = 'portal_guru_notification_prefs';
const LAST_CHECK_KEY = 'portal_guru_last_notification_check';

/**
 * Default notification preferences
 */
const DEFAULT_PREFERENCES: NotificationPreferences = {
    taskReminders: true,
    taskReminderHours: 24,
    dailyDigest: false,
    attendanceReminders: true,
    messageNotifications: true,
};

/**
 * Get notifications from storage
 */
export const getNotifications = (): Notification[] => {
    try {
        const stored = localStorage.getItem(NOTIFICATIONS_KEY);
        if (!stored) return [];
        return JSON.parse(stored).map((n: any) => ({
            ...n,
            timestamp: new Date(n.timestamp),
        }));
    } catch {
        return [];
    }
};

/**
 * Save notifications to storage
 */
const saveNotifications = (notifications: Notification[]): void => {
    localStorage.setItem(NOTIFICATIONS_KEY, JSON.stringify(notifications));
};

/**
 * Add a new notification
 */
export const addNotification = (notification: Omit<Notification, 'id' | 'timestamp' | 'read'>): void => {
    const notifications = getNotifications();

    // Check for duplicate (same type and metadata id)
    const isDuplicate = notifications.some(n =>
        n.type === notification.type &&
        n.metadata?.taskId === notification.metadata?.taskId
    );

    if (isDuplicate) return;

    const newNotification: Notification = {
        ...notification,
        id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        timestamp: new Date(),
        read: false,
    };

    notifications.unshift(newNotification);

    // Keep only last 50 notifications
    saveNotifications(notifications.slice(0, 50));
};

/**
 * Mark notification as read
 */
export const markAsRead = (notificationId: string): void => {
    const notifications = getNotifications();
    const index = notifications.findIndex(n => n.id === notificationId);

    if (index !== -1) {
        notifications[index].read = true;
        saveNotifications(notifications);
    }
};

/**
 * Mark all notifications as read
 */
export const markAllAsRead = (): void => {
    const notifications = getNotifications();
    notifications.forEach(n => n.read = true);
    saveNotifications(notifications);
};

/**
 * Clear all notifications
 */
export const clearNotifications = (): void => {
    localStorage.removeItem(NOTIFICATIONS_KEY);
};

/**
 * Get unread notification count
 */
export const getUnreadCount = (): number => {
    return getNotifications().filter(n => !n.read).length;
};

/**
 * Get notification preferences
 */
export const getPreferences = (): NotificationPreferences => {
    try {
        const stored = localStorage.getItem(PREFERENCES_KEY);
        if (!stored) return DEFAULT_PREFERENCES;
        return { ...DEFAULT_PREFERENCES, ...JSON.parse(stored) };
    } catch {
        return DEFAULT_PREFERENCES;
    }
};

/**
 * Save notification preferences
 */
export const savePreferences = (prefs: Partial<NotificationPreferences>): void => {
    const current = getPreferences();
    localStorage.setItem(PREFERENCES_KEY, JSON.stringify({ ...current, ...prefs }));
};

/**
 * Get tasks that are due soon or overdue
 */
export const getDueTasks = async (userId: string): Promise<DueTask[]> => {
    const { data: tasks } = await supabase
        .from('tasks')
        .select('id, title, description, due_date, status')
        .eq('user_id', userId)
        .neq('status', 'done')
        .not('due_date', 'is', null)
        .order('due_date', { ascending: true });

    if (!tasks) return [];

    const now = new Date();
    const preferences = getPreferences();
    const reminderThreshold = preferences.taskReminderHours * 60 * 60 * 1000; // Convert to ms

    return tasks
        .filter(task => task.due_date !== null)
        .map(task => {
            const dueDate = new Date(task.due_date!);
            const timeDiff = dueDate.getTime() - now.getTime();
            const hoursUntilDue = timeDiff / (1000 * 60 * 60);

            return {
                id: task.id,
                title: task.title,
                description: task.description ?? undefined,
                due_date: task.due_date!,
                status: task.status,
                isOverdue: timeDiff < 0,
                hoursUntilDue: Math.round(hoursUntilDue),
            };
        })
        .filter(task => task.isOverdue || task.hoursUntilDue <= preferences.taskReminderHours);
};

/**
 * Check for due tasks and create notifications
 */
export const checkAndNotify = async (userId: string): Promise<number> => {
    const preferences = getPreferences();
    if (!preferences.taskReminders) return 0;

    const lastCheck = localStorage.getItem(LAST_CHECK_KEY);
    const now = Date.now();

    // Don't check more than once per 15 minutes
    if (lastCheck && now - parseInt(lastCheck) < 15 * 60 * 1000) {
        return getUnreadCount();
    }

    localStorage.setItem(LAST_CHECK_KEY, now.toString());

    const dueTasks = await getDueTasks(userId);
    let newNotifications = 0;

    for (const task of dueTasks) {
        if (task.isOverdue) {
            addNotification({
                type: 'task_overdue',
                title: 'Tugas Terlambat!',
                message: `"${task.title}" sudah melewati deadline.`,
                metadata: { taskId: task.id },
                link: '/tugas',
            });
            newNotifications++;
        } else if (task.hoursUntilDue <= 24) {
            addNotification({
                type: 'task_due',
                title: 'Tugas Hampir Deadline',
                message: `"${task.title}" deadline dalam ${task.hoursUntilDue} jam.`,
                metadata: { taskId: task.id, hoursLeft: task.hoursUntilDue },
                link: '/tugas',
            });
            newNotifications++;
        }
    }

    return getUnreadCount();
};

/**
 * Format time ago string
 */
export const formatTimeAgo = (date: Date): string => {
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / (1000 * 60));
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffMins < 1) return 'Baru saja';
    if (diffMins < 60) return `${diffMins} menit lalu`;
    if (diffHours < 24) return `${diffHours} jam lalu`;
    if (diffDays < 7) return `${diffDays} hari lalu`;
    return date.toLocaleDateString('id-ID');
};

/**
 * Get notification icon based on type
 */
export const getNotificationIcon = (type: NotificationType): string => {
    switch (type) {
        case 'task_due':
            return 'ΓÅ░';
        case 'task_overdue':
            return '≡ƒÜ¿';
        case 'attendance_reminder':
            return '≡ƒôï';
        case 'message':
            return '≡ƒÆ¼';
        case 'system':
        default:
            return '≡ƒöö';
    }
};

export default {
    getNotifications,
    addNotification,
    markAsRead,
    markAllAsRead,
    clearNotifications,
    getUnreadCount,
    getPreferences,
    savePreferences,
    getDueTasks,
    checkAndNotify,
    formatTimeAgo,
    getNotificationIcon,
};

/**
 * Performance Monitoring Service
 * 
 * Tracks Core Web Vitals and other performance metrics:
 * - FCP (First Contentful Paint)
 * - LCP (Largest Contentful Paint)
 * - FID (First Input Delay)
 * - CLS (Cumulative Layout Shift)
 * - TTFB (Time to First Byte)
 * - INP (Interaction to Next Paint)
 */

import { logger } from './logger';

interface PerformanceMetric {
    name: string;
    value: number;
    rating: 'good' | 'needs-improvement' | 'poor';
    timestamp: number;
}

interface WebVitalsThresholds {
    good: number;
    poor: number;
}

// Core Web Vitals thresholds (in milliseconds, except CLS which is unitless)
const THRESHOLDS: Record<string, WebVitalsThresholds> = {
    FCP: { good: 1800, poor: 3000 },
    LCP: { good: 2500, poor: 4000 },
    FID: { good: 100, poor: 300 },
    CLS: { good: 0.1, poor: 0.25 },
    TTFB: { good: 800, poor: 1800 },
    INP: { good: 200, poor: 500 },
};

class PerformanceMonitoringService {
    private static instance: PerformanceMonitoringService;
    private metrics: Map<string, PerformanceMetric> = new Map();
    private observers: Set<(metrics: Map<string, PerformanceMetric>) => void> = new Set();
    private isEnabled: boolean = true;

    private constructor() {
        if (typeof window !== 'undefined') {
            this.initializeObservers();
        }
    }

    static getInstance(): PerformanceMonitoringService {
        if (!PerformanceMonitoringService.instance) {
            PerformanceMonitoringService.instance = new PerformanceMonitoringService();
        }
        return PerformanceMonitoringService.instance;
    }

    /**
     * Enable or disable performance monitoring
     */
    setEnabled(enabled: boolean): void {
        this.isEnabled = enabled;
    }

    /**
     * Get rating for a metric value
     */
    private getRating(name: string, value: number): 'good' | 'needs-improvement' | 'poor' {
        const threshold = THRESHOLDS[name];
        if (!threshold) return 'good';

        if (value <= threshold.good) return 'good';
        if (value <= threshold.poor) return 'needs-improvement';
        return 'poor';
    }

    /**
     * Record a metric
     */
    private recordMetric(name: string, value: number): void {
        if (!this.isEnabled) return;

        const metric: PerformanceMetric = {
            name,
            value,
            rating: this.getRating(name, value),
            timestamp: Date.now(),
        };

        this.metrics.set(name, metric);
        this.notifyObservers();

        // Log warnings for poor metrics
        if (metric.rating === 'poor') {
            logger.warn(`Poor ${name} detected: ${value.toFixed(2)}`, 'PerformanceMonitor', { metric });

            if (process.env.NODE_ENV === 'development') {
                console.warn(`ΓÜá∩╕Å Poor ${name}: ${value.toFixed(2)} (threshold: ${THRESHOLDS[name].poor})`);
            }
        } else if (metric.rating === 'needs-improvement') {
            logger.info(`${name} needs improvement: ${value.toFixed(2)}`, 'PerformanceMonitor', { metric });
        } else {
            logger.debug(`${name}: ${value.toFixed(2)} (good)`, 'PerformanceMonitor', { metric });
        }
    }

    /**
     * Initialize performance observers
     */
    private initializeObservers(): void {
        // FCP - First Contentful Paint
        this.observePaint('first-contentful-paint', 'FCP');

        // LCP - Largest Contentful Paint
        this.observeLCP();

        // FID - First Input Delay
        this.observeFID();

        // CLS - Cumulative Layout Shift
        this.observeCLS();

        // TTFB - Time to First Byte
        this.observeTTFB();

        // INP - Interaction to Next Paint
        this.observeINP();

        // Log navigation timing on load
        if (document.readyState === 'complete') {
            this.logNavigationTiming();
        } else {
            window.addEventListener('load', () => {
                setTimeout(() => this.logNavigationTiming(), 0);
            });
        }
    }

    /**
     * Observe paint entries
     */
    private observePaint(entryType: string, metricName: string): void {
        try {
            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries();
                entries.forEach((entry) => {
                    if (entry.name === entryType) {
                        this.recordMetric(metricName, entry.startTime);
                    }
                });
            });
            observer.observe({ type: 'paint', buffered: true });
        } catch (e) {
            // PerformanceObserver not supported
        }
    }

    /**
     * Observe Largest Contentful Paint
     */
    private observeLCP(): void {
        try {
            let lcp = 0;
            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries();
                const lastEntry = entries[entries.length - 1] as PerformanceEntry & { startTime: number };
                lcp = lastEntry.startTime;
            });
            observer.observe({ type: 'largest-contentful-paint', buffered: true });

            // Report LCP on visibility change or page unload
            const reportLCP = () => {
                if (lcp > 0) {
                    this.recordMetric('LCP', lcp);
                }
            };

            document.addEventListener('visibilitychange', () => {
                if (document.visibilityState === 'hidden') {
                    reportLCP();
                }
            });

            window.addEventListener('beforeunload', reportLCP);
        } catch (e) {
            // LCP not supported
        }
    }

    /**
     * Observe First Input Delay
     */
    private observeFID(): void {
        try {
            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries();
                entries.forEach((entry) => {
                    const fidEntry = entry as PerformanceEventTiming;
                    const fid = fidEntry.processingStart - fidEntry.startTime;
                    this.recordMetric('FID', fid);
                });
            });
            observer.observe({ type: 'first-input', buffered: true });
        } catch (e) {
            // FID not supported
        }
    }

    /**
     * Observe Cumulative Layout Shift
     */
    private observeCLS(): void {
        try {
            let cls = 0;
            let sessionValue = 0;
            let sessionEntries: PerformanceEntry[] = [];

            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries() as (PerformanceEntry & { hadRecentInput: boolean; value: number })[];

                for (const entry of entries) {
                    // Only count shifts without recent input
                    if (!entry.hadRecentInput) {
                        const firstEntry = sessionEntries[0] as PerformanceEntry & { startTime: number } | undefined;
                        const lastEntry = sessionEntries[sessionEntries.length - 1] as PerformanceEntry & { startTime: number } | undefined;

                        // If the entry occurred within 1 second of the previous entry and
                        // 5 seconds of the first entry in the session
                        if (
                            sessionValue &&
                            entry.startTime - (lastEntry?.startTime || 0) < 1000 &&
                            entry.startTime - (firstEntry?.startTime || 0) < 5000
                        ) {
                            sessionValue += entry.value;
                            sessionEntries.push(entry);
                        } else {
                            sessionValue = entry.value;
                            sessionEntries = [entry];
                        }

                        if (sessionValue > cls) {
                            cls = sessionValue;
                        }
                    }
                }
            });

            observer.observe({ type: 'layout-shift', buffered: true });

            // Report CLS on visibility change
            const reportCLS = () => {
                if (cls > 0) {
                    this.recordMetric('CLS', cls);
                }
            };

            document.addEventListener('visibilitychange', () => {
                if (document.visibilityState === 'hidden') {
                    reportCLS();
                }
            });
        } catch (e) {
            // CLS not supported
        }
    }

    /**
     * Observe Time to First Byte
     */
    private observeTTFB(): void {
        try {
            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries();
                entries.forEach((entry) => {
                    const navEntry = entry as PerformanceNavigationTiming;
                    const ttfb = navEntry.responseStart - navEntry.requestStart;
                    if (ttfb > 0) {
                        this.recordMetric('TTFB', ttfb);
                    }
                });
            });
            observer.observe({ type: 'navigation', buffered: true });
        } catch (e) {
            // TTFB not supported
        }
    }

    /**
     * Observe Interaction to Next Paint
     */
    private observeINP(): void {
        try {
            let inp = 0;
            const observer = new PerformanceObserver((list) => {
                const entries = list.getEntries() as PerformanceEventTiming[];
                entries.forEach((entry) => {
                    const duration = entry.processingEnd - entry.startTime;
                    if (duration > inp) {
                        inp = duration;
                    }
                });
            });
            observer.observe({ type: 'event', buffered: true });

            // Report INP on visibility change
            const reportINP = () => {
                if (inp > 0) {
                    this.recordMetric('INP', inp);
                }
            };

            document.addEventListener('visibilitychange', () => {
                if (document.visibilityState === 'hidden') {
                    reportINP();
                }
            });
        } catch (e) {
            // INP not supported
        }
    }

    /**
     * Log navigation timing metrics
     */
    private logNavigationTiming(): void {
        try {
            const navigation = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;
            if (navigation) {
                const timing = {
                    dns: navigation.domainLookupEnd - navigation.domainLookupStart,
                    connection: navigation.connectEnd - navigation.connectStart,
                    ttfb: navigation.responseStart - navigation.requestStart,
                    download: navigation.responseEnd - navigation.responseStart,
                    domParsing: navigation.domInteractive - navigation.responseEnd,
                    domContentLoaded: navigation.domContentLoadedEventEnd - navigation.domContentLoadedEventStart,
                    load: navigation.loadEventEnd - navigation.loadEventStart,
                    total: navigation.loadEventEnd - navigation.startTime,
                };

                logger.info('Navigation timing', 'PerformanceMonitor', timing);

                if (process.env.NODE_ENV === 'development') {
                    console.log('≡ƒôè Navigation Timing:', timing);
                }
            }
        } catch (e) {
            // Navigation timing not available
        }
    }

    /**
     * Subscribe to metric updates
     */
    subscribe(callback: (metrics: Map<string, PerformanceMetric>) => void): () => void {
        this.observers.add(callback);
        // Immediately call with current metrics
        callback(this.metrics);

        return () => {
            this.observers.delete(callback);
        };
    }

    /**
     * Notify all observers
     */
    private notifyObservers(): void {
        this.observers.forEach((callback) => callback(this.metrics));
    }

    /**
     * Get all metrics
     */
    getMetrics(): Map<string, PerformanceMetric> {
        return new Map(this.metrics);
    }

    /**
     * Get a specific metric
     */
    getMetric(name: string): PerformanceMetric | undefined {
        return this.metrics.get(name);
    }

    /**
     * Generate performance report
     */
    generateReport(): string {
        const metrics = Array.from(this.metrics.values());

        let report = `
PERFORMANCE REPORT
Generated: ${new Date().toISOString()}
URL: ${typeof window !== 'undefined' ? window.location.href : 'N/A'}

CORE WEB VITALS
---------------
`;

        const vitalOrder = ['FCP', 'LCP', 'FID', 'CLS', 'TTFB', 'INP'];

        vitalOrder.forEach((name) => {
            const metric = this.metrics.get(name);
            if (metric) {
                const statusEmoji = metric.rating === 'good' ? 'Γ£à' : metric.rating === 'needs-improvement' ? 'ΓÜá∩╕Å' : 'Γ¥î';
                const unit = name === 'CLS' ? '' : 'ms';
                report += `${statusEmoji} ${name}: ${metric.value.toFixed(2)}${unit} (${metric.rating})\n`;
            } else {
                report += `ΓÅ│ ${name}: Not measured yet\n`;
            }
        });

        // Summary
        const poorMetrics = metrics.filter(m => m.rating === 'poor');
        const needsImprovement = metrics.filter(m => m.rating === 'needs-improvement');

        report += `
SUMMARY
-------
Good: ${metrics.filter(m => m.rating === 'good').length}
Needs Improvement: ${needsImprovement.length}
Poor: ${poorMetrics.length}

`;

        if (poorMetrics.length > 0) {
            report += `ΓÜá∩╕Å ATTENTION: ${poorMetrics.length} metric(s) need immediate attention!\n`;
        }

        return report;
    }
}

// Singleton export
export const performanceMonitor = PerformanceMonitoringService.getInstance();

// React hook for using performance metrics
export function usePerformanceMetrics() {
    const [metrics, setMetrics] = React.useState<Map<string, PerformanceMetric>>(new Map());

    React.useEffect(() => {
        const unsubscribe = performanceMonitor.subscribe(setMetrics);
        return unsubscribe;
    }, []);

    return {
        metrics,
        getMetric: (name: string) => metrics.get(name),
        generateReport: () => performanceMonitor.generateReport(),
    };
}

