/**
 * Global search across all entities
 */
export const globalSearch = async (
    userId: string,
    query: string,
    options: SearchOptions = {}
): Promise<SearchResult[]> => {
    if (!query || query.trim().length < 2) return [];

    const defaultOptions: SearchOptions = {
        entityType: 'all',
        limit: 20,
        fuzzy: true,
        includeMetadata: true,
        ...options,
    };

    const { entityType, limit } = defaultOptions;

    let results: SearchResult[] = [];

    if (entityType === 'all' || entityType === 'students') {
        const studentResults = await searchStudents(userId, query, defaultOptions);
        results = [...results, ...studentResults];
    }

    if (entityType === 'all' || entityType === 'classes') {
        const classResults = await searchClasses(userId, query, defaultOptions);
        results = [...results, ...classResults];
    }

    if (entityType === 'all' || entityType === 'tasks') {
        const taskResults = await searchTasks(userId, query, defaultOptions);
        results = [...results, ...taskResults];
    }

    if (entityType === 'all' || entityType === 'schedules') {
        const scheduleResults = await searchSchedules(userId, query, defaultOptions);
        results = [...results, ...scheduleResults];
    }

    // Sort by relevance and limit
    return results
        .sort((a, b) => b.relevance - a.relevance)
        .slice(0, limit);
};

/**
 * Get search suggestions based on history and popular searches
 */
export const getSearchSuggestions = async (
    userId: string,
    partialQuery: string
): Promise<string[]> => {
    if (!partialQuery || partialQuery.length < 1) return [];

    const suggestions: string[] = [];

    // Get matching student names
    const { data: students } = await supabase
        .from('students')
        .select('name')
        .eq('user_id', userId)
        .ilike('name', `%${partialQuery}%`)
        .limit(5);

    students?.forEach(s => suggestions.push(s.name));

    // Get matching class names
    const { data: classes } = await supabase
        .from('classes')
        .select('name')
        .eq('user_id', userId)
        .ilike('name', `%${partialQuery}%`)
        .limit(3);

    classes?.forEach(c => suggestions.push(c.name));

    // Get matching subjects
    const { data: schedules } = await supabase
        .from('schedules')
        .select('subject')
        .eq('user_id', userId)
        .ilike('subject', `%${partialQuery}%`)
        .limit(3);

    schedules?.forEach(s => suggestions.push(s.subject));

    // Remove duplicates and limit
    return [...new Set(suggestions)].slice(0, 8);
};

/**
 * Search result grouping by type
 */
export const groupResultsByType = (results: SearchResult[]): Record<SearchEntityType, SearchResult[]> => {
    const grouped: Record<SearchEntityType, SearchResult[]> = {
        all: [],
        students: [],
        classes: [],
        tasks: [],
        schedules: [],
        attendance: [],
    };

    results.forEach(result => {
        if (grouped[result.type]) {
            grouped[result.type].push(result);
        }
    });

    return grouped;
};

export default {
    globalSearch,
    getSearchSuggestions,
    groupResultsByType,
    calculateRelevance,
};

/**
 * Soft Delete Service
 * 
 * Provides soft delete functionality for all entities.
 * Records can be restored within 30 days before permanent deletion.
 */

import { supabase } from './supabase';

export type SoftDeleteEntity = 'students' | 'classes' | 'attendance' | 'violations' | 'quiz_points' | 'academic_records';

export interface SoftDeleteResult {
    success: boolean;
    deletedAt?: string;
    error?: string;
}

export interface RestoreResult {
    success: boolean;
    error?: string;
}

export interface DeletedItem {
    id: string;
    entity: SoftDeleteEntity;
    deletedAt: string;
    daysRemaining: number;
    data: Record<string, any>;
}

/**
 * Soft delete a record by setting deleted_at timestamp
 */
export async function softDelete(
    entity: SoftDeleteEntity,
    id: string
): Promise<SoftDeleteResult> {
    try {
        const deletedAt = new Date().toISOString();

        const { error } = await supabase
            .from(entity)
            .update({ deleted_at: deletedAt })
            .eq('id', id);

        if (error) throw error;

        return { success: true, deletedAt };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to soft delete'
        };
    }
}

/**
 * Soft delete multiple records as a single operation
 */
export async function softDeleteBulk(
    entity: SoftDeleteEntity,
    ids: string[]
): Promise<SoftDeleteResult> {
    try {
        const deletedAt = new Date().toISOString();

        const { error } = await supabase
            .from(entity)
            .update({ deleted_at: deletedAt })
            .in('id', ids);

        if (error) throw error;

        return { success: true, deletedAt };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to bulk soft delete'
        };
    }
}

/**
 * Restore a soft-deleted record by clearing deleted_at
 */
export async function restore(
    entity: SoftDeleteEntity,
    id: string
): Promise<RestoreResult> {
    try {
        const { error } = await supabase
            .from(entity)
            .update({ deleted_at: null })
            .eq('id', id);

        if (error) throw error;

        return { success: true };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to restore'
        };
    }
}

/**
 * Restore multiple soft-deleted records
 */
export async function restoreBulk(
    entity: SoftDeleteEntity,
    ids: string[]
): Promise<RestoreResult> {
    try {
        const { error } = await supabase
            .from(entity)
            .update({ deleted_at: null })
            .in('id', ids);

        if (error) throw error;

        return { success: true };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to bulk restore'
        };
    }
}

/**
 * Permanently delete a record (removes from database)
 */
export async function permanentDelete(
    entity: SoftDeleteEntity,
    id: string
): Promise<{ success: boolean; error?: string }> {
    try {
        const { error } = await supabase
            .from(entity)
            .delete()
            .eq('id', id);

        if (error) throw error;

        return { success: true };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Failed to permanently delete'
        };
    }
}

/**
 * Get all soft-deleted items for trash view
 */
export async function getDeletedItems(
    entity: SoftDeleteEntity,
    userId: string
): Promise<DeletedItem[]> {
    try {
        const { data, error } = await supabase
            .from(entity)
            .select('*')
            .eq('user_id', userId)
            .not('deleted_at', 'is', null)
            .order('deleted_at', { ascending: false });

        if (error) throw error;

        const now = new Date();
        const RETENTION_DAYS = 30;

        return (data || [])
            .filter(item => (item as any).deleted_at !== null)
            .map(item => {
                const deletedAt = new Date((item as any).deleted_at!);
                const daysSinceDelete = Math.floor((now.getTime() - deletedAt.getTime()) / (1000 * 60 * 60 * 24));
                const daysRemaining = Math.max(0, RETENTION_DAYS - daysSinceDelete);

                return {
                    id: item.id,
                    entity,
                    deletedAt: (item as any).deleted_at as string,
                    daysRemaining,
                    data: item,
                };
            });
    } catch (error) {
        console.error(`Failed to get deleted ${entity}:`, error);
        return [];
    }
}

/**
 * Get all deleted items across all entities
 */
export async function getAllDeletedItems(userId: string): Promise<DeletedItem[]> {
    const entities: SoftDeleteEntity[] = [
        'students',
        'classes',
        'attendance',
        'violations',
        'quiz_points',
        'academic_records',
    ];

    const results = await Promise.all(
        entities.map(entity => getDeletedItems(entity, userId))
    );

    return results
        .flat()
        .sort((a, b) => new Date(b.deletedAt).getTime() - new Date(a.deletedAt).getTime());
}

/**
 * Clean up expired soft-deleted records (older than 30 days)
 */
export async function cleanupExpired(): Promise<{
    success: boolean;
    deletedCounts: Record<SoftDeleteEntity, number>;
    error?: string;
}> {
    const entities: SoftDeleteEntity[] = [
        'students',
        'classes',
        'attendance',
        'violations',
        'quiz_points',
        'academic_records',
    ];
    const RETENTION_DAYS = 30;
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - RETENTION_DAYS);
    const cutoffISO = cutoffDate.toISOString();

    const deletedCounts: Record<SoftDeleteEntity, number> = {
        students: 0,
        classes: 0,
        attendance: 0,
        violations: 0,
        quiz_points: 0,
        academic_records: 0,
    };

    try {
        for (const entity of entities) {
            // First get items to delete (deleted_at < cutoff means they were deleted more than 30 days ago)
            // lt() filter on a date column automatically excludes null values
            const { data: itemsToDelete, error: selectError } = await supabase
                .from(entity)
                .select('id')
                .lt('deleted_at', cutoffISO);

            if (selectError) {
                console.error(`Failed to query ${entity}:`, selectError);
                continue;
            }

            if (!itemsToDelete || itemsToDelete.length === 0) {
                continue;
            }

            // Delete them by ID
            const ids = itemsToDelete.map(item => item.id);
            const { error: deleteError } = await supabase
                .from(entity)
                .delete()
                .in('id', ids);

            if (deleteError) {
                console.error(`Failed to delete ${entity}:`, deleteError);
                continue;
            }

            deletedCounts[entity] = ids.length;
        }

        return { success: true, deletedCounts };
    } catch (error) {
        return {
            success: false,
            deletedCounts,
            error: error instanceof Error ? error.message : 'Failed to cleanup expired records'
        };
    }
}

export default {
    softDelete,
    softDeleteBulk,
    restore,
    restoreBulk,
    permanentDelete,
    getDeletedItems,
    getAllDeletedItems,
    cleanupExpired,
};

/**
 * Undo Manager
 * 
 * Manages action history and provides undo functionality.
 * Actions expire after a configurable timeout (default 10 seconds for toast).
 */

import { supabase } from './supabase';
import { restore, restoreBulk, SoftDeleteEntity } from './SoftDeleteService';

export type ActionType = 'create' | 'update' | 'delete' | 'bulk_delete';
export type StateRecord = Record<string, unknown>;

export interface UndoableAction {
    id: string;
    userId: string;
    actionType: ActionType;
    entity: SoftDeleteEntity;
    entityIds: string[];
    previousState?: StateRecord[];
    createdAt: Date;
    expiresAt: Date;
    undone: boolean;
    description: string;
}

export interface ActionHistoryItem {
    id: string;
    actionType: ActionType;
    entity: SoftDeleteEntity;
    entityIds: string[];
    description: string;
    createdAt: Date;
    canUndo: boolean;
    previousState?: StateRecord[];
}

// In-memory action store (for quick access to recent undoable actions)
const recentActions: Map<string, UndoableAction> = new Map();

// Default timeout for undo actions (10 seconds)
const DEFAULT_UNDO_TIMEOUT_MS = 10000;

// Maximum actions to keep in history
const MAX_HISTORY_ITEMS = 50;

/**
 * Generate unique action ID
 */
function generateActionId(): string {
    return `action_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

/**
 * Record an undoable action
 */
export async function recordAction(
    userId: string,
    actionType: ActionType,
    entity: SoftDeleteEntity,
    entityIds: string[],
    previousState?: StateRecord[],
    description?: string,
    timeoutMs: number = DEFAULT_UNDO_TIMEOUT_MS
): Promise<UndoableAction> {
    const now = new Date();
    const expiresAt = new Date(now.getTime() + timeoutMs);

    const action: UndoableAction = {
        id: generateActionId(),
        userId,
        actionType,
        entity,
        entityIds,
        previousState,
        createdAt: now,
        expiresAt,
        undone: false,
        description: description || generateDescription(actionType, entity, entityIds.length),
    };

    // Store in memory for quick access
    recentActions.set(action.id, action);

    // Store in database for persistence (using correct column names from schema)
    try {
        await supabase.from('action_history').insert({
            id: action.id,
            user_id: userId,
            action_type: actionType,
            entity_type: entity,
            affected_ids: entityIds,
            previous_state: (previousState as any) || null,
            expires_at: expiresAt.toISOString(),
            can_undo: true,
        });
    } catch (error) {
        console.error('Failed to persist action to database:', error);
        // Continue even if database insert fails - we still have in-memory record
    }

    // Schedule cleanup after expiration
    setTimeout(() => {
        if (recentActions.has(action.id)) {
            const stored = recentActions.get(action.id);
            if (stored && !stored.undone) {
                recentActions.delete(action.id);
            }
        }
    }, timeoutMs + 1000);

    // Cleanup old actions if exceeding limit
    cleanupOldActions();

    return action;
}

/**
 * Generate human-readable description for action
 */
function generateDescription(actionType: ActionType, entity: SoftDeleteEntity, count: number): string {
    const entityNames: Record<SoftDeleteEntity, { singular: string; plural: string }> = {
        students: { singular: 'siswa', plural: 'siswa' },
        classes: { singular: 'kelas', plural: 'kelas' },
        attendance: { singular: 'absensi', plural: 'absensi' },
        violations: { singular: 'pelanggaran', plural: 'pelanggaran' },
        quiz_points: { singular: 'poin keaktifan', plural: 'poin keaktifan' },
        academic_records: { singular: 'nilai', plural: 'nilai' },
    };

    const entityName = entityNames[entity]
        ? (count > 1 ? entityNames[entity].plural : entityNames[entity].singular)
        : String(entity);

    switch (actionType) {
        case 'delete':
            return `Menghapus ${count} ${entityName}`;
        case 'bulk_delete':
            return `Menghapus ${count} ${entityName}`;
        case 'update':
            return `Memperbarui ${count} ${entityName}`;
        case 'create':
            return `Membuat ${count} ${entityName}`;
        default:
            return `${actionType} ${count} ${entityName}`;
    }
}

/**
 * Undo an action by its ID
 */
export async function undo(actionId: string): Promise<{ success: boolean; error?: string }> {
    // Try to get from memory first
    let action = recentActions.get(actionId);

    // If not in memory, try database
    if (!action) {
        try {
            const { data, error } = await supabase
                .from('action_history')
                .select('*')
                .eq('id', actionId)
                .single();

            if (error || !data) {
                return { success: false, error: error?.message || 'Aksi tidak ditemukan' };
            }

            // Map database columns to our interface
            action = {
                id: data.id,
                userId: data.user_id,
                actionType: data.action_type as ActionType,
                entity: data.entity_type as SoftDeleteEntity,
                entityIds: data.affected_ids || [],
                previousState: (data.previous_state as StateRecord[]) || undefined,
                createdAt: new Date(data.created_at || 0),
                expiresAt: new Date(data.expires_at ?? 0),
                undone: !(data.can_undo ?? true), // can_undo is the inverse of undone
                description: generateDescription(
                    data.action_type as ActionType,
                    data.entity_type as SoftDeleteEntity,
                    (data.affected_ids || []).length
                ),
            };
        } catch (err) {
            return {
                success: false,
                error: err instanceof Error ? err.message : 'Gagal mengambil data aksi'
            };
        }
    }

    // Check if already undone
    if (action.undone) {
        return { success: false, error: 'Aksi sudah di-undo' };
    }

    // Check if expired
    if (new Date() > action.expiresAt) {
        return { success: false, error: 'Waktu undo telah habis' };
    }

    // Perform the undo based on action type
    try {
        switch (action.actionType) {
            case 'delete':
            case 'bulk_delete':
                // Restore soft-deleted items
                if (action.entityIds.length === 1) {
                    const result = await restore(action.entity, action.entityIds[0]);
                    if (!result.success) {
                        return { success: false, error: result.error };
                    }
                } else {
                    const result = await restoreBulk(action.entity, action.entityIds);
                    if (!result.success) {
                        return { success: false, error: result.error };
                    }
                }
                break;

            case 'update':
                // Restore previous state
                if (action.previousState && action.previousState.length > 0) {
                    for (let i = 0; i < action.entityIds.length; i++) {
                        const id = action.entityIds[i];
                        const prevState = action.previousState[i];
                        if (prevState) {
                            await supabase
                                .from(action.entity)
                                .update(prevState)
                                .eq('id', id);
                        }
                    }
                }
                break;

            case 'create':
                // Delete created items (soft delete)
                for (const id of action.entityIds) {
                    await supabase
                        .from(action.entity)
                        .update({ deleted_at: new Date().toISOString() })
                        .eq('id', id);
                }
                break;
        }

        // Mark action as undone
        action.undone = true;
        recentActions.set(actionId, action);

        // Update database (can_undo = false means undone)
        await supabase
            .from('action_history')
            .update({ can_undo: false })
            .eq('id', actionId);

        return { success: true };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Gagal membatalkan aksi'
        };
    }
}

/**
 * Get action history for a user
 */
export interface ActionHistoryFilters {
    type?: ActionType | 'all';
    entity?: SoftDeleteEntity | 'all';
    startDate?: string;
    endDate?: string;
    search?: string;
}

/**
 * Get action history for a user with filters
 */
export async function getActionHistory(
    userId: string,
    limit: number = 20,
    offset: number = 0,
    filters: ActionHistoryFilters = {}
): Promise<{ items: ActionHistoryItem[]; total: number }> {
    try {
        let query = supabase
            .from('action_history')
            .select('*', { count: 'exact' })
            .eq('user_id', userId)
            .order('created_at', { ascending: false })
            .range(offset, offset + limit - 1);

        // Apply filters
        if (filters.type && filters.type !== 'all') {
            query = query.eq('action_type', filters.type);
        }

        if (filters.entity && filters.entity !== 'all') {
            query = query.eq('entity_type', filters.entity);
        }

        if (filters.startDate) {
            query = query.gte('created_at', filters.startDate);
        }

        if (filters.endDate) {
            // Add 1 day to include the end date fully
            const nextDay = new Date(filters.endDate);
            nextDay.setDate(nextDay.getDate() + 1);
            query = query.lt('created_at', nextDay.toISOString());
        }

        if (filters.search) {
            query = query.ilike('description', `%${filters.search}%`);
        }

        const { data, error, count } = await query;

        if (error) throw error;

        const now = new Date();

        const items = (data || []).map(item => ({
            id: item.id,
            actionType: item.action_type as ActionType,
            entity: item.entity_type as SoftDeleteEntity,
            entityIds: item.affected_ids || [],
            description: generateDescription(
                item.action_type as ActionType,
                item.entity_type as SoftDeleteEntity,
                (item.affected_ids || []).length
            ),
            createdAt: new Date(item.created_at || 0),
            canUndo: (item.can_undo || false) && new Date(item.expires_at ?? 0) > now,
            previousState: (item.previous_state as StateRecord[]) || undefined,
        }));

        return { items, total: count || 0 };
    } catch (error) {
        console.error('Failed to get action history:', error);
        return { items: [], total: 0 };
    }
}

/**
 * Check if an action can still be undone
 */
export function canUndo(actionId: string): boolean {
    const action = recentActions.get(actionId);
    if (!action) return false;
    return !action.undone && new Date() <= action.expiresAt;
}

/**
 * Get remaining time to undo an action (in milliseconds)
 */
export function getUndoTimeRemaining(actionId: string): number {
    const action = recentActions.get(actionId);
    if (!action || action.undone) return 0;

    const remaining = action.expiresAt.getTime() - Date.now();
    return Math.max(0, remaining);
}

/**
 * Clear old actions from memory
 */
export function cleanupOldActions(): void {
    const now = Date.now();
    const expiredThreshold = now - (60 * 60 * 1000); // 1 hour ago

    for (const [id, action] of recentActions) {
        if (action.createdAt.getTime() < expiredThreshold) {
            recentActions.delete(id);
        }
    }

    // Also enforce max history limit
    if (recentActions.size > MAX_HISTORY_ITEMS) {
        const sortedActions = Array.from(recentActions.entries())
            .sort((a, b) => b[1].createdAt.getTime() - a[1].createdAt.getTime());

        const toDelete = sortedActions.slice(MAX_HISTORY_ITEMS);
        toDelete.forEach(([id]) => recentActions.delete(id));
    }
}

/**
 * Clear all action history for a user
 */
export async function clearHistory(userId: string): Promise<{ success: boolean; error?: string }> {
    try {
        const { error } = await supabase
            .from('action_history')
            .delete()
            .eq('user_id', userId);

        if (error) throw error;

        // Clear from memory too
        for (const [id, action] of recentActions) {
            if (action.userId === userId) {
                recentActions.delete(id);
            }
        }

        return { success: true };
    } catch (error) {
        return {
            success: false,
            error: error instanceof Error ? error.message : 'Gagal menghapus history'
        };
    }
}

/**
 * Clean up expired actions from database
 */
export async function cleanupExpiredActions(): Promise<{ success: boolean; deleted: number; error?: string }> {
    try {
        const cutoffDate = new Date();
        cutoffDate.setDate(cutoffDate.getDate() - 7); // Keep for 7 days

        // First get count
        const { count } = await supabase
            .from('action_history')
            .select('*', { count: 'exact', head: true })
            .lt('expires_at', cutoffDate.toISOString());

        // Then delete
        const { error } = await supabase
            .from('action_history')
            .delete()
            .lt('expires_at', cutoffDate.toISOString());

        if (error) throw error;

        return { success: true, deleted: count || 0 };
    } catch (error) {
        return {
            success: false,
            deleted: 0,
            error: error instanceof Error ? error.message : 'Gagal cleanup expired actions'
        };
    }
}

export default {
    recordAction,
    undo,
    getActionHistory,
    canUndo,
    getUndoTimeRemaining,
    clearHistory,
    cleanupExpiredActions,
};

import { ValidationRule, ValidationRules } from '../types';
import { logger } from './logger';

export interface ValidationResult {
    isValid: boolean;
    error?: string;
}

export interface FormValidationResult {
    isValid: boolean;
    errors: Record<string, string>;
}

export class ValidationService {
    /**
     * Validate a single value against a list of rules
     */
    static validateField(value: any, rules: ValidationRule[]): ValidationResult {
        for (const rule of rules) {
            try {
                if (!rule.validate(value)) {
                    return { isValid: false, error: rule.message };
                }
            } catch (error) {
                logger.error('Error during field validation', error as Error, { value, ruleMessage: rule.message }, 'ValidationService');
                return { isValid: false, error: 'Validation error occurred' };
            }
        }
        return { isValid: true };
    }

    /**
     * Validate an entire form object against a schema of rules
     */
    static validateForm(values: Record<string, any>, rules: ValidationRules): FormValidationResult {
        const errors: Record<string, string> = {};
        let isValid = true;

        for (const field in rules) {
            if (Object.prototype.hasOwnProperty.call(rules, field)) {
                const result = this.validateField(values[field], rules[field]);
                if (!result.isValid && result.error) {
                    errors[field] = result.error;
                    isValid = false;
                }
            }
        }

        return { isValid, errors };
    }

    /**
     * Pre-built validators
     */
    static validators = {
        required: (message = 'Wajib diisi'): ValidationRule => ({
            validate: (value: any) => {
                if (value === null || value === undefined) return false;
                if (typeof value === 'string') return value.trim().length > 0;
                if (Array.isArray(value)) return value.length > 0;
                return true;
            },
            message
        }),

        minLength: (length: number, message?: string): ValidationRule => ({
            validate: (value: any) => {
                if (!value) return true; // Skip if empty (use required for non-empty check)
                return String(value).length >= length;
            },
            message: message || `Minimal ${length} karakter`
        }),

        maxLength: (length: number, message?: string): ValidationRule => ({
            validate: (value: any) => {
                if (!value) return true;
                return String(value).length <= length;
            },
            message: message || `Maksimal ${length} karakter`
        }),

        email: (message = 'Format email tidak valid'): ValidationRule => ({
            validate: (value: string) => {
                if (!value) return true;
                const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
                return emailRegex.test(value);
            },
            message
        }),

        phoneNumber: (message = 'Nomor telepon tidak valid'): ValidationRule => ({
            validate: (value: string) => {
                if (!value) return true;
                // Basic phone validation: 10-15 digits, optional + prefix
                const phoneRegex = /^\+?[\d\s-]{10,15}$/;
                return phoneRegex.test(value.replace(/\s|-/g, ''));
            },
            message
        }),

        number: (message = 'Harus berupa angka'): ValidationRule => ({
            validate: (value: any) => {
                if (value === null || value === undefined || value === '') return true;
                return !isNaN(Number(value));
            },
            message
        }),

        alphanumeric: (message = 'Hanya huruf dan angka'): ValidationRule => ({
            validate: (value: string) => {
                if (!value) return true;
                return /^[a-zA-Z0-9]*$/.test(value);
            },
            message
        }),

        url: (message = 'URL tidak valid'): ValidationRule => ({
            validate: (value: string) => {
                if (!value) return true;
                try {
                    new URL(value);
                    return true;
                } catch {
                    return false;
                }
            },
            message
        }),

        futureDate: (message = 'Harus tanggal di masa depan'): ValidationRule => ({
            validate: (value: string | Date) => {
                if (!value) return true;
                const date = new Date(value);
                return date > new Date();
            },
            message
        })
    };
}

