function applyUserId<T extends Record<string, any>>(records: T[], userId: string): T[] {
    return records.map(record => {
        if (!record || typeof record !== 'object') return record;
        if (Object.prototype.hasOwnProperty.call(record, 'user_id')) {
            return { ...record, user_id: userId };
        }
        return record;
    });
}

const entityValidators: Record<EntityType, (record: Record<string, unknown>) => Record<string, unknown>> = {
    students: (record) => {
        if (!record.name || typeof record.name !== 'string') {
            throw new Error('Invalid name');
        }
        if (record.gender && typeof record.gender === 'string' && !['Laki-laki', 'Perempuan'].includes(record.gender)) {
            throw new Error('Invalid gender');
        }
        return {
            id: record.id,
            name: (record.name as string).trim(),
            class: typeof record.class === 'string' ? record.class.trim() : null,
            gender: record.gender || null,
            access_code: record.access_code || null,
            parent_contact: record.parent_contact || null,
            email: record.email || null,
            birthdate: record.birthdate || null,
            student_id: record.student_id || null
        };
    },
    attendance: (record) => {
        if (!record.student_id) throw new Error('Missing student_id');
        if (!record.date) throw new Error('Missing date');
        // Use correct enum values: Hadir, Sakit, Izin, Alpha (with capital first letter)
        if (!['Hadir', 'Sakit', 'Izin', 'Alpha'].includes(String(record.status))) {
            throw new Error('Invalid status. Must be one of: Hadir, Sakit, Izin, Alpha');
        }
        return {
            id: record.id,
            student_id: record.student_id,
            date: record.date,
            status: record.status,
            notes: record.notes || null
        };
    },
    tasks: (record) => {
        if (!record.title) throw new Error('Missing title');
        return {
            id: record.id,
            title: typeof record.title === 'string' ? record.title.trim() : String(record.title),
            description: record.description || null,
            due_date: record.due_date || null,
            priority: record.priority || 'medium',
            status: record.status || 'pending',
            category: record.category || null
        };
    },
    schedules: (record) => {
        if (!record.day) throw new Error('Missing day');
        if (!record.subject) throw new Error('Missing subject');
        return {
            id: record.id,
            day: record.day,
            subject: typeof record.subject === 'string' ? record.subject.trim() : String(record.subject),
            start_time: record.start_time || null,
            end_time: record.end_time || null,
            room: record.room || null,
            teacher: record.teacher || null
        };
    },
    academic_records: (record) => {
        if (!record.student_id) throw new Error('Missing student_id');
        if (!record.subject) throw new Error('Missing subject');
        return {
            id: record.id,
            student_id: record.student_id,
            subject: typeof record.subject === 'string' ? record.subject.trim() : String(record.subject),
            score: Number(record.score) || 0,
            assessment_name: record.assessment_name || null,
            notes: record.notes || null
        };
    }
};

function validateAndTransformRecord(entity: EntityType, record: Record<string, unknown>): Record<string, unknown> {
    const validator = entityValidators[entity];
    if (!validator) {
        throw new Error(`Unknown entity: ${entity}`);
    }
    return validator(record);
}

// ============================================
// CSV UTILITIES
// ============================================

function convertToCSV(data: any[]): string {
    if (data.length === 0) return '';

    const headers = Object.keys(data[0]);
    const rows = data.map(row =>
        headers.map(header => {
            const value = row[header];
            if (value === null || value === undefined) return '';
            const str = String(value);
            // Escape quotes and wrap in quotes if contains comma or quote
            if (str.includes(',') || str.includes('"') || str.includes('\n')) {
                return `"${str.replace(/"/g, '""')}"`;
            }
            return str;
        }).join(',')
    );

    return [headers.join(','), ...rows].join('\n');
}

function parseCSV(content: string): any[] {
    const lines = content.trim().split('\n');
    if (lines.length < 2) return [];

    const headers = parseCSVLine(lines[0]);

    return lines.slice(1).map(line => {
        const values = parseCSVLine(line);
        const record: any = {};
        headers.forEach((header, index) => {
            record[header] = values[index] || null;
        });
        return record;
    });
}

function parseCSVLine(line: string): string[] {
    const result: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
        const char = line[i];

        if (char === '"') {
            if (inQuotes && line[i + 1] === '"') {
                current += '"';
                i++;
            } else {
                inQuotes = !inQuotes;
            }
        } else if (char === ',' && !inQuotes) {
            result.push(current.trim());
            current = '';
        } else {
            current += char;
        }
    }

    result.push(current.trim());
    return result;
}

