export const enhancedSecurity = {
    // CSRF
    generateCSRFToken,
    validateCSRFToken,
    getCSRFToken,
    csrfFetch,

    // XSS
    escapeHtml,
    sanitizeContent,
    sanitizeText,
    sanitizeUrl,

    // File validation
    validateFile,
    validateImageFile,
    sanitizeFilename,

    // Cryptographic
    generateSecureAccessCode,
    generateSecurePassword,
    generateSecureToken,
    hashString,

    // Audit
    auditLog,
    getAuditLog,
    clearAuditLog,
    exportAuditLog,

    // Form
    sanitizeFormData,

    // CSP
    getCSPNonce,
    isAllowedScriptSrc
};

