// ============================================
// SCROLL LOCK UTILITY
// ============================================

let scrollLockCount = 0;
let originalBodyOverflow = '';
let originalBodyPaddingRight = '';

export const lockScroll = () => {
    if (scrollLockCount === 0) {
        originalBodyOverflow = document.body.style.overflow;
        originalBodyPaddingRight = document.body.style.paddingRight;

        const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
        document.body.style.overflow = 'hidden';
        document.body.style.paddingRight = `${scrollbarWidth}px`;
    }
    scrollLockCount++;
};

export const unlockScroll = () => {
    scrollLockCount--;
    if (scrollLockCount <= 0) {
        scrollLockCount = 0;
        document.body.style.overflow = originalBodyOverflow;
        document.body.style.paddingRight = originalBodyPaddingRight;
    }
};

// ============================================
// SAFE AREA INSETS HOOK
// ============================================

interface SafeAreaInsets {
    top: number;
    right: number;
    bottom: number;
    left: number;
}

export function useSafeAreaInsets(): SafeAreaInsets {
    const [insets, setInsets] = useState<SafeAreaInsets>({
        top: 0,
        right: 0,
        bottom: 0,
        left: 0,
    });

    useEffect(() => {
        const updateInsets = () => {
            const computedStyle = getComputedStyle(document.documentElement);
            setInsets({
                top: parseInt(computedStyle.getPropertyValue('--sat') || '0', 10) ||
                    parseInt(computedStyle.getPropertyValue('env(safe-area-inset-top)') || '0', 10),
                right: parseInt(computedStyle.getPropertyValue('--sar') || '0', 10) ||
                    parseInt(computedStyle.getPropertyValue('env(safe-area-inset-right)') || '0', 10),
                bottom: parseInt(computedStyle.getPropertyValue('--sab') || '0', 10) ||
                    parseInt(computedStyle.getPropertyValue('env(safe-area-inset-bottom)') || '0', 10),
                left: parseInt(computedStyle.getPropertyValue('--sal') || '0', 10) ||
                    parseInt(computedStyle.getPropertyValue('env(safe-area-inset-left)') || '0', 10),
            });
        };

        updateInsets();
        window.addEventListener('resize', updateInsets);
        return () => window.removeEventListener('resize', updateInsets);
    }, []);

    return insets;
}

export default {
    useKeyboardAwareness,
    KeyboardAwareContainer,
    TouchTarget,
    LoadingProvider,
    useLoading,
    InlineLoading,
    LoadingButton,
    lockScroll,
    unlockScroll,
    useSafeAreaInsets,
};

/**
 * Custom Notification Sound Generator for Portal Guru
 * 
 * Creates a unique, pleasant "ding-dong" sound using Web Audio API
 * This sound is distinctive and professional, perfect for education apps
 */

// Audio context singleton
let audioContext: AudioContext | null = null;

/**
 * Get or create the AudioContext
 */
const getAudioContext = (): AudioContext | null => {
    if (!audioContext) {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContextClass) {
            audioContext = new AudioContextClass();
        }
    }
    return audioContext;
};

/**
 * Play a pleasant two-tone notification sound (ding-dong style)
 * Perfect for Portal Guru's educational theme
 */
export const playNotificationSound = (): void => {
    try {
        const ctx = getAudioContext();
        if (!ctx) return;

        // Resume context if suspended
        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        const now = ctx.currentTime;

        // Create master gain for volume control
        const masterGain = ctx.createGain();
        masterGain.connect(ctx.destination);
        masterGain.gain.setValueAtTime(0.3, now);

        // === FIRST TONE (Higher pitch "Ding") ===
        const osc1 = ctx.createOscillator();
        const gain1 = ctx.createGain();

        osc1.connect(gain1);
        gain1.connect(masterGain);

        osc1.type = 'sine';
        osc1.frequency.setValueAtTime(880, now); // A5 note
        osc1.frequency.exponentialRampToValueAtTime(660, now + 0.15); // Slight pitch drop

        gain1.gain.setValueAtTime(0.4, now);
        gain1.gain.exponentialRampToValueAtTime(0.01, now + 0.4);

        osc1.start(now);
        osc1.stop(now + 0.4);

        // Add harmonics for richness
        const osc1Harmonic = ctx.createOscillator();
        const gain1Harmonic = ctx.createGain();

        osc1Harmonic.connect(gain1Harmonic);
        gain1Harmonic.connect(masterGain);

        osc1Harmonic.type = 'sine';
        osc1Harmonic.frequency.setValueAtTime(1760, now); // Octave higher

        gain1Harmonic.gain.setValueAtTime(0.1, now);
        gain1Harmonic.gain.exponentialRampToValueAtTime(0.001, now + 0.3);

        osc1Harmonic.start(now);
        osc1Harmonic.stop(now + 0.3);

        // === SECOND TONE (Lower pitch "Dong") ===
        const osc2 = ctx.createOscillator();
        const gain2 = ctx.createGain();

        osc2.connect(gain2);
        gain2.connect(masterGain);

        osc2.type = 'sine';
        osc2.frequency.setValueAtTime(660, now + 0.15); // E5 note
        osc2.frequency.exponentialRampToValueAtTime(440, now + 0.5); // Drop to A4

        gain2.gain.setValueAtTime(0, now);
        gain2.gain.setValueAtTime(0.3, now + 0.15);
        gain2.gain.exponentialRampToValueAtTime(0.01, now + 0.6);

        osc2.start(now + 0.15);
        osc2.stop(now + 0.6);

        // Add sub-bass for fullness
        const subBass = ctx.createOscillator();
        const subBassGain = ctx.createGain();

        subBass.connect(subBassGain);
        subBassGain.connect(masterGain);

        subBass.type = 'sine';
        subBass.frequency.setValueAtTime(220, now + 0.15); // A3

        subBassGain.gain.setValueAtTime(0, now);
        subBassGain.gain.setValueAtTime(0.15, now + 0.15);
        subBassGain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);

        subBass.start(now + 0.15);
        subBass.stop(now + 0.5);

    } catch (e) {
        console.warn('Could not play notification sound:', e);
    }
};

/**
 * Play a success notification sound (ascending chime)
 * Used for successful actions like saving, submitting, etc.
 */
export const playSuccessSound = (): void => {
    try {
        const ctx = getAudioContext();
        if (!ctx) return;

        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        const now = ctx.currentTime;

        const masterGain = ctx.createGain();
        masterGain.connect(ctx.destination);
        masterGain.gain.setValueAtTime(0.25, now);

        // Ascending three-note chime
        const notes = [523.25, 659.25, 783.99]; // C5, E5, G5 - major chord
        const delays = [0, 0.08, 0.16];

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.connect(gain);
            gain.connect(masterGain);

            osc.type = 'sine';
            osc.frequency.setValueAtTime(freq, now + delays[i]);

            gain.gain.setValueAtTime(0, now);
            gain.gain.setValueAtTime(0.4, now + delays[i]);
            gain.gain.exponentialRampToValueAtTime(0.01, now + delays[i] + 0.3);

            osc.start(now + delays[i]);
            osc.stop(now + delays[i] + 0.3);

            // Add shimmer harmonic
            const harmonic = ctx.createOscillator();
            const harmonicGain = ctx.createGain();

            harmonic.connect(harmonicGain);
            harmonicGain.connect(masterGain);

            harmonic.type = 'sine';
            harmonic.frequency.setValueAtTime(freq * 2, now + delays[i]);

            harmonicGain.gain.setValueAtTime(0, now);
            harmonicGain.gain.setValueAtTime(0.1, now + delays[i]);
            harmonicGain.gain.exponentialRampToValueAtTime(0.001, now + delays[i] + 0.2);

            harmonic.start(now + delays[i]);
            harmonic.stop(now + delays[i] + 0.2);
        });

    } catch (e) {
        console.warn('Could not play success sound:', e);
    }
};

/**
 * Play an error/warning notification sound (descending minor)
 * Used for errors, warnings, or failed actions
 */
export const playErrorSound = (): void => {
    try {
        const ctx = getAudioContext();
        if (!ctx) return;

        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        const now = ctx.currentTime;

        const masterGain = ctx.createGain();
        masterGain.connect(ctx.destination);
        masterGain.gain.setValueAtTime(0.2, now);

        // Two descending tones (minor feel)
        const osc1 = ctx.createOscillator();
        const gain1 = ctx.createGain();

        osc1.connect(gain1);
        gain1.connect(masterGain);

        osc1.type = 'triangle';
        osc1.frequency.setValueAtTime(392, now); // G4
        osc1.frequency.exponentialRampToValueAtTime(330, now + 0.15); // E4

        gain1.gain.setValueAtTime(0.5, now);
        gain1.gain.exponentialRampToValueAtTime(0.01, now + 0.2);

        osc1.start(now);
        osc1.stop(now + 0.2);

        // Second lower tone
        const osc2 = ctx.createOscillator();
        const gain2 = ctx.createGain();

        osc2.connect(gain2);
        gain2.connect(masterGain);

        osc2.type = 'triangle';
        osc2.frequency.setValueAtTime(330, now + 0.12); // E4
        osc2.frequency.exponentialRampToValueAtTime(262, now + 0.3); // C4

        gain2.gain.setValueAtTime(0, now);
        gain2.gain.setValueAtTime(0.4, now + 0.12);
        gain2.gain.exponentialRampToValueAtTime(0.01, now + 0.35);

        osc2.start(now + 0.12);
        osc2.stop(now + 0.35);

    } catch (e) {
        console.warn('Could not play error sound:', e);
    }
};

/**
 * Play a message received notification sound
 * Used when receiving new messages from parents
 */
export const playMessageSound = (): void => {
    try {
        const ctx = getAudioContext();
        if (!ctx) return;

        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        const now = ctx.currentTime;

        const masterGain = ctx.createGain();
        masterGain.connect(ctx.destination);
        masterGain.gain.setValueAtTime(0.25, now);

        // Soft two-tone "pop-pop"
        const notes = [587.33, 880]; // D5, A5
        const delays = [0, 0.08];

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.connect(gain);
            gain.connect(masterGain);

            osc.type = 'sine';
            osc.frequency.setValueAtTime(freq, now + delays[i]);

            gain.gain.setValueAtTime(0, now);
            gain.gain.setValueAtTime(0.35, now + delays[i]);
            gain.gain.exponentialRampToValueAtTime(0.01, now + delays[i] + 0.12);

            osc.start(now + delays[i]);
            osc.stop(now + delays[i] + 0.15);
        });

    } catch (e) {
        console.warn('Could not play message sound:', e);
    }
};

/**
 * Play a reminder notification sound
 * Used for class reminders, task due dates, etc.
 */
export const playReminderSound = (): void => {
    try {
        const ctx = getAudioContext();
        if (!ctx) return;

        if (ctx.state === 'suspended') {
            ctx.resume();
        }

        const now = ctx.currentTime;

        const masterGain = ctx.createGain();
        masterGain.connect(ctx.destination);
        masterGain.gain.setValueAtTime(0.3, now);

        // Gentle bell-like sound with decay
        const frequencies = [523.25, 659.25, 784]; // C5, E5, G5

        frequencies.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.connect(gain);
            gain.connect(masterGain);

            osc.type = 'sine';
            osc.frequency.setValueAtTime(freq, now);

            gain.gain.setValueAtTime(0.3 - (i * 0.05), now);
            gain.gain.exponentialRampToValueAtTime(0.001, now + 0.8);

            osc.start(now);
            osc.stop(now + 0.8);
        });

        // Add a soft "ping" on top
        const pingOsc = ctx.createOscillator();
        const pingGain = ctx.createGain();

        pingOsc.connect(pingGain);
        pingGain.connect(masterGain);

        pingOsc.type = 'sine';
        pingOsc.frequency.setValueAtTime(1568, now); // G6 - high ping

        pingGain.gain.setValueAtTime(0.15, now);
        pingGain.gain.exponentialRampToValueAtTime(0.001, now + 0.3);

        pingOsc.start(now);
        pingOsc.stop(now + 0.3);

    } catch (e) {
        console.warn('Could not play reminder sound:', e);
    }
};

export default {
    playNotificationSound,
    playSuccessSound,
    playErrorSound,
    playMessageSound,
    playReminderSound,
};

/**
 * Page Accessibility Wrapper
 * 
 * Provides accessibility enhancements for page components:
 * - Skip links
 * - Page title announcements
 * - Landmark roles
 * - Focus management
 */

import React, { useEffect, useRef, ReactNode, useState, useCallback } from 'react';

// ============================================
// VISUALLY HIDDEN (local implementation)
// ============================================

interface VisuallyHiddenProps {
    children: ReactNode;
}

const VisuallyHidden: React.FC<VisuallyHiddenProps> = ({ children }) => (
    <span className="sr-only">{children}</span>
);

// ============================================
// SIMPLE ANNOUNCE HOOK (local implementation)
// ============================================

function usePageAnnounce() {
    const [, setMessage] = useState('');

    const announce = useCallback((text: string, _priority: 'polite' | 'assertive' = 'polite') => {
        // Force re-render to trigger screen reader
        setMessage('');
        setTimeout(() => setMessage(text), 100);
    }, []);

    return announce;
}

// ============================================
// ACCESSIBLE PAGE WRAPPER
// ============================================

interface AccessiblePageProps {
    children: ReactNode;
    title: string;
    description?: string;
    className?: string;
}

/**
 * Wrapper for pages with accessibility enhancements
 */
export const AccessiblePage: React.FC<AccessiblePageProps> = ({
    children,
    title,
    description,
    className = '',
}) => {
    const mainRef = useRef<HTMLElement>(null);
    const announce = usePageAnnounce();

    // Announce page title when mounted
    useEffect(() => {
        announce(`${title}${description ? `. ${description}` : ''}`, 'polite');

        // Update document title
        document.title = `${title} | Portal Guru`;

        // Focus main content if coming from skip link
        const hash = window.location.hash;
        if (hash === '#main-content' && mainRef.current) {
            mainRef.current.focus();
        }
    }, [title, description, announce]);

    return (
        <main
            ref={mainRef}
            id="main-content"
            role="main"
            aria-label={title}
            tabIndex={-1}
            className={`outline-none ${className}`}
        >
            <VisuallyHidden>
                <h1>{title}</h1>
            </VisuallyHidden>
            {children}
        </main>
    );
};

// ============================================
// SKIP LINK
// ============================================

export const SkipToMainContent: React.FC = () => {
    return (
        <a
            href="#main-content"
            className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-[9999] focus:px-4 focus:py-2 focus:bg-indigo-600 focus:text-white focus:rounded-lg focus:shadow-lg"
        >
            Lewati ke konten utama
        </a>
    );
};

// ============================================
// SECTION WITH HEADING
// ============================================

interface AccessibleSectionProps {
    children: ReactNode;
    title: string;
    level?: 2 | 3 | 4 | 5 | 6;
    showTitle?: boolean;
    className?: string;
    titleClassName?: string;
    id?: string;
}

/**
 * Section with proper heading structure
 */
export const AccessibleSection: React.FC<AccessibleSectionProps> = ({
    children,
    title,
    level = 2,
    showTitle = true,
    className = '',
    titleClassName = '',
    id,
}) => {
    const HeadingTag = `h${level}` as keyof JSX.IntrinsicElements;
    const sectionId = id || title.toLowerCase().replace(/\s+/g, '-');

    return (
        <section
            aria-labelledby={`${sectionId}-heading`}
            className={className}
        >
            {showTitle ? (
                <HeadingTag
                    id={`${sectionId}-heading`}
                    className={titleClassName || 'text-lg font-semibold text-slate-900 dark:text-white mb-4'}
                >
                    {title}
                </HeadingTag>
            ) : (
                <VisuallyHidden>
                    <HeadingTag id={`${sectionId}-heading`}>{title}</HeadingTag>
                </VisuallyHidden>
            )}
            {children}
        </section>
    );
};

// ============================================
// ACCESSIBLE TABLE
// ============================================

interface AccessibleTableProps<T> {
    data: T[];
    columns: {
        key: string;
        header: string;
        render: (item: T, index: number) => ReactNode;
        sortable?: boolean;
    }[];
    caption: string;
    showCaption?: boolean;
    emptyMessage?: string;
    onRowClick?: (item: T, index: number) => void;
    selectedIndex?: number;
    className?: string;
    keyExtractor: (item: T, index: number) => string;
}

/**
 * Accessible table with proper ARIA attributes
 */
export function AccessibleTable<T>({
    data,
    columns,
    caption,
    showCaption = false,
    emptyMessage = 'Tidak ada data',
    onRowClick,
    selectedIndex,
    className = '',
    keyExtractor,
}: AccessibleTableProps<T>) {
    return (
        <div className={`overflow-x-auto ${className}`}>
            <table
                className="w-full border-collapse"
                role="grid"
                aria-label={caption}
            >
                {showCaption ? (
                    <caption className="text-left text-sm text-slate-500 mb-2">{caption}</caption>
                ) : (
                    <caption className="sr-only">{caption}</caption>
                )}

                <thead>
                    <tr role="row">
                        {columns.map((col) => (
                            <th
                                key={col.key}
                                scope="col"
                                role="columnheader"
                                className="px-4 py-3 text-left text-sm font-medium text-slate-600 dark:text-slate-400 bg-slate-50 dark:bg-slate-800/50"
                            >
                                {col.header}
                            </th>
                        ))}
                    </tr>
                </thead>

                <tbody>
                    {data.length === 0 ? (
                        <tr role="row">
                            <td
                                colSpan={columns.length}
                                className="px-4 py-8 text-center text-slate-500"
                            >
                                {emptyMessage}
                            </td>
                        </tr>
                    ) : (
                        data.map((item, index) => (
                            <tr
                                key={keyExtractor(item, index)}
                                role="row"
                                aria-selected={selectedIndex === index}
                                tabIndex={onRowClick ? 0 : undefined}
                                onClick={() => onRowClick?.(item, index)}
                                onKeyDown={(e) => {
                                    if (onRowClick && (e.key === 'Enter' || e.key === ' ')) {
                                        e.preventDefault();
                                        onRowClick(item, index);
                                    }
                                }}
                                className={`
                                    border-b border-slate-100 dark:border-slate-800
                                    ${onRowClick ? 'cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800/50' : ''}
                                    ${selectedIndex === index ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}
                                    focus:outline-none focus:bg-indigo-50 dark:focus:bg-indigo-900/20
                                `}
                            >
                                {columns.map((col) => (
                                    <td
                                        key={col.key}
                                        role="gridcell"
                                        className="px-4 py-3 text-sm text-slate-700 dark:text-slate-300"
                                    >
                                        {col.render(item, index)}
                                    </td>
                                ))}
                            </tr>
                        ))
                    )}
                </tbody>
            </table>
        </div>
    );
}

// ============================================
// ACCESSIBLE LIST
// ============================================

interface AccessibleListProps<T> {
    items: T[];
    renderItem: (item: T, index: number) => ReactNode;
    label: string;
    emptyMessage?: string;
    className?: string;
    itemClassName?: string;
    keyExtractor: (item: T, index: number) => string;
    onItemClick?: (item: T, index: number) => void;
}

/**
 * Accessible list with proper ARIA
 */
export function AccessibleList<T>({
    items,
    renderItem,
    label,
    emptyMessage = 'Tidak ada item',
    className = '',
    itemClassName = '',
    keyExtractor,
    onItemClick,
}: AccessibleListProps<T>) {
    if (items.length === 0) {
        return (
            <div className="text-center py-8 text-slate-500" role="status">
                {emptyMessage}
            </div>
        );
    }

    return (
        <ul
            role="list"
            aria-label={label}
            className={className}
        >
            {items.map((item, index) => (
                <li
                    key={keyExtractor(item, index)}
                    role="listitem"
                    tabIndex={onItemClick ? 0 : undefined}
                    onClick={() => onItemClick?.(item, index)}
                    onKeyDown={(e) => {
                        if (onItemClick && (e.key === 'Enter' || e.key === ' ')) {
                            e.preventDefault();
                            onItemClick(item, index);
                        }
                    }}
                    className={`
                        ${onItemClick ? 'cursor-pointer focus:outline-none focus:ring-2 focus:ring-indigo-500' : ''}
                        ${itemClassName}
                    `}
                >
                    {renderItem(item, index)}
                </li>
            ))}
        </ul>
    );
}

// ============================================
// LIVE REGION
// ============================================

interface LiveRegionProps {
    children: ReactNode;
    mode?: 'polite' | 'assertive';
    atomic?: boolean;
}

/**
 * Live region for screen reader announcements
 */
export const LiveRegion: React.FC<LiveRegionProps> = ({
    children,
    mode = 'polite',
    atomic = true,
}) => {
    return (
        <div
            role="status"
            aria-live={mode}
            aria-atomic={atomic}
            className="sr-only"
        >
            {children}
        </div>
    );
};

// ============================================
// ACCESSIBLE ICON BUTTON
// ============================================

interface AccessibleIconButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    icon: ReactNode;
    label: string;
    variant?: 'default' | 'ghost' | 'outline';
    size?: 'sm' | 'md' | 'lg';
}

/**
 * Icon-only button with required label for accessibility
 */
export const AccessibleIconButton: React.FC<AccessibleIconButtonProps> = ({
    icon,
    label,
    variant = 'ghost',
    size = 'md',
    className = '',
    ...props
}) => {
    const sizeClasses = {
        sm: 'w-8 h-8',
        md: 'w-10 h-10',
        lg: 'w-12 h-12',
    };

    const variantClasses = {
        default: 'bg-indigo-600 text-white hover:bg-indigo-700',
        ghost: 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800',
        outline: 'border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800',
    };

    return (
        <button
            type="button"
            aria-label={label}
            title={label}
            className={`
                inline-flex items-center justify-center rounded-lg transition-colors
                focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2
                ${sizeClasses[size]}
                ${variantClasses[variant]}
                ${className}
            `}
            {...props}
        >
            {icon}
            <span className="sr-only">{label}</span>
        </button>
    );
};

// ============================================
// LOADING INDICATOR
// ============================================

interface AccessibleLoadingProps {
    message?: string;
    className?: string;
}

/**
 * Accessible loading indicator
 */
export const AccessibleLoading: React.FC<AccessibleLoadingProps> = ({
    message = 'Memuat...',
    className = '',
}) => {
    return (
        <div
            role="status"
            aria-busy="true"
            aria-label={message}
            className={`flex items-center justify-center gap-2 ${className}`}
        >
            <div className="w-5 h-5 border-2 border-indigo-600 border-t-transparent rounded-full animate-spin" />
            <span className="text-sm text-slate-600 dark:text-slate-400">{message}</span>
        </div>
    );
};

export default {
    AccessiblePage,
    SkipToMainContent,
    AccessibleSection,
    AccessibleTable,
    AccessibleList,
    LiveRegion,
    AccessibleIconButton,
    AccessibleLoading,
};

import { getAutoTable, getJsPDF } from './dynamicImports';
