    });

    // Summary statistics
    const stats = calculateAttendanceStats(classData.students, attendanceData, date);
    const finalY = (doc as any).lastAutoTable.finalY + 10;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text('Rekap Kehadiran:', 14, finalY);
    doc.setFont('helvetica', 'normal');
    doc.text(`Hadir: ${stats.hadir}  |  Sakit: ${stats.sakit}  |  Izin: ${stats.izin}  |  Alpha: ${stats.alpha}`, 14, finalY + 6);
    doc.text(`Persentase Kehadiran: ${stats.percentage.toFixed(1)}%`, 14, finalY + 12);

    // Footer with signature
    const signatureY = finalY + 30;
    doc.text(`${schoolName.split(' ').pop()}, ${formattedDate}`, pageWidth - 60, signatureY);
    doc.text('Wali Kelas,', pageWidth - 60, signatureY + 6);
    doc.text('', pageWidth - 60, signatureY + 25);
    doc.text(`( ${teacherName || '............................'} )`, pageWidth - 60, signatureY + 30);

    // Save PDF
    const fileName = `Absensi_${classData.name}_${date}.pdf`;
    doc.save(fileName);
    return fileName;
};

/**
 * Generate PDF report for monthly attendance
 */
export const exportMonthlyAttendanceToPDF = async (
    classData: ClassInfo,
    attendanceData: AttendanceRecord[],
    month: number, // 1-12
    year: number,
    schoolName: string = 'MI AL IRSYAD KOTA MADIUN'
) => {
    // Ensure logos are loaded
    await ensureLogosLoaded();

    const { default: jsPDF } = await getJsPDF();
    const { default: autoTable } = await getAutoTable();
    const doc = new jsPDF('l', 'mm', 'a4'); // Landscape for monthly report
    const pageWidth = doc.internal.pageSize.getWidth();

    const monthNames = [
        'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
        'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
    ];
    const monthName = monthNames[month - 1];
    const daysInMonth = new Date(year, month, 0).getDate();

    // Add header with logos
    let y = addPdfHeader(doc, { schoolName, orientation: 'landscape' });

    // Title
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text(`REKAP ABSENSI KELAS ${classData.name}`, pageWidth / 2, y, { align: 'center' });
    y += 5;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Bulan: ${monthName} ${year}`, pageWidth / 2, y, { align: 'center' });
    const tableStartY = y + 6;

    // Prepare table data with all days
    const tableData = classData.students.map((student, index) => {
        const row: (string | number)[] = [index + 1, student.name];
        let hadir = 0, sakit = 0, izin = 0, alpha = 0;

        for (let day = 1; day <= daysInMonth; day++) {
            const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const record = attendanceData.find(
                att => att.student_id === student.id && att.date === dateStr
            );

            if (record) {
                const statusMap: Record<string, string> = {
                    'Hadir': 'H', 'Sakit': 'S', 'Izin': 'I', 'Alpha': 'A'
                };
                row.push(statusMap[record.status] || '-');

                if (record.status === 'Hadir') hadir++;
                else if (record.status === 'Sakit') sakit++;
                else if (record.status === 'Izin') izin++;
                else if (record.status === 'Alpha') alpha++;
            } else {
                row.push('-');
            }
        }

        // Add summary columns
        row.push(hadir, sakit, izin, alpha);
        return row;
    });

    // Generate header with day numbers
    const headers = ['No', 'Nama'];
    for (let day = 1; day <= daysInMonth; day++) {
        headers.push(String(day));
    }
    headers.push('H', 'S', 'I', 'A');

    // Generate table
    autoTable(doc, {
        head: [headers],
        body: tableData,
        startY: tableStartY,
        styles: {
            fontSize: 7,
            cellPadding: 1.5,
            halign: 'center'
        },
        headStyles: {
            fillColor: [79, 70, 229],
            textColor: 255,
            fontStyle: 'bold',
            fontSize: 7
        },
        columnStyles: {
            0: { cellWidth: 8 },
            1: { cellWidth: 35, halign: 'left' },
        },
        alternateRowStyles: { fillColor: [248, 250, 252] }
    });

    // Legend
    const finalY = (doc as any).lastAutoTable.finalY + 8;
    doc.setFontSize(8);
    doc.text('Keterangan: H = Hadir, S = Sakit, I = Izin, A = Alpha', 14, finalY);

    // Save PDF
    const fileName = `Rekap_Absensi_${classData.name}_${monthName}_${year}.pdf`;
    doc.save(fileName);
    return fileName;
};

/**
 * Calculate attendance statistics
 */
export const calculateAttendanceStats = (
    students: Student[],
    attendanceData: AttendanceRecord[],
    date?: string
): AttendanceStats => {
    let hadir = 0, sakit = 0, izin = 0, alpha = 0;

    const relevantRecords = date
        ? attendanceData.filter(record => record.date === date)
        : attendanceData;

    relevantRecords.forEach(record => {
        switch (record.status) {
            case 'Hadir': hadir++; break;
            case 'Sakit': sakit++; break;
            case 'Izin': izin++; break;
            case 'Alpha': alpha++; break;
        }
    });

    const total = hadir + sakit + izin + alpha;
    const percentage = total > 0 ? (hadir / total) * 100 : 0;

    return { hadir, sakit, izin, alpha, total, percentage };
};

/**
 * Calculate class attendance statistics for a date range
 */
export const calculateClassStatsForPeriod = (
    students: Student[],
    attendanceData: AttendanceRecord[],
    startDate: string,
    endDate: string
): AttendanceStats & { totalStudents: number; daysWithRecords: number } => {
    const start = new Date(startDate);
    const end = new Date(endDate);

    const relevantRecords = attendanceData.filter(record => {
        const recordDate = new Date(record.date);
        return recordDate >= start && recordDate <= end;
    });

    const stats = calculateAttendanceStats(students, relevantRecords);

    // Calculate unique days with records
    const uniqueDays = new Set(relevantRecords.map(r => r.date)).size;

    return {
        ...stats,
        totalStudents: students.length,
        daysWithRecords: uniqueDays
    };
};

/**
 * Responsive Design Testing Utilities
 * 
 * Collection of utilities for testing responsive design compliance.
 */

// Standard breakpoints (matching Tailwind CSS)
export const BREAKPOINTS = {
    sm: 640,
    md: 768,
    lg: 1024,
    xl: 1280,
    '2xl': 1536
};

// Common device presets for testing
export const DEVICE_PRESETS = {
    // Mobile devices
    'iphone-se': { width: 375, height: 667, orientation: 'portrait' as const },
    'iphone-14': { width: 390, height: 844, orientation: 'portrait' as const },
    'iphone-14-landscape': { width: 844, height: 390, orientation: 'landscape' as const },
    'pixel-7': { width: 412, height: 915, orientation: 'portrait' as const },
    'samsung-galaxy-s21': { width: 360, height: 800, orientation: 'portrait' as const },

    // Tablets
    'ipad-mini': { width: 768, height: 1024, orientation: 'portrait' as const },
    'ipad-mini-landscape': { width: 1024, height: 768, orientation: 'landscape' as const },
    'ipad-pro-11': { width: 834, height: 1194, orientation: 'portrait' as const },
    'ipad-pro-12.9': { width: 1024, height: 1366, orientation: 'portrait' as const },
    'surface-pro-7': { width: 912, height: 1368, orientation: 'portrait' as const },

    // Desktop
    'desktop-hd': { width: 1366, height: 768, orientation: 'landscape' as const },
    'desktop-fhd': { width: 1920, height: 1080, orientation: 'landscape' as const },
    'desktop-qhd': { width: 2560, height: 1440, orientation: 'landscape' as const },
};

interface BreakpointInfo {
    name: string;
    minWidth: number;
    maxWidth?: number;
    current: boolean;
}

/**
 * Get current breakpoint information
 */
export function getCurrentBreakpoint(): BreakpointInfo {
    const width = window.innerWidth;

    if (width < BREAKPOINTS.sm) {
        return { name: 'xs', minWidth: 0, maxWidth: BREAKPOINTS.sm - 1, current: true };
    }
    if (width < BREAKPOINTS.md) {
        return { name: 'sm', minWidth: BREAKPOINTS.sm, maxWidth: BREAKPOINTS.md - 1, current: true };
    }
    if (width < BREAKPOINTS.lg) {
        return { name: 'md', minWidth: BREAKPOINTS.md, maxWidth: BREAKPOINTS.lg - 1, current: true };
    }
    if (width < BREAKPOINTS.xl) {
        return { name: 'lg', minWidth: BREAKPOINTS.lg, maxWidth: BREAKPOINTS.xl - 1, current: true };
    }
    if (width < BREAKPOINTS['2xl']) {
        return { name: 'xl', minWidth: BREAKPOINTS.xl, maxWidth: BREAKPOINTS['2xl'] - 1, current: true };
    }
    return { name: '2xl', minWidth: BREAKPOINTS['2xl'], current: true };
}

/**
 * Check if current viewport matches a breakpoint
 */
export function matchesBreakpoint(breakpoint: keyof typeof BREAKPOINTS): boolean {
    return window.innerWidth >= BREAKPOINTS[breakpoint];
}

/**
 * Check for horizontal overflow issues
 */
export function checkHorizontalOverflow(): HTMLElement[] {
    const overflowingElements: HTMLElement[] = [];
    const docWidth = document.documentElement.offsetWidth;

    document.querySelectorAll<HTMLElement>('*').forEach((element) => {
        if (element.offsetWidth > docWidth) {
            overflowingElements.push(element);
        }
    });

    return overflowingElements;
}

/**
 * Audit spacing consistency
 */
interface SpacingAuditResult {
    element: HTMLElement;
    selector: string;
    property: string;
    value: string;
    isInconsistent: boolean;
}

export function auditSpacing(): SpacingAuditResult[] {
    const results: SpacingAuditResult[] = [];
    const containers = document.querySelectorAll<HTMLElement>('[class*="p-"], [class*="m-"], [class*="gap-"]');

    containers.forEach((element) => {
        const style = window.getComputedStyle(element);
        const classes = element.className;

        // Check for intermediate breakpoint usage (which we want to avoid)
        const hasIntermediateBreakpoints = /(?:sm|md):(?:p|m|gap)-\d+/.test(classes) &&
            /lg:(?:p|m|gap)-\d+/.test(classes);

        if (hasIntermediateBreakpoints) {
            results.push({
                element,
                selector: element.tagName.toLowerCase() + (element.className ? '.' + element.className.split(' ')[0] : ''),
                property: 'spacing',
                value: classes,
                isInconsistent: true
            });
        }
    });

    return results;
}

/**
 * Check grid responsiveness
 */
interface GridInfo {
    element: HTMLElement;
    columns: number;
    gap: string;
    breakpoint: string;
}

export function getGridInfo(): GridInfo[] {
    const grids: GridInfo[] = [];
    const gridElements = document.querySelectorAll<HTMLElement>('[class*="grid-cols"]');

    gridElements.forEach((element) => {
        const style = window.getComputedStyle(element);
        const gridTemplateColumns = style.gridTemplateColumns;
        const columns = gridTemplateColumns.split(' ').filter(v => v !== '').length;

        grids.push({
            element,
            columns,
            gap: style.gap,
            breakpoint: getCurrentBreakpoint().name
        });
    });

    return grids;
}

/**
 * Log responsive design status
 */
export function logResponsiveStatus(): void {
    console.group('%c≡ƒô▒ Responsive Design Status', 'font-size: 16px; font-weight: bold;');

    // Current breakpoint
    const breakpoint = getCurrentBreakpoint();
    console.log(`%cCurrent Breakpoint: ${breakpoint.name}`, 'font-size: 14px; color: blue;');
    console.log(`Viewport: ${window.innerWidth}x${window.innerHeight}`);
    console.log(`Orientation: ${window.innerWidth > window.innerHeight ? 'landscape' : 'portrait'}`);

    // Horizontal overflow check
    const overflowing = checkHorizontalOverflow();
    if (overflowing.length > 0) {
        console.warn(`ΓÜá∩╕Å ${overflowing.length} elements causing horizontal overflow:`);
        overflowing.forEach(el => console.log(el));
    } else {
        console.log('Γ£à No horizontal overflow detected');
    }

    // Grid info
    const grids = getGridInfo();
    if (grids.length > 0) {
        console.group('≡ƒôè Grid Layouts:');
        grids.forEach(({ element, columns, gap }) => {
            console.log(`${columns} columns, gap: ${gap}`, element);
        });
        console.groupEnd();
    }

    // Spacing audit
    const spacingIssues = auditSpacing();
    if (spacingIssues.length > 0) {
        console.warn(`ΓÜá∩╕Å ${spacingIssues.length} potential spacing inconsistencies found`);
    }

    console.groupEnd();
}

// Attach to window for console usage
if (typeof window !== 'undefined') {
    (window as any).checkResponsive = logResponsiveStatus;
    (window as any).getBreakpoint = getCurrentBreakpoint;
    (window as any).checkOverflow = checkHorizontalOverflow;
    (window as any).auditSpacing = auditSpacing;
    (window as any).getGrids = getGridInfo;
}

export default {
    BREAKPOINTS,
    DEVICE_PRESETS,
    getCurrentBreakpoint,
    matchesBreakpoint,
    checkHorizontalOverflow,
    auditSpacing,
    getGridInfo,
    logResponsiveStatus
};
